    <content '>
   <style>
      .main {
  display: block !important;
  opacity: 1 !important;
  visibility: visible !important;
  margin: 2rem auto;
  max-width: 800px;
}

        /* --- ENHANCED THEME & MODERN STYLING --- */
        :root {
            --accent-color: #22d3ee;
            --primary-glow: rgba(34, 211, 238, 0.4);
            --secondary-glow: rgba(34, 211, 238, 0.7);
            --dark-bg: #0d1117;
            --card-bg: #161b22;
            --border-color: #30363d;
            --text-primary: #c9d1d9;
            --text-secondary: #8b949e;
            --button-bg: #21262d;
            --button-hover-bg: #30363d;
            --heading-color: #ffffff;
            --background-gradient: radial-gradient(ellipse at top, #1a233b, var(--dark-bg));
            --header-bg: rgba(13, 17, 23, 0.8);
            --modal-bg: rgba(13, 17, 23, 0.7);
            --font-main: 'Poppins', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
        }

        body.light-mode {
            --accent-color: #007bff;
            --primary-glow: rgba(0, 123, 255, 0.3);
            --secondary-glow: rgba(0, 123, 255, 0.5);
            --dark-bg: #f4f7fa;
            --card-bg: #ffffff;
            --border-color: #d1d5da;
            --text-primary: #24292e;
            --text-secondary: #586069;
            --button-bg: #f6f8fa;
            --button-hover-bg: #e1e4e8;
            --heading-color: #1a233b;
            --background-gradient: linear-gradient(to bottom, #e9ecef, #f8f9fa);
            --header-bg: rgba(255, 255, 255, 0.8);
            --modal-bg: rgba(244, 247, 250, 0.7);
        }

        /* Global Reset & Base Styles */
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        html {
            scroll-behavior: smooth;
        }

        body {
            font-family: var(--font-main);
            background: var(--background-gradient);
            color: var(--text-primary);
            line-height: 1.7;
            font-size: 16px;
            transition: background-color 0.4s ease, color 0.4s ease;
        }

        /* Header & Navigation */
        .header, .card-bg, .footer, .tool-card, .category-card, .modal-content, .tool-container input, .tool-container select, .tool-container textarea, .glow-button, .dropdown-menu {
             transition: background-color 0.4s ease, color 0.4s ease, border-color 0.4s ease;
        }

        .header {
            background-color: var(--header-bg);
            backdrop-filter: blur(10px);
            padding: 1rem 5%;
            border-bottom: 1px solid var(--border-color);
            display: flex;
            justify-content: space-between;
            align-items: center;
            position: sticky;
            top: 0;
            z-index: 1000;
        }

        .logo-container { cursor: pointer; display: flex; align-items: center; }
        .logo-container img {
            height: 40px;
            margin-right: 10px;
            border-radius: 8px;
        }
        .logo-container .title {
            font-size: 1.8rem;
            font-weight: 700;
            color: var(--heading-color);
            text-shadow: 0 0 8px var(--primary-glow);
        }
        .logo-container .subtitle { font-size: 0.9rem; color: var(--text-secondary); font-weight: 400; }

        .navbar ul { list-style: none; display: flex; align-items: center; gap: 1.5rem; }
        .navbar a {
            color: var(--text-primary);
            text-decoration: none;
            font-weight: 500;
            padding: 0.5rem 0;
            transition: color 0.3s ease, text-shadow 0.3s ease;
            cursor: pointer;
        }
        .navbar a:hover, .dropdown-toggle:hover {
            color: var(--accent-color);
            text-shadow: 0 0 10px var(--secondary-glow);
        }

        .theme-toggle-button {
            background: none;
            border: 1px solid var(--border-color);
            color: var(--text-primary);
            font-size: 1.5rem;
            cursor: pointer;
            border-radius: 50%;
            width: 40px;
            height: 40px;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .theme-toggle-button:hover {
            background-color: var(--button-hover-bg);
            border-color: var(--accent-color);
        }

        /* Dropdown Menu */
        .dropdown { position: relative; }
        .dropdown-toggle { user-select: none; }
        .dropdown-menu {
            display: none;
            position: absolute;
            top: 150%;
            left: -20px;
            background-color: var(--card-bg);
            border: 1px solid var(--border-color);
            border-radius: 8px;
            box-shadow: 0 8px 16px rgba(0,0,0,0.3);
            z-index: 1001;
            min-width: 220px;
            padding: 0.5rem 0;
        }
        .dropdown-menu.show { display: block; }
        .dropdown-menu a { display: block; padding: 0.75rem 1.5rem; white-space: nowrap; }
        .dropdown-menu a:hover { background-color: var(--button-hover-bg); }

        /* Page Management */
        .page {
            display: none;
            padding: 0 5% 4rem 5%;
            animation: fadeIn 0.5s ease-in-out;
        }
        .page.active { display: block; }
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(15px); }
            to { opacity: 1; transform: translateY(0); }
        }

        /* Section & Content Styles */
        .section-title, .content-page-container h3, .tool-card h3, .category-card h3 {
            color: var(--heading-color);
        }
        .section-title {
            font-size: clamp(2.2rem, 5vw, 3.2rem);
            font-weight: 700;
            text-align: center;
            margin-bottom: 1rem;
            text-shadow: 0 0 12px var(--primary-glow);
            letter-spacing: -1px;
        }
        .section-subtitle {
            text-align: center;
            color: var(--text-secondary);
            max-width: 700px;
            margin: 0 auto 4rem auto;
            font-size: clamp(1rem, 2.5vw, 1.2rem);
            font-weight: 400;
        }
        .content-page-container {
            max-width: 800px;
            margin: 2rem auto;
            background: var(--card-bg);
            padding: 2.5rem;
            border-radius: 12px;
            border: 1px solid var(--border-color);
        }
        .content-page-container h3 { margin-bottom: 1rem; border-bottom: 1px solid var(--border-color); padding-bottom: 0.5rem; }

        /* --- Homepage Hero Banner --- */
        #page-home { padding: 0; }
        .hero-banner {
            position: relative;
            text-align: center;
            padding: 8vh 5%; /* Adjusted padding */
            min-height: 70vh;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            color: #fff;
            overflow: hidden;
        }
      .main {
  display: block !important;
  opacity: 1 !important;
  visibility: visible !important;
}

        .hero-banner::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0; bottom: 0;
            background: linear-gradient(rgba(13, 17, 23, 0.5), rgba(13, 17, 23, 0.9));
            z-index: 1;
        }
        .hero-content {
             position: relative;
             z-index: 2;
        }
        .hero-content .section-title {
            font-size: clamp(2.8rem, 7vw, 4.5rem);
            font-weight: 700;
            letter-spacing: -2px;
            text-shadow: 0 4px 20px rgba(0,0,0,0.6);
            margin-bottom: 1rem;
            color: #fff; /* Always white for readability over images */
        }
        .hero-content .section-subtitle {
            font-size: clamp(1.1rem, 3vw, 1.4rem);
            color: #e0e0e0;
            max-width: 800px;
            text-shadow: 0 2px 10px rgba(0,0,0,0.5);
            margin-bottom: 2.5rem;
        }
        .home-content-area {
            padding: 5rem 5%;
            background-color: var(--dark-bg);
        }

        /* --- Hero Slider Styles --- */
        .hero-slider-container {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            z-index: 0;
        }
        .hero-slide {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            opacity: 0;
            transition: opacity 1s ease-in-out;
        }
        .hero-slide.active {
            opacity: 1;
        }
        .hero-slide img {
            width: 100%;
            height: 100%;
            object-fit: cover;
            object-position: center;
        }
        .slider-dots {
            position: absolute;
            bottom: 2rem;
            left: 50%;
            transform: translateX(-50%);
            display: flex;
            gap: 10px;
            z-index: 3;
        }
        .dot {
            width: 12px;
            height: 12px;
            border-radius: 50%;
            background-color: rgba(255, 255, 255, 0.5);
            cursor: pointer;
            transition: background-color 0.3s ease, transform 0.3s ease;
        }
        .dot.active {
            background-color: var(--accent-color);
            transform: scale(1.2);
        }

        /* --- NEW: Tools Feature Slider --- */
        @keyframes scrollLeft {
            from { transform: translateX(0); }
            to { transform: translateX(-50%); }
        }
        .tools-features-slider {
            background-color: var(--dark-bg);
            padding: 4rem 0;
        }
        .slider-track-container {
            overflow: hidden;
            position: relative;
            width: 100%;
            -webkit-mask-image: linear-gradient(to right, transparent, black 10%, black 90%, transparent);
            mask-image: linear-gradient(to right, transparent, black 10%, black 90%, transparent);
        }
        .slider-track {
            display: flex;
            /* width calculated in JS */
            animation: scrollLeft 90s linear infinite;
        }
        .slider-track-container:hover .slider-track {
            animation-play-state: paused;
        }
        .slider-card {
            width: 320px;
            flex-shrink: 0;
            margin: 0 1rem;
            padding: 2rem 1.5rem;
            background: var(--card-bg);
            border: 1px solid var(--border-color);
            border-radius: 12px;
            text-align: center;
            cursor: pointer;
            transition: transform 0.3s ease, box-shadow 0.3s ease;
        }
        .slider-card:hover {
            transform: translateY(-8px);
            box-shadow: 0 0 25px 5px var(--primary-glow);
            border-color: var(--accent-color);
        }
        .slider-card-icon {
            font-size: 2.5rem;
            margin-bottom: 1rem;
        }
        .slider-card h3 {
            font-size: 1.2rem;
            color: var(--heading-color);
        }

        /* --- Homepage Newsletter Form --- */
        .newsletter-form-wrapper {
            max-width: 600px;
            margin: 2rem auto 0;
            display: flex;
            gap: 10px;
        }
        .newsletter-form-wrapper input {
            /* This reuses styles from the tool-container inputs */
            width: 100%;
            padding: 0.8rem;
            background-color: var(--button-bg);
            font-size: 1rem;
            border: 1px solid var(--border-color);
            border-radius: 8px;
            color: var(--text-primary);
            font-family: var(--font-main);
            flex-grow: 1;
            transition: all 0.3s ease;
        }
         .newsletter-form-wrapper input:focus {
            outline: none;
            border-color: var(--accent-color);
            box-shadow: 0 0 8px 2px var(--primary-glow);
        }
        .newsletter-form-wrapper button {
            flex-shrink: 0;
        }

        /* Category Grid */
        .category-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
            gap: 2rem;
            margin-top: 2rem;
        }
        .category-card {
            background: var(--card-bg);
            border: 1px solid var(--border-color);
            border-radius: 12px;
            padding: 2.5rem;
            text-align: center;
            transition: transform 0.3s ease, box-shadow 0.3s ease, border-color 0.3s ease, background-color 0.4s ease;
            cursor: pointer;
            text-decoration: none;
            color: var(--text-primary);
        }
        .category-card:hover {
            transform: translateY(-10px) scale(1.03);
            border-color: var(--accent-color);
            box-shadow: 0 0 30px 5px var(--primary-glow);
        }
        .card-icon {
            font-size: 2.5rem;
            display: block;
            margin-bottom: 1rem;
        }
        .category-card h3 { font-size: 1.6rem; margin-bottom: 0.5rem; }

        /* Toolls Grid Layout */
        #page-tools { padding-top: 4rem; }
        .tools-grid {
            display: grid;
            /* Default for smaller screens: 2 columns */
            grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); /* Adjusted minmax for 2 columns on mobile */
            gap: 1.5rem;
        }

        /* Desktop view: 3 columns */
        @media (min-width: 992px) { /* Adjust breakpoint as needed for your "desktop" size */
            .tools-grid {
                grid-template-columns: repeat(3, 1fr);
            }
        }

        /* Mobile view: 2 columns (already set by default above, but can be more specific) */
        @media (max-width: 768px) { /* This media query is already present and will apply, ensuring 2 columns on smaller screens */
            .tools-grid {
                grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); /* Even smaller minmax for very small screens if needed, adjust to your preference */
            }
        }
        /* Further fine-tune for very small phones, if 2 columns makes cards too small */
        @media (max-width: 480px) {
            .tools-grid {
                grid-template-columns: 1fr; /* Single column for very narrow screens */
            }
        }


        .category-title {
            grid-column: 1 / -1;
            font-size: 2rem;
            font-weight: 600;
            margin-top: 3rem;
            margin-bottom: 1rem;
            border-bottom: 2px solid var(--accent-color);
            padding-bottom: 0.8rem;
        }

        /* Tool Card Styling */
        .tool-card {
            background-color: var(--card-bg);
            border: 1px solid var(--border-color);
            border-radius: 12px;
            padding: 2rem;
            display: flex;
            flex-direction: column;
            transition: transform 0.3s ease, box-shadow 0.3s ease, border-color 0.3s ease, background-color 0.4s ease;
        }
        .tool-card:hover {
            transform: translateY(-5px);
            border-color: var(--accent-color);
            box-shadow: 0 0 20px 5px var(--primary-glow);
        }
        .tool-card h3 { font-size: 1.4rem; margin-bottom: 0.5rem; font-weight: 600; }
        .tool-card p { color: var(--text-secondary); font-size: 0.95rem; flex-grow: 1; margin-bottom: 1.5rem; }

        /* --- ENHANCED BUTTONS --- */
        .glow-button {
            background-color: var(--button-bg);
            color: var(--text-primary);
            border: 1px solid var(--border-color);
            padding: 0.8rem 1.8rem;
            border-radius: 8px;
            cursor: pointer;
            font-weight: 600;
            font-family: var(--font-main);
            text-align: center;
            text-decoration: none;
            display: inline-block;
            transition: all 0.3s ease;
        }
        .glow-button:hover {
            background-color: var(--button-hover-bg);
            color: #fff;
            border-color: var(--accent-color);
            box-shadow: 0 0 15px 3px var(--primary-glow);
            transform: scale(1.05);
        }
        body.light-mode .glow-button:hover {
            color: var(--text-primary);
        }
        .glow-button:disabled {
            cursor: not-allowed;
            opacity: 0.6;
            box-shadow: none;
            transform: none;
        }
        /* Primary CTA Button Style */
        .cta-button {
            background: var(--accent-color);
            color: var(--dark-bg);
            border-color: var(--accent-color);
            font-size: 1.1rem;
        }
        .cta-button:hover {
            background: #4ef9ff;
            color: var(--dark-bg);
            border-color: #4ef9ff;
            box-shadow: 0 0 25px 5px var(--secondary-glow);
        }
        body.light-mode .cta-button {
             color: #fff;
        }


        /* Modal Styles */
        .modal {
            display: none; position: fixed; z-index: 2000; left: 0; top: 0; width: 100%; height: 100%;
            overflow: auto; background-color: var(--modal-bg); backdrop-filter: blur(8px);
            align-items: center; justify-content: center;
        }
        .modal-content {
            background-color: var(--card-bg); margin: auto; padding: 30px; border: 1px solid var(--accent-color);
            width: 90%; max-width: 800px; border-radius: 12px;
            box-shadow: 0 0 40px 10px var(--primary-glow);
            position: relative; max-height: 90vh; overflow-y: auto;
        }
        .close-button {
            color: var(--text-secondary); position: absolute; top: 15px; right: 25px; font-size: 28px;
            font-weight: bold; cursor: pointer; transition: color 0.3s ease, text-shadow 0.3s ease;
        }
        .close-button:hover { color: var(--heading-color); text-shadow: 0 0 10px var(--secondary-glow); }
        #modal-title { margin-bottom: 20px; color: var(--heading-color); text-shadow: 0 0 5px var(--primary-glow); }
        .tool-container { display: flex; flex-direction: column; gap: 1.2rem; }
        .tool-container label { font-weight: 500; color: var(--text-primary); }
        .tool-container input, .tool-container select, .tool-container textarea {
            width: 100%; padding: 0.8rem; background-color: var(--button-bg); font-size: 1rem;
            border: 1px solid var(--border-color); border-radius: 8px; color: var(--text-primary); font-family: var(--font-main);
        }
        .tool-container input:focus, .tool-container select:focus, .tool-container textarea:focus {
            outline: none; border-color: var(--accent-color); box-shadow: 0 0 8px 2px var(--primary-glow);
        }
        #tool-output {
            margin-top: 1.5rem; padding: 1.5rem; background-color: var(--dark-bg);
            border: 1px dashed var(--border-color); border-radius: 8px; min-height: 50px;
            white-space: pre-wrap; word-wrap: break-word; color: var(--text-primary);
        }
        #tool-output ul { list-style-position: inside; padding-left: 10px; margin-top: 5px; }
        #tool-output li { margin-bottom: 5px; }
        canvas { max-width: 100%; border-radius: 8px; border: 1px solid var(--border-color); }

        /* --- PRODUCTS PAGE SPECIFIC STYLES --- */
        .featured-product-section { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; align-items: center; margin-bottom: 4rem; }
        .featured-product-image img { width: 100%; border-radius: 12px; border: 1px solid var(--border-color); }
        .product-price { font-size: 1.5rem; font-weight: 600; color: var(--accent-color); margin: 1rem 0; }
        .product-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 2rem; }
        .product-card { background-color: var(--card-bg); border: 1px solid var(--border-color); border-radius: 12px; overflow: hidden; display: flex; flex-direction: column; }
        .product-image img { width: 100%; height: 200px; object-fit: cover; }
        .product-card h4, .product-card p, .product-card .product-price, .product-card .glow-button { padding: 0 1.5rem; }
        .product-card h4 { font-size: 1.4rem; margin-top: 1.5rem; color: var(--heading-color); }
        .product-card p { color: var(--text-secondary); flex-grow: 1; margin: 0.5rem 0 1.5rem; }
        .product-card .product-price { text-align: left; padding-bottom: 1rem; }
        .product-card .glow-button { margin: 0 1.5rem 1.5rem; text-align: center; }

        /* --- ENHANCED FOOTER --- */
        .footer {
            background-color: var(--card-bg);
            padding: 2.5rem 5% 1.5rem 5%;
            border-top: 1px solid var(--border-color);
            margin-top: 4rem;
        }

        .footer-upper-row {
            display: flex;
            justify-content: space-between;
            flex-wrap: wrap;
            gap: 2rem;
            padding-bottom: 2rem;
            margin-bottom: 1.5rem;
            border-bottom: 1px solid var(--border-color);
        }

        .footer-links {
            flex: 1;
            min-width: 200px;
            text-align: left;
        }

        .footer-social {
            flex: 1;
            min-width: 200px;
            text-align: right;
        }

        .footer-links h4,
        .footer-social h4 {
            color: var(--heading-color);
            margin-bottom: 1rem;
            font-size: 1.1rem;
            font-weight: 600;
        }

        .footer-links a {
            color: var(--text-secondary);
            text-decoration: none;
            display: block;
            margin-bottom: 0.75rem;
            transition: color 0.3s ease;
            cursor: pointer;
        }
        .footer-links a:hover {
            color: var(--accent-color);
        }

        .footer-social-icons {
            display: flex;
            justify-content: flex-end;
            gap: 1.25rem;
        }

        .footer-social-icons a {
            color: var(--text-secondary);
            transition: color 0.3s ease, transform 0.3s ease;
        }

        .footer-social-icons a:hover {
            color: var(--accent-color);
            transform: translateY(-3px);
        }

        .footer-social-icons svg {
            width: 24px;
            height: 24px;
        }

        .footer-lower-row {
            text-align: center;
        }

        .footer-lower-row p {
            color: var(--text-secondary);
            font-size: 0.9em;
        }

        /* Responsive Design */
        @media (max-width: 768px) {
            body { font-size: 15px; }
            .header { flex-direction: column; align-items: flex-start; gap: 1rem; position: static; }
            .navbar ul { flex-direction: column; gap: 0.5rem; width: 100%; align-items: flex-start; }
            .dropdown-menu { left: 0; top: 110%; }
            /* .tools-grid, .category-grid, .product-grid, .featured-product-section { grid-template-columns: 1fr; } Removed as handled by specific .tools-grid rules */
            .category-grid, .product-grid, .featured-product-section { grid-template-columns: 1fr; } /* Keep for other grids */
            .modal-content { width: 95%; padding: 20px; }
            .hero-banner { min-height: 60vh; padding-top: 5vh; padding-bottom: 5vh; }
            .home-content-area, #page-tools { padding-top: 3rem; }
            .slider-card { width: 280px; }

            /* Responsive Footer Adjustments */
            .footer-upper-row {
                flex-direction: column;
                align-items: center;
                text-align: center;
            }
            .footer-links, .footer-social {
                text-align: center;
                width: 100%;
            }
            .footer-social-icons {
                justify-content: center;
            }
        }

        /* --- SPECIFIC TOOL STYLES --- */

        /* Workout Calendar */
        .calendar-grid-header, .calendar-grid-body { display: grid; grid-template-columns: repeat(7, 1fr); gap: 5px; }
        .day-cell { min-height: 100px; background-color: var(--button-bg); border: 1px solid transparent; cursor: pointer; transition: all 0.2s ease; position: relative; display: flex; flex-direction: column; justify-content: space-between; padding: 5px; }
        .day-cell:hover { border-color: var(--accent-color); transform: translateY(-2px); }
        .day-number { align-self: flex-start; font-size: 0.9em; color: var(--text-secondary); }
        .other-month { opacity: 0.4; pointer-events: none; }
        .day-cell.today .day-number { font-weight: bold; color: var(--accent-color); background-color: var(--card-bg); border-radius: 50%; width: 24px; height: 24px; line-height: 24px; text-align: center; }
        .workout-preview { font-size: 0.85em; font-weight: 500; padding: 3px 5px; border-radius: 4px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; background-color: rgba(34, 211, 238, 0.1); color: var(--accent-color); margin-top: auto; }
        .workout-completed { background-color: rgba(46, 204, 113, 0.2); border-left: 3px solid #2ecc71; }
        .workout-completed-badge { position: absolute; top: 5px; right: 5px; font-size: 1rem; color: #2ecc71; }

       .  /* Plateau Tracker */
        .plateau-tracker-list-item { background-color: var(--button-bg); padding: 1rem 1.5rem; border-radius: 8px; cursor: pointer; transition: all 0.3s ease; border: 1px solid var(--border-color); display: flex; justify-content: space-between; align-items: center; }
        .plateau-tracker-list-item:hover { background-color: var(--button-hover-bg); border-color: var(--accent-color); transform: translateX(5px); }
        .plateau-tracker-list-item span { font-weight: 600; }
        .plateau-analysis-box { margin-top: 1.5rem; padding: 1.5rem; border-radius: 8px; border: 1px solid var(--border-color); background-color: var(--dark-bg); }
        .plateau-analysis-box.plateau-warning { border-color: #e74c3c; background-color: rgba(231, 76, 60, 0.1); }
        .plateau-analysis-box h4 { margin-bottom: 0.5rem; color: var(--heading-color); }
        .plateau-analysis-box.plateau-warning h4 { color: #e74c3c; }
        .plateau-advice ul { padding-left: 20px; margin-top: 10px; }
        .plateau-data-log { margin-top: 1.5rem; max-height: 200px; overflow-y: auto; border: 1px solid var(--border-color); border-radius: 8px; }
        .plateau-data-log table { width: 100%; border-collapse: collapse; }
        .plateau-data-log th, .plateau-data-log td { padding: 0.75rem; text-align: left; border-bottom: 1px solid var(--border-color); }
        .plateau-data-log th { background-color: var(--button-bg); position: sticky; top: 0; }
        .plateau-data-log tr:last-child td { border-bottom: none; }
        .plateau-data-log button { background: none; border: none; cursor: pointer; font-size: 1rem; padding: 0.3rem 0.6rem; border-radius: 4px; }
        .plateau-data-log button:hover { background-color: var(--button-hover-bg); }

        /* Search Bar Results */
        .search-result-item:hover { background-color: var(--button-hover-bg); }
        .search-result-item:last-child { border-bottom: none; }
    </style>

</html>
