<script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
<script defer="" src="https://cdn.jsdelivr.net/npm/tesseract.js@2/dist/tesseract.min.js"></script>
<script src="https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js"></script>
<script>
//<![CDATA[
    document.addEventListener('DOMContentLoaded', () => {

        // --- THEME TOGGLE LOGIC ---
        const themeToggle = document.getElementById('theme-toggle');
        const body = document.body;
        const applyTheme = (theme) => { if (theme === 'light') { body.classList.add('light-mode'); themeToggle.textContent = '☀️'; } else { body.classList.remove('light-mode'); themeToggle.textContent = '🌙'; } };
        themeToggle.addEventListener('click', () => { const isLight = body.classList.contains('light-mode'); const newTheme = isLight ? 'dark' : 'light'; localStorage.setItem('theme', newTheme); applyTheme(newTheme); });
        const savedTheme = localStorage.getItem('theme'); const prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;
        if (savedTheme) { applyTheme(savedTheme); } else if (prefersDark) { applyTheme('dark'); } else { applyTheme('light'); }

        // --- PAGE NAVIGATION & DROPDOWN LOGIC ---
        const pages = document.querySelectorAll('.page');
        const navLinks = document.querySelectorAll('a[data-page], .logo-container[data-page], .category-card[data-page]');
        const dropdownToggle = document.querySelector('.dropdown-toggle');
        const dropdownMenu = document.querySelector('.dropdown-menu');
        const heroCta = document.querySelector('.hero-banner .cta-button');
        if (heroCta) { heroCta.addEventListener('click', (e) => { const pageId = heroCta.dataset.page; if(pageId) { e.preventDefault(); showPage(pageId); } }); }
        const showPage = (pageId, scrollToId) => { pages.forEach(page => { page.classList.toggle('active', page.id === pageId); }); window.scrollTo(0, 0); if (scrollToId) { setTimeout(() => { const targetElement = document.getElementById(scrollToId); if (targetElement) { targetElement.scrollIntoView({ behavior: 'smooth', block: 'start' }); } }, 100); } };
        navLinks.forEach(link => { link.addEventListener('click', (e) => { if (!link.dataset.page) return; e.preventDefault(); const pageId = link.dataset.page; const scrollToId = link.dataset.scrollTo; showPage(pageId, scrollToId); if (dropdownMenu.classList.contains('show')) { dropdownMenu.classList.remove('show'); } }); });
        dropdownToggle.addEventListener('click', (e) => { e.stopPropagation(); dropdownMenu.classList.toggle('show'); });
        window.addEventListener('click', () => { if (dropdownMenu.classList.contains('show')) { dropdownMenu.classList.remove('show'); } });

        // --- NEWSLETTER SUBSCRIBE LOGIC ---
        const newsletterForm = document.getElementById('newsletter-form');
        if (newsletterForm) {
            newsletterForm.addEventListener('submit', function(e) {
                e.preventDefault();
                const emailInput = document.getElementById('newsletter-email');
                const statusDiv = document.getElementById('newsletter-status');
                const userEmail = emailInput.value;
                if (userEmail) {
                    const recipientEmail = 'sujit@omnitoolaz.com'; 
                    const subject = 'Subscribe to ToolBox Hub Newsletter';
                    const body = `Please add my email (${userEmail}) to the newsletter list. Thank you!`;
                    const mailtoLink = `mailto:${recipientEmail}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
                    window.location.href = mailtoLink;

                    statusDiv.textContent = 'Opening your email client to complete the subscription...';
                    setTimeout(() => {
                        emailInput.value = '';
                        statusDiv.textContent = '';
                    }, 5000);
                }
            });
        }

        // --- CONTACT FORM LOGIC ---
        const feedbackForm = document.getElementById('feedback-form');
        if (feedbackForm) { feedbackForm.addEventListener('submit', function(e) { e.preventDefault(); const formStatus = document.getElementById('form-status'); const name = document.getElementById('feedback-name').value; const subject = document.getElementById('feedback-subject').value; let message = document.getElementById('feedback-message').value; if (name) { message = `From: ${name}\n\n${message}`; } const recipientEmail = 'sujit@omnitoolaz.com'; const mailtoLink = `mailto:${recipientEmail}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(message)}`; window.location.href = mailtoLink; formStatus.textContent = 'Opening your email client...'; setTimeout(() => { feedbackForm.reset(); formStatus.textContent = ''; }, 5000); });}

        // --- MODAL HANDLING ---
        const modal = document.getElementById('toolModal');
        const modalTitle = document.getElementById('modal-title');
        const modalBody = document.getElementById('modal-body');
        const closeButton = document.querySelector('.close-button');

        const openModal = (toolId) => {
            const toolData = toolImplementations[toolId];
            if (!toolData) { console.error('Tool not found:', toolId); return; }
            modalTitle.innerHTML = toolData.title;
            modalBody.innerHTML = toolData.getContent();
            modal.style.display = 'flex';
            document.body.style.overflow = 'hidden';
            if (toolData.init) {
                 try {
                    toolData.init();
                 } catch (error) {
                    console.error(`Error initializing tool "${toolId}":`, error);
                    modalBody.innerHTML = `<p style="color: red;">Error: Could not initialize this tool. Please check the console for details.</p>`;
                 }
            }
        };
        const closeModal = () => {
            modal.style.display = 'none';
            document.body.style.overflow = 'auto';
            modal.dispatchEvent(new CustomEvent('modal:close'));
            modalBody.innerHTML = '';
        };

        document.querySelectorAll('.glow-button[data-tool]').forEach(button => { button.addEventListener('click', () => { const toolId = button.getAttribute('data-tool'); openModal(toolId); }); });
        closeButton.addEventListener('click', closeModal);
        window.addEventListener('click', (event) => { if (event.target === modal) { closeModal(); } });

        // --- HERO SLIDER LOGIC ---
        const slides = document.querySelectorAll('.hero-slide');
        const dotsContainer = document.querySelector('.slider-dots');
        let currentSlide = 0;
        let slideInterval;
        function createDots() { if (!dotsContainer) return; dotsContainer.innerHTML = ''; slides.forEach((_, i) => { const dot = document.createElement('span'); dot.classList.add('dot'); dot.setAttribute('data-slide', i); dotsContainer.appendChild(dot); dot.addEventListener('click', () => { showSlide(i); resetInterval(); }); }); }
        function showSlide(n) { if (slides.length === 0) return; slides.forEach(slide => slide.classList.remove('active')); const dots = document.querySelectorAll('.dot'); dots.forEach(dot => dot.classList.remove('active')); currentSlide = (n + slides.length) % slides.length; slides[currentSlide].classList.add('active'); if (dots[currentSlide]) { dots[currentSlide].classList.add('active'); } }
        function nextSlide() { showSlide(currentSlide + 1); }
        function startInterval() { slideInterval = setInterval(nextSlide, 5000); }
        function resetInterval() { clearInterval(slideInterval); startInterval(); }
        if (slides.length > 1) { createDots(); showSlide(0); startInterval(); } else if (slides.length === 1) { showSlide(0); }

        // --- NEW: TOOL SLIDER LOGIC ---
        const populateToolSlider = () => {
            const sliderTrack = document.querySelector('.slider-track');
            if (!sliderTrack) return;
            let allCardsHTML = '';
            const toolKeys = Object.keys(toolImplementations);

            toolKeys.forEach(key => {
                const tool = toolImplementations[key];
                if (tool.icon) {
                    allCardsHTML += `
                        <div class="slider-card" data-tool="${key}">
                            <div class="slider-card-icon">${tool.icon}</div>
                            <h3>${tool.title}</h3>
                        </div>
                    `;
                }
            });

            // Duplicate for seamless loop
            sliderTrack.innerHTML = allCardsHTML + allCardsHTML;

            // Set dynamic width for the track
            const cardWidth = 320; // width of .slider-card
            const cardMargin = 16; // margin-left/right of .slider-card in rem (1rem = 16px)
            const totalWidth = (cardWidth + cardMargin * 2) * toolKeys.filter(key => toolImplementations[key].icon).length;
            sliderTrack.style.width = `${totalWidth * 2}px`;

            // Add click listener for the dynamically created cards
            sliderTrack.addEventListener('click', (e) => {
                const card = e.target.closest('.slider-card');
                if (card && card.dataset.tool) {
                    openModal(card.dataset.tool);
                }
            });
        };

        // --- ON-SITE TOOL SEARCH LOGIC ---
        const searchBar = document.getElementById('tool-search-bar');
        const searchResultsContainer = document.getElementById('tool-search-results');
        const allToolCards = Array.from(document.querySelectorAll('.tool-card'));

        if (searchBar) {
            searchBar.addEventListener('input', (e) => {
                const query = e.target.value.toLowerCase().trim();

                if (query.length < 2) {
                    searchResultsContainer.style.display = 'none';
                    searchResultsContainer.innerHTML = '';
                    return;
                }

                const matchedTools = [];
                for (const toolId in toolImplementations) {
                    const tool = toolImplementations[toolId];
                    const toolTitle = tool.title.toLowerCase();
                    const toolCard = allToolCards.find(card => card.querySelector(`button[data-tool="${toolId}"]`));
                    const toolDescription = toolCard ? toolCard.querySelector('p').textContent.toLowerCase() : '';

                    if (toolTitle.includes(query) || toolDescription.includes(query)) {
                        matchedTools.push({
                            id: toolId,
                            title: tool.title,
                            description: toolCard ? toolCard.querySelector('p').textContent : ''
                        });
                    }
                }

                if (matchedTools.length > 0) {
                    searchResultsContainer.innerHTML = matchedTools.map(tool => `
                        <div class="search-result-item" data-tool="${tool.id}" style="padding: 1rem 1.5rem; cursor: pointer; border-bottom: 1px solid var(--border-color);">
                            <h4 style="margin: 0 0 0.25rem 0; color: var(--heading-color); pointer-events: none;">${tool.title}</h4>
                            <p style="margin: 0; font-size: 0.9em; color: var(--text-secondary); pointer-events: none;">${tool.description}</p>
                        </div>
                    `).join('');
                    searchResultsContainer.style.display = 'block';
                } else {
                    searchResultsContainer.innerHTML = '<div style="padding: 1rem 1.5rem; color: var(--text-secondary);">No tools found.</div>';
                    searchResultsContainer.style.display = 'block';
                }
            });

            document.addEventListener('click', (e) => {
                const searchContainer = e.target.closest('.search-bar-container');
                if (!searchContainer) {
                    searchResultsContainer.style.display = 'none';
                }
            });

            searchResultsContainer.addEventListener('click', (e) => {
                const resultItem = e.target.closest('.search-result-item');
                if (resultItem && resultItem.dataset.tool) {
                    openModal(resultItem.dataset.tool);
                    searchBar.value = '';
                    searchResultsContainer.style.display = 'none';
                }
            });
        }

        // --- ALL TOOL IMPLEMENTATIONS (ICONS ADDED) ---
        const toolImplementations = {
             'body-fat-calculator': {
                title: 'Body Fat Calculator',
                icon: '📊',
                getContent: () => `
                    <div class="tool-container">
                        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 1.5rem;">
                            <div>
                                <label for="bf-gender">Gender:</label>
                                <select id="bf-gender"><option value="male">Male</option><option value="female">Female</option></select>
                            </div>
                            <div id="unit-toggle" style="background-color: var(--button-bg); border: 1px solid var(--border-color); border-radius: 6px; display: flex; cursor:pointer;">
                                <button class="active" data-unit="metric" style="padding: 0.5rem 1rem; border:none; background:var(--accent-color); color:var(--dark-bg); border-radius: 6px 0 0 6px;">Metric</button>
                                <button data-unit="imperial" style="padding: 0.5rem 1rem; border:none; background: transparent; color: var(--text-primary); border-radius: 0 6px 6px 0;">Imperial</button>
                            </div>
                        </div>
                        <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1rem;">
                            <div><label for="bf-age">Age</label><input type="number" id="bf-age" placeholder="e.g., 30"/></div>
                            <div>
                                <label for="bf-height"><span class="height-unit">Height (cm)</span></label>
                                <div style="display:flex; gap:10px;">
                                    <input type="number" id="bf-height" placeholder="e.g., 175"/>
                                    <input type="number" id="bf-height-in" placeholder="in" style="display: none; width: 80px;"/>
                                </div>
                            </div>
                            <div><label for="bf-weight"><span class="weight-unit">Weight (kg)</span></label><input type="number" id="bf-weight" placeholder="e.g., 70"/></div>
                            <div><label for="bf-neck"><span class="measure-unit">Neck (cm)</span></label><input type="number" id="bf-neck" placeholder="e.g., 38"/></div>
                            <div><label for="bf-waist"><span class="measure-unit">Waist (cm)</span></label><input type="number" id="bf-waist" placeholder="e.g., 85"/></div>
                            <div id="bf-hip-container"><label for="bf-hip"><span class="measure-unit">Hip (cm)</span></label><input type="number" id="bf-hip" placeholder="e.g., 95"/></div>
                        </div>
                         <div style="margin-top:1rem; font-size: 0.9em; color: var(--text-secondary); padding: 0.8rem; border: 1px solid var(--border-color); border-radius: 8px;">
                            <strong>How to Measure:</strong>
                            <ul style="list-style-type: disc; padding-left: 20px; margin-top: 5px;">
                                <li><strong>Neck:</strong> Below the larynx (Adam's apple).</li>
                                <li><strong>Waist:</strong> At the navel for men, at the narrowest point for women.</li>
                                <li><strong>Hip (Women only):</strong> At the largest horizontal measure.</li>
                            </ul>
                        </div>
                        <div id="tool-output"></div>
                    </div>
                `,
                init: () => {
                    const genderSelect = document.getElementById('bf-gender');
                    const ageInput = document.getElementById('bf-age'), heightInput = document.getElementById('bf-height'), heightInInput = document.getElementById('bf-height-in'), weightInput = document.getElementById('bf-weight'), neckInput = document.getElementById('bf-neck'), waistInput = document.getElementById('bf-waist'), hipInput = document.getElementById('bf-hip'), hipContainer = document.getElementById('bf-hip-container');
                    const unitToggle = document.getElementById('unit-toggle'), outputDiv = document.getElementById('tool-output');
                    const allInputs = [ageInput, heightInput, heightInInput, weightInput, neckInput, waistInput, hipInput];

                    let currentUnit = 'metric';

                    const updateUI = () => {
                        hipContainer.style.display = genderSelect.value === 'female' ? 'block' : 'none';
                        const isMetric = currentUnit === 'metric';
                        document.querySelector('.height-unit').textContent = `Height (${isMetric ? 'cm' : 'ft/in'})`;
                        document.querySelector('.weight-unit').textContent = `Weight (${isMetric ? 'kg' : 'lbs'})`;
                        document.querySelectorAll('.measure-unit').forEach(el => el.textContent = `(${isMetric ? 'cm' : 'in'})`);
                        heightInInput.style.display = isMetric ? 'none' : 'inline-block';
                        heightInput.placeholder = isMetric ? 'e.g., 175' : 'ft';
                        weightInput.placeholder = isMetric ? 'e.g., 70' : 'e.g., 154';
                        neckInput.placeholder = isMetric ? 'e.g., 38' : 'e.g., 15';
                        waistInput.placeholder = isMetric ? 'e.g., 85' : 'e.g., 34';
                        hipInput.placeholder = isMetric ? 'e.g., 95' : 'e.g., 37';
                        calculate();
                    };

                    unitToggle.addEventListener('click', (e) => {
                        if (e.target.tagName === 'BUTTON') {
                            const newUnit = e.target.dataset.unit;
                            if (newUnit === currentUnit) return;

                            unitToggle.querySelector('.active').classList.remove('active');
                            e.target.classList.add('active');

                             const activeBtn = unitToggle.querySelector('.active');
                            unitToggle.querySelectorAll('button').forEach(b => {
                                b.style.background = 'transparent';
                                b.style.color = 'var(--text-primary)';
                            });
                            activeBtn.style.background = 'var(--accent-color)';
                            activeBtn.style.color = 'var(--dark-bg)';

                            currentUnit = newUnit;
                            updateUI();
                        }
                    });

                    const calculate = () => {
                        const gender = genderSelect.value;
                        const age = parseFloat(ageInput.value) || 0;
                        let h_cm = parseFloat(heightInput.value) || 0;
                        let w_kg = parseFloat(weightInput.value) || 0;
                        let neck_cm = parseFloat(neckInput.value) || 0;
                        let waist_cm = parseFloat(waistInput.value) || 0;
                        let hip_cm = parseFloat(hipInput.value) || 0;

                        if (currentUnit === 'imperial') {
                            const h_in = parseFloat(heightInInput.value) || 0;
                            h_cm = ((h_cm * 12) + h_in) * 2.54;
                            w_kg *= 0.453592;
                            neck_cm *= 2.54;
                            waist_cm *= 2.54;
                            hip_cm *= 2.54;
                        }

                        if (h_cm <= 0 || w_kg <= 0) {
                            outputDiv.innerHTML = '';
                            return;
                        }

                        // US NAVY Formula
                        let bfp_navy = 0;
                        if(neck_cm > 0 && waist_cm > 0) {
                            if (gender === 'male' && waist_cm > neck_cm) {
                                bfp_navy = 86.010 * Math.log10(waist_cm - neck_cm) - 70.041 * Math.log10(h_cm) + 36.76;
                            } else if (gender === 'female' && (waist_cm + hip_cm) > neck_cm) {
                                bfp_navy = 163.205 * Math.log10(waist_cm + hip_cm - neck_cm) - 97.684 * Math.log10(h_cm) - 78.387;
                            }
                        }

                        // BMI Based Formula
                        const bmi = w_kg / ((h_cm/100) * (h_cm/100));
                        let bfp_bmi = 0;
                        if(age > 0) {
                            if(gender === 'male') {
                                bfp_bmi = (1.20 * bmi) + (0.23 * age) - 16.2;
                            } else {
                                bfp_bmi = (1.20 * bmi) + (0.23 * age) - 5.4;
                            }
                        }

                        displayResults(bfp_navy > 0 ? bfp_navy : bfp_bmi, w_kg);
                    };

                     const getCategory = (bfp, gender) => {
                         const categories = gender === 'male' 
                             ? { "Essential Fat": [2, 5], "Athletes": [6, 13], "Fitness": [14, 17], "Acceptable": [18, 24], "Obese": [25, 100] }
                             : { "Essential Fat": [10, 13], "Athletes": [14, 20], "Fitness": [21, 24], "Acceptable": [25, 31], "Obese": [32, 100] };
                         for (const cat in categories) {
                             if (bfp >= categories[cat][0] && bfp <= categories[cat][1]) {
                                 return cat;
                             }
                         }
                         return "N/A";
                    };

                    const displayResults = (bfp, weightKg) => {
                        bfp = Math.max(0, bfp);
                        const category = getCategory(bfp, genderSelect.value);
                        const fatMass = weightKg * (bfp / 100);
                        const leanMass = weightKg - fatMass;

                        outputDiv.innerHTML = `
                            <div style="text-align:center; padding-top:1.5rem; border-top:1px solid var(--border-color);">
                                <div style="font-size: 1.2rem; color: var(--text-secondary);">Your Body Fat Percentage</div>
                                <div style="font-size: 3.5rem; font-weight: 700; color: var(--accent-color);">${bfp.toFixed(1)}%</div>
                                <div style="font-size: 1.3rem; font-weight: 500;">Category: ${category}</div>
                            </div>
                            <div style="margin-top: 1.5rem; display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; text-align: center;">
                                <div style="background: var(--button-bg); padding: 1rem; border-radius: 8px;">
                                    <div style="font-size: 1rem; color: var(--text-secondary);">Fat Mass</div>
                                    <div style="font-size: 1.5rem; font-weight: 600;">${fatMass.toFixed(2)} ${currentUnit === 'metric' ? 'kg' : 'lbs'}</div>
                                </div>
                                <div style="background: var(--button-bg); padding: 1rem; border-radius: 8px;">
                                    <div style="font-size: 1rem; color: var(--text-secondary);">Lean Mass</div>
                                    <div style="font-size: 1.5rem; font-weight: 600;">${leanMass.toFixed(2)} ${currentUnit === 'metric' ? 'kg' : 'lbs'}</div>
                                </div>
                            </div>
                        `;
                    };

                    genderSelect.addEventListener('change', updateUI);
                    allInputs.forEach(input => input.addEventListener('input', calculate));

                    updateUI();
                }
            },

            'keyword-density-checker': {
                title: 'Keyword Density Checker',
                icon: '🔑',
                getContent: () => `
                    <div class="tool-container">
                        <div>
                            <label for="kd-text-input">Paste your text here:</label>
                            <textarea id="kd-text-input" rows="10" placeholder="Enter the article, blog post, or any text you want to analyze..."></textarea>
                        </div>
                        <div>
                            <label for="kd-stopwords">Stop Words (words to ignore, comma-separated):</label>
                            <textarea id="kd-stopwords" rows="3">a,about,above,after,again,against,all,am,an,and,any,are,aren't,as,at,be,because,been,before,being,below,between,both,but,by,can't,cannot,could,couldn't,did,didn't,do,does,doesn't,doing,don't,down,during,each,few,for,from,further,had,hadn't,has,hasn't,have,haven't,having,he,he'd,he'll,he's,her,here,here's,hers,herself,him,himself,his,how,how's,i,i'd,i'll,i'm,i've,if,in,into,is,isn't,it,it's,its,itself,let's,me,more,most,mustn't,my,myself,no,nor,not,of,off,on,once,only,or,other,ought,our,ours,ourselves,out,over,own,same,shan't,she,she'd,she'll,she's,should,shouldn't,so,some,such,than,that,that's,the,their,theirs,them,themselves,then,there,there's,these,they,they'd,they'll,they're,they've,this,those,through,to,too,under,until,up,very,was,wasn't,we,we'd,we'll,we're,we've,were,weren't,what,what's,when,when's,where,where's,which,while,who,who's,whom,why,why's,with,won't,would,wouldn't,you,you'd,you'll,you're,you've,your,yours,yourself,yourselves</textarea>
                        </div>
                        <button id="kd-analyze-btn" class="glow-button cta-button">Analyze Keyword Density</button>
                        <div id="tool-output">
                             <p style="text-align: center; color: var(--text-secondary);">Results will be displayed here.</p>
                        </div>
                    </div>
                `,
                init: () => {
                    const textInput = document.getElementById('kd-text-input');
                    const stopwordsInput = document.getElementById('kd-stopwords');
                    const analyzeBtn = document.getElementById('kd-analyze-btn');
                    const outputDiv = document.getElementById('tool-output');

                    const getNgrams = (words, n) => {
                        const ngrams = [];
                        for (let i = 0; i <= words.length - n; i++) {
                            ngrams.push(words.slice(i, i + n).join(' '));
                        }
                        return ngrams;
                    };

                    const analyze = () => {
                        const text = textInput.value;
                        if (!text.trim()) {
                            outputDiv.innerHTML = `<p style="text-align: center; color: var(--accent-color);">Please paste some text to analyze.</p>`;
                            return;
                        }

                        const stopWords = new Set(stopwordsInput.value.toLowerCase().split(',').map(sw => sw.trim()));

                        const words = text.toLowerCase().replace(/[^a-z0-9\s']/g, ' ').replace(/\s+/g, ' ').trim().split(' ');
                        const filteredWords = words.filter(word => word && !stopWords.has(word));

                        const totalWords = filteredWords.length;
                        if (totalWords === 0) {
                            outputDiv.innerHTML = `<p style="text-align: center; color: var(--accent-color);">No valid keywords to analyze after removing stop words.</p>`;
                            return;
                        }

                        const oneWordPhrases = filteredWords;
                        const twoWordPhrases = getNgrams(filteredWords, 2);
                        const threeWordPhrases = getNgrams(filteredWords, 3);

                        const generateResultsTable = (phrases, title) => {
                            const counts = phrases.reduce((acc, phrase) => {
                                acc[phrase] = (acc[phrase] || 0) + 1;
                                return acc;
                            }, {});

                            const sorted = Object.entries(counts).sort(([, a], [, b]) => b - a).slice(0, 20); // Top 20

                            if (sorted.length === 0) return '';

                            let tableHTML = `<h4 style="margin-top: 1.5rem; margin-bottom: 0.5rem; color: var(--heading-color);">${title}</h4>
                                           <table style="width:100%; border-collapse: collapse;">
                                             <thead>
                                               <tr style="text-align: left;">
                                                 <th style="padding: 8px; border-bottom: 1px solid var(--border-color);">Keyword</th>
                                                 <th style="padding: 8px; border-bottom: 1px solid var(--border-color);">Count</th>
                                                 <th style="padding: 8px; border-bottom: 1px solid var(--border-color);">Density</th>
                                               </tr>
                                             </thead>
                                             <tbody>`;

                            sorted.forEach(([phrase, count]) => {
                                const density = (count / totalWords) * 100;
                                tableHTML += `<tr>
                                                <td style="padding: 8px; border-bottom: 1px solid var(--border-color);">${phrase}</td>
                                                <td style="padding: 8px; border-bottom: 1px solid var(--border-color);">${count}</td>
                                                <td style="padding: 8px; border-bottom: 1px solid var(--border-color);">
                                                    <div style="display:flex; align-items:center; gap: 10px;">
                                                        <span style="flex-shrink:0;">${density.toFixed(2)}%</span>
                                                        <div style="width:100%; background:var(--button-bg); border-radius:3px;">
                                                            <div style="width:${density > 10 ? 100 : density * 10}%; background:var(--accent-color); height:10px; border-radius:3px;"></div>
                                                        </div>
                                                    </div>
                                                </td>
                                              </tr>`;
                            });

                            tableHTML += `</tbody></table>`;
                            return tableHTML;
                        };

                        const uniqueWords = new Set(filteredWords).size;
                        const summaryHTML = `
                            <div style="display:flex; gap: 2rem; justify-content: center; background: var(--button-bg); padding: 1rem; border-radius: 8px; margin-bottom: 1.5rem;">
                                <div style="text-align: center;"><div style="font-size: 0.9em; color: var(--text-secondary);">Total Words</div><div style="font-size: 1.5em; font-weight: 600; color: var(--heading-color);">${totalWords}</div></div>
                                <div style="text-align: center;"><div style="font-size: 0.9em; color: var(--text-secondary);">Unique Words</div><div style="font-size: 1.5em; font-weight: 600; color: var(--heading-color);">${uniqueWords}</div></div>
                            </div>
                        `;

                        outputDiv.innerHTML = summaryHTML + 
                                          generateResultsTable(oneWordPhrases, 'Top 1-Word Keywords') + 
                                          generateResultsTable(twoWordPhrases, 'Top 2-Word Keywords') + 
                                          generateResultsTable(threeWordPhrases, 'Top 3-Word Keywords');
                    };

                    analyzeBtn.addEventListener('click', analyze);
                }
            },
            'advanced-gst-calculator': {
                title: 'Advanced GST Calculator',
                icon: '🧾',
                getContent: () => `
                    <div class="tool-container">
                        <div>
                            <label for="gst-amount">Amount:</label>
                            <input type="number" id="gst-amount" placeholder="e.g., 1000"/>
                        </div>
                        <div>
                            <label for="gst-rate">GST Rate (%):</label>
                            <select id="gst-rate">
                                <option value="3">3%</option>
                                <option value="5">5%</option>
                                <option value="12">12%</option>
                                <option value="18" selected="selected">18%</option>
                                <option value="28">28%</option>
                            </select>
                        </div>
                        <div style="margin-top: 1rem;">
                            <label>GST Type:</label>
                            <div style="display: flex; gap: 1rem; margin-top: 0.5rem;">
                                <label style="font-weight: normal; display: flex; align-items: center;"><input type="radio" name="gst-type" value="exclusive" checked="checked" style="width: auto; margin-right: 8px;"/> GST Exclusive</label>
                                <label style="font-weight: normal; display: flex; align-items: center;"><input type="radio" name="gst-type" value="inclusive" style="width: auto; margin-right: 8px;"/> GST Inclusive</label>
                            </div>
                        </div>
                        <div id="tool-output" style="margin-top: 1.5rem; background: var(--dark-bg); padding: 1.5rem; border-radius: 8px;">
                            <p>Results will be calculated here.</p>
                        </div>
                    </div>
                `,
                init: () => {
                    const amountInput = document.getElementById('gst-amount');
                    const rateSelect = document.getElementById('gst-rate');
                    const typeRadios = document.querySelectorAll('input[name="gst-type"]');
                    const outputDiv = document.getElementById('tool-output');

                    const calculateGST = () => {
                        const amount = parseFloat(amountInput.value) || 0;
                        const rate = parseFloat(rateSelect.value) / 100;
                        const type = document.querySelector('input[name="gst-type"]:checked').value;

                        if (amount <= 0) {
                            outputDiv.innerHTML = '<p>Please enter a valid amount.</p>';
                            return;
                        }

                        let baseAmount, gstAmount, totalAmount;

                        if (type === 'exclusive') {
                            baseAmount = amount;
                            gstAmount = baseAmount * rate;
                            totalAmount = baseAmount + gstAmount;
                        } else { // inclusive
                            totalAmount = amount;
                            baseAmount = totalAmount / (1 + rate);
                            gstAmount = totalAmount - baseAmount;
                        }

                        outputDiv.innerHTML = `
                            <div style="display: grid; grid-template-columns: 1fr 2fr; align-items: center; gap: 0.8rem; font-size: 1.1em;">
                                <strong style="color: var(--text-secondary);">Base Amount:</strong> <span>${baseAmount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</span>
                                <strong style="color: var(--text-secondary);">GST Amount:</strong> <span>${gstAmount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</span>
                                <strong style="color: var(--accent-color); font-size: 1.2em; border-top: 1px solid var(--border-color); padding-top: 0.8rem; margin-top: 0.5rem; grid-column: 1 / -1;">Total Amount:</strong>
                                <span style="font-size: 1.2em; font-weight: bold; color: var(--accent-color); border-top: 1px solid var(--border-color); padding-top: 0.8rem; margin-top: 0.5rem; grid-column: 2 / 3; text-align: left;">${totalAmount.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</span>
                            </div>
                        `;
                    };

                    [amountInput, rateSelect].forEach(el => el.addEventListener('input', calculateGST));
                    typeRadios.forEach(radio => radio.addEventListener('change', calculateGST));
                }
            },
            'currency-converter': {
                title: 'Currency Converter',
                icon: '💸',
                getContent: () => `
                    <div class="tool-container">
                        <div id="currency-converter-status" style="padding: 1rem; color: var(--text-secondary); text-align:center;">Loading currency rates...</div>
                        <div id="currency-converter-main" style="display: none;">
                            <div style="display: flex; gap: 1rem; align-items: center; justify-content: space-between; flex-wrap: wrap;">
                                <div style="flex: 5;">
                                    <label for="currency-amount">Amount</label>
                                    <input type="number" id="currency-amount" value="100"/>
                                </div>
                                <div style="flex: 4;">
                                    <label for="currency-from">From</label>
                                    <select id="currency-from"></select>
                                </div>
                                <button id="currency-swap-btn" style="flex: 1; margin-top: 24px; padding: 10px;" class="glow-button">&#8646;</button>
                                <div style="flex: 4;">
                                    <label for="currency-to">To</label>
                                    <select id="currency-to"></select>
                                </div>
                            </div>
                            <div id="tool-output" style="margin-top: 1.5rem; text-align: center; font-size: 1.2em; padding: 1rem; background-color: var(--dark-bg); border-radius: 8px;"></div>
                        </div>
                    </div>
                `,
                init: () => {
                    const statusDiv = document.getElementById('currency-converter-status');
                    const mainDiv = document.getElementById('currency-converter-main');
                    const amountInput = document.getElementById('currency-amount');
                    const fromSelect = document.getElementById('currency-from');
                    const toSelect = document.getElementById('currency-to');
                    const swapBtn = document.getElementById('currency-swap-btn');
                    const outputDiv = document.getElementById('tool-output');

                    let rates = {};

                    const fetchRates = async () => {
                        try {
                            const response = await fetch('https://open.er-api.com/v6/latest/USD');
                            if (!response.ok) throw new Error('Failed to fetch rates');
                            const data = await response.json();
                            rates = data.rates;

                            const currencies = Object.keys(rates);
                            let optionsHtml = '';
                            currencies.forEach(currency => {
                                optionsHtml += `<option value="${currency}">${currency}</option>`;
                            });

                            fromSelect.innerHTML = optionsHtml;
                            toSelect.innerHTML = optionsHtml;

                            fromSelect.value = 'USD';
                            toSelect.value = 'INR';

                            statusDiv.style.display = 'none';
                            mainDiv.style.display = 'block';

                            convert();
                        } catch (error) {
                            statusDiv.textContent = `Error: ${error.message}. Please try again later.`;
                            statusDiv.style.color = 'red';
                        }
                    };

                    const convert = () => {
                        if (Object.keys(rates).length === 0) return;

                        const amount = parseFloat(amountInput.value) || 0;
                        const fromCurrency = fromSelect.value;
                        const toCurrency = toSelect.value;
                        const fromRate = rates[fromCurrency];
                        const toRate = rates[toCurrency];

                        const result = (amount / fromRate) * toRate;

                        outputDiv.innerHTML = `
                            <div style="color: var(--text-primary); font-size: 1.8rem; font-weight: 700;">
                                ${result.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 4})} ${toCurrency}
                            </div>
                            <div style="color: var(--text-secondary); font-size: 0.9em; margin-top: 0.5rem;">
                                1 ${fromCurrency} = ${(toRate / fromRate).toFixed(4)} ${toCurrency}
                            </div>
                        `;
                    };

                    amountInput.addEventListener('input', convert);
                    fromSelect.addEventListener('change', convert);
                    toSelect.addEventListener('change', convert);

                    swapBtn.addEventListener('click', () => {
                        const temp = fromSelect.value;
                        fromSelect.value = toSelect.value;
                        toSelect.value = temp;
                        convert();
                    });

                    fetchRates();
                }
            },
            'pi-converter': {
                title: 'Pi (π) Fiat Currency Converter',
                icon: '💱',
                getContent: () => `
                    <div class="tool-container">
                        <div style="padding: 1rem; border-left: 4px solid var(--accent-color); background-color: rgba(34, 211, 238, 0.1); border-radius: 4px;">
                            <p style="margin: 0; font-size: 0.9em; color: var(--text-primary);">
                                <strong>Disclaimer:</strong> Pi Network is in an Enclosed Mainnet and not officially listed on exchanges. The value is speculative. This tool uses your assumed value for calculation.
                            </p>
                        </div>
                        <div>
                            <label for="pi-value-usd">Set Your Assumed Value of 1 Pi (in USD):</label>
                            <input type="number" id="pi-value-usd" value="314.159" placeholder="e.g., 314.159"/>
                        </div>
                        <div style="display: grid; grid-template-columns: 1fr; gap: 1rem; margin-top: 1rem;">
                            <div>
                                <label for="pi-amount">Pi (π) Amount:</label>
                                <input type="number" id="pi-amount" value="1"/>
                            </div>
                            <div style="text-align: center; font-size: 1.5rem; color: var(--text-secondary);">
                                &#8595;&#8593;
                            </div>
                            <div>
                                <label for="fiat-currency">Fiat Currency:</label>
                                <div style="display: flex; gap: 1rem;">
                                    <select id="fiat-currency" style="flex-grow: 1;"></select>
                                    <input type="number" id="fiat-amount" placeholder="Fiat amount" style="flex-grow: 2;"/>
                                </div>
                            </div>
                        </div>
                        <div id="tool-output" style="text-align: center; font-size: 1em; margin-top: 1rem; padding: 1rem;">Loading exchange rates...</div>
                    </div>
                `,
                init: () => {
                    const piValueInput = document.getElementById('pi-value-usd');
                    const piAmountInput = document.getElementById('pi-amount');
                    const fiatAmountInput = document.getElementById('fiat-amount');
                    const fiatCurrencySelect = document.getElementById('fiat-currency');
                    const outputDiv = document.getElementById('tool-output');
                    let ratesCache = null;
                    let lastEdited = 'pi';
                    const fetchRates = async () => {
                        try {
                            const response = await fetch(`https://open.er-api.com/v6/latest/USD`);
                            if (!response.ok) throw new Error('Network response was not ok');
                            const data = await response.json();
                            ratesCache = data.rates;
                            const currencies = Object.keys(ratesCache);
                            let options = '';
                            currencies.forEach(currency => { options += `<option value="${currency}">${currency}</option>`; });
                            fiatCurrencySelect.innerHTML = options;
                            fiatCurrencySelect.value = 'INR';
                            convert();
                        } catch (error) {
                            outputDiv.innerHTML = `<p style="color:red; font-size: 1rem;">Failed to load currency data. Please try again later.</p>`;
                        }
                    };
                    const convert = () => {
                        if (!ratesCache) return;
                        const assumedPiValueUSD = parseFloat(piValueInput.value) || 0;
                        const piAmount = parseFloat(piAmountInput.value) || 0;
                        const fiatAmount = parseFloat(fiatAmountInput.value) || 0;
                        const selectedFiat = fiatCurrencySelect.value;
                        const fiatRate = ratesCache[selectedFiat];
                        if (isNaN(fiatRate)) { outputDiv.textContent = 'Error: Could not find exchange rate.'; return; }
                        if (lastEdited === 'pi') {
                            if (isNaN(assumedPiValueUSD) || isNaN(piAmount)) return;
                            const totalUSD = piAmount * assumedPiValueUSD;
                            const resultFiat = totalUSD * fiatRate;
                            fiatAmountInput.value = resultFiat.toFixed(2);
                        } else {
                            if (isNaN(fiatAmount) || assumedPiValueUSD === 0) return;
                            const totalUSD = fiatAmount / fiatRate;
                            const resultPi = totalUSD / assumedPiValueUSD;
                            piAmountInput.value = resultPi.toFixed(6);
                        }
                        outputDiv.innerHTML = `<p style="font-size: 0.9em; color: var(--text-secondary);">Current Rates: <strong>1 USD</strong> = <strong>${fiatRate.toFixed(4)} ${selectedFiat}</strong><br/>Your Rate: <strong>1 π</strong> = <strong>${(assumedPiValueUSD * fiatRate).toFixed(2)} ${selectedFiat}</strong></p>`;
                    };
                    piAmountInput.addEventListener('input', () => { lastEdited = 'pi'; convert(); });
                    fiatAmountInput.addEventListener('input', () => { lastEdited = 'fiat'; convert(); });
                    piValueInput.addEventListener('input', () => { lastEdited = 'pi'; convert(); });
                    fiatCurrencySelect.addEventListener('change', () => { lastEdited = 'pi'; convert(); });
                    fetchRates();
                }
            },
            'plateau-tracker': {
                title: 'Plateau Progress Tracker',
                icon: '🔄',
                getContent: () => `<div id="plateau-tracker-container" class="tool-container"></div>`,
                init: () => {
                    const container = document.getElementById('plateau-tracker-container');
                    const STORAGE_KEY = 'toolboxhub_plateau_trackers';
                    let trackers = JSON.parse(localStorage.getItem(STORAGE_KEY)) || {};
                    let chartInstance = null;
                    const saveTrackers = () => localStorage.setItem(STORAGE_KEY, JSON.stringify(trackers));
                    const analyzePlateau = (trackerId) => {
                        const tracker = trackers[trackerId];
                        if (!tracker || tracker.entries.length < 4) return { isPlateau: false, reason: "You need at least 4 data points for an analysis." };
                        const sortedEntries = [...tracker.entries].sort((a, b) => new Date(a.date) - new Date(b.date));
                        const recentEntries = sortedEntries.slice(-4);
                        const firstValue = recentEntries[0].value;
                        const lastValue = recentEntries[3].value;
                        if (tracker.goal === 'increase') {
                            if (lastValue <= firstValue) return { isPlateau: true, reason: "Your progress has stalled or slightly decreased over the last 4 entries." };
                        } else if (tracker.goal === 'decrease') {
                            if (lastValue >= firstValue) return { isPlateau: true, reason: "Your progress has stalled or slightly increased over the last 4 entries." };
                        }
                        return { isPlateau: false, reason: "Keep going! You're making progress." };
                    };
                    const renderTrackerDetailView = (trackerId) => {
                        if (chartInstance) chartInstance.destroy();
                        const tracker = trackers[trackerId];
                        modalTitle.innerHTML = `🔄 ${tracker.name} <small>(${tracker.unit})</small>`;
                        const plateauAnalysis = analyzePlateau(trackerId);
                        const plateauAdvice = `<div class="plateau-advice"><strong>Try these strategies to break through:</strong><ul><li><strong>Change Intensity:</strong> Try adding more weight, reps, or reducing rest times.</li><li><strong>Vary Your Routine:</strong> Introduce new exercises for the same muscle group.</li><li><strong>Check Nutrition &amp; Recovery:</strong> Ensure you're eating enough protein and getting adequate sleep.</li><li><strong>Take a Deload Week:</strong> Reduce your training volume and intensity for a week to recover.</li></ul></div>`;
                        container.innerHTML = `<canvas id="plateau-chart"></canvas><div class="plateau-analysis-box ${plateauAnalysis.isPlateau ? 'plateau-warning' : ''}"><h4>Progress Status</h4><p>${plateauAnalysis.reason}</p>${plateauAnalysis.isPlateau ? plateauAdvice : ''}</div><div style="border: 1px solid var(--border-color); padding: 1rem; border-radius: 8px; margin-top: 1.5rem;"><h4 style="margin-bottom: 1rem;">Add New Entry</h4><div style="display: grid; grid-template-columns: 1fr 1fr auto; gap: 1rem; align-items: flex-end;"><div><label for="entry-date">Date</label><input type="date" id="entry-date" value="${new Date().toISOString().slice(0, 10)}"/></div><div><label for="entry-value">Value (${tracker.unit})</label><input type="number" id="entry-value" placeholder="e.g., 100"/></div><button id="add-entry-btn" class="glow-button cta-button">Add</button></div></div><div class="plateau-data-log"><table><thead><tr><th>Date</th><th>Value (${tracker.unit})</th><th>Actions</th></tr></thead><tbody id="data-log-body"></tbody></table></div><div style="display: flex; justify-content: space-between; margin-top: 1.5rem;"><button id="back-to-list-btn" class="glow-button">&lt; All Trackers</button><button id="delete-tracker-btn" class="glow-button" style="background-color: #581c1c;">Delete Tracker</button></div>`;
                        renderDataLog(trackerId);
                        renderChart(trackerId);
                        document.getElementById('back-to-list-btn').addEventListener('click', () => { modalTitle.innerHTML = '🔄 Plateau Progress Tracker'; renderTrackerList(); });
                        document.getElementById('add-entry-btn').addEventListener('click', () => addEntry(trackerId));
                        document.getElementById('delete-tracker-btn').addEventListener('click', () => deleteTracker(trackerId));
                    };
                    const renderDataLog = (trackerId) => {
                        const tbody = document.getElementById('data-log-body');
                        tbody.innerHTML = '';
                        const sortedEntries = [...trackers[trackerId].entries].sort((a,b) => new Date(b.date) - new Date(a.date));
                        if(sortedEntries.length === 0){
                           tbody.innerHTML = '<tr><td colspan="3" style="text-align:center;">No data yet. Add an entry above to get started!</td></tr>';
                           return;
                        }
                        sortedEntries.forEach((entry, index) => {
                           const originalIndex = trackers[trackerId].entries.findIndex(e => e.date === entry.date && e.value === entry.value);
                           const row = `<tr><td>${new Date(entry.date+'T00:00:00').toLocaleDateString()}</td><td>${entry.value}</td><td><button class="edit-entry-btn" title="Edit" data-index="${originalIndex}">✏️</button><button class="delete-entry-btn" title="Delete" data-index="${originalIndex}">❌</button></td></tr>`;
                           tbody.innerHTML += row;
                        });
                        tbody.querySelectorAll('.edit-entry-btn').forEach(b => b.addEventListener('click', (e) => editEntry(trackerId, parseInt(e.currentTarget.dataset.index))));
                        tbody.querySelectorAll('.delete-entry-btn').forEach(b => b.addEventListener('click', (e) => deleteEntry(trackerId, parseInt(e.currentTarget.dataset.index))));
                    };
                    const renderChart = (trackerId) => {
                         if (chartInstance) chartInstance.destroy();
                         const tracker = trackers[trackerId];
                         if (tracker.entries.length === 0) {
                             document.getElementById('plateau-chart').style.display = 'none';
                             return;
                         }
                         document.getElementById('plateau-chart').style.display = 'block';
                         const sortedEntries = [...tracker.entries].sort((a, b) => new Date(a.date) - new Date(b.date));
                         const ctx = document.getElementById('plateau-chart').getContext('2d');
                         chartInstance = new Chart(ctx, { type: 'line', data: { labels: sortedEntries.map(e => new Date(e.date+'T00:00:00').toLocaleDateString()), datasets: [{ label: `${tracker.name} (${tracker.unit})`, data: sortedEntries.map(e => e.value), borderColor: 'var(--accent-color)', backgroundColor: 'var(--primary-glow)', tension: 0.1, fill: true }] }, options: { responsive: true, scales: { x: { ticks: { color: 'var(--text-secondary)' }, grid: { color: 'var(--border-color)' } }, y: { ticks: { color: 'var(--text-secondary)' }, grid: { color: 'var(--border-color)' } } }, plugins: { legend: { labels: { color: 'var(--text-primary)' } } } } });
                    };
                    const addEntry = (trackerId) => {
                        const date = document.getElementById('entry-date').value;
                        const value = parseFloat(document.getElementById('entry-value').value);
                        if(date && !isNaN(value)) {
                            const existingIndex = trackers[trackerId].entries.findIndex(e => e.date === date);
                            if (existingIndex > -1) {
                                if (!confirm('An entry for this date already exists. Overwrite it?')) return;
                                trackers[trackerId].entries[existingIndex].value = value;
                            } else {
                                trackers[trackerId].entries.push({ date, value });
                            }
                            saveTrackers();
                            renderTrackerDetailView(trackerId);
                        }
                    };
                    const editEntry = (trackerId, index) => {
                        const entry = trackers[trackerId].entries[index];
                        const newValue = prompt(`Edit value for ${new Date(entry.date+'T00:00:00').toLocaleDateString()}:`, entry.value);
                        if (newValue !== null && !isNaN(parseFloat(newValue))) {
                            trackers[trackerId].entries[index].value = parseFloat(newValue);
                            saveTrackers();
                            renderTrackerDetailView(trackerId);
                        }
                    };
                    const deleteEntry = (trackerId, index) => { if (confirm('Delete this entry?')) { trackers[trackerId].entries.splice(index, 1); saveTrackers(); renderTrackerDetailView(trackerId); } };
                    const deleteTracker = (trackerId) => { if (confirm(`Are you sure you want to delete the entire "${trackers[trackerId].name}" tracker and all its data? This cannot be undone.`)) { delete trackers[trackerId]; saveTrackers(); modalTitle.innerHTML = '🔄 Plateau Progress Tracker'; renderTrackerList(); } };
                    const renderNewTrackerForm = () => { container.innerHTML = `<h3>Create New Progress Tracker</h3><div><label for="tracker-name">Tracker Name</label><input type="text" id="tracker-name" placeholder="e.g., Bench Press, Body Weight"/></div><div><label for="tracker-unit">Unit</label><input type="text" id="tracker-unit" placeholder="e.g., kg, lbs, km, minutes"/></div><div><label for="tracker-goal">Primary Goal</label><select id="tracker-goal"><option value="increase">Increase the value (e.g., lift more weight)</option><option value="decrease">Decrease the value (e.g., lose body weight)</option></select></div><div style="display:flex; gap: 1rem; margin-top: 1rem;"><button id="save-new-tracker-btn" class="glow-button cta-button">Create Tracker</button><button id="cancel-new-tracker-btn" class="glow-button">Cancel</button></div>`; document.getElementById('save-new-tracker-btn').addEventListener('click', () => { const name = document.getElementById('tracker-name').value.trim(); const unit = document.getElementById('tracker-unit').value.trim(); const goal = document.getElementById('tracker-goal').value; if (name && unit) { const newId = `tracker_${Date.now()}`; trackers[newId] = { name, unit, goal, entries: [] }; saveTrackers(); renderTrackerList(); } }); document.getElementById('cancel-new-tracker-btn').addEventListener('click', renderTrackerList); };
                    const renderTrackerList = () => { if(chartInstance) chartInstance.destroy(); container.innerHTML = '<h3>Your Progress Trackers</h3><div id="tracker-list"></div><button id="create-new-tracker-btn" class="glow-button" style="margin-top: 1rem;">+ Create New Tracker</button>'; const listDiv = document.getElementById('tracker-list'); if (Object.keys(trackers).length === 0) { listDiv.innerHTML = '<p>No trackers found. Create one to get started!</p>'; } else { for (const id in trackers) { const tracker = trackers[id]; const lastEntryValue = tracker.entries.length > 0 ? [...tracker.entries].sort((a,b) => new Date(b.date) - new Date(a.date))[0].value : 'N/A'; const item = document.createElement('div'); item.className = 'plateau-tracker-list-item'; item.dataset.id = id; item.innerHTML = `<span>${tracker.name}</span> <small>Last: ${lastEntryValue} ${tracker.unit}</small>`; item.addEventListener('click', () => renderTrackerDetailView(id)); listDiv.appendChild(item); } } document.getElementById('create-new-tracker-btn').addEventListener('click', renderNewTrackerForm); };
                    renderTrackerList();
                }
            },
            'workout-calendar': {
                title: 'Editable Workout Calendar',
                icon: '🗓️',
                getContent: () => `
                    <div id="calendar-to-print">
                        <div id="calendar-container" class="tool-container" style="gap: 0;">
                            <div class="calendar-controls" style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 1rem; flex-wrap: wrap; gap: 10px;">
                                <button id="prev-month-btn" class="glow-button" style="padding: 0.5rem 1rem;">&lt; Prev</button>
                                <h3 id="month-year-title" style="font-size: 1.5rem; font-weight: 600; color: var(--heading-color);"></h3>
                                <button id="next-month-btn" class="glow-button" style="padding: 0.5rem 1rem;">Next &gt;</button>
                            </div>
                            <div class="calendar-grid-header">
                                ${['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => `<div class="day-name" style="text-align: center; padding: 0.5rem; border-radius: 6px; font-weight: 700; color: var(--text-secondary);">${day}</div>`).join('')}
                            </div>
                            <div class="calendar-grid-body" id="calendar-grid-body"></div>
                        </div>
                    </div>
                    <div class="calendar-template-controls" style="padding: 1rem; border: 1px solid var(--border-color); border-radius: 8px; margin-top: 1rem;">
                         <label for="template-select">Apply a Template (Warning: Overwrites month):</label>
                         <div style="display:flex; gap:10px; margin-top: 0.5rem;"><select id="template-select" style="flex-grow: 1;">
                            <option value="">Select a plan...</option>
                            <option value="ppl">Push/Pull/Legs</option>
                            <option value="upper-lower">4-Day Upper/Lower Split</option>
                            <option value="full-body">3-Day Beginner Full Body</option>
                         </select>
                         <button id="apply-template-btn" class="glow-button" style="padding: 0.5rem 1rem;">Apply</button></div>
                    </div>
                    <div class="calendar-actions" style="display: flex; gap: 1rem; justify-content: flex-end; margin-top: 1rem; flex-wrap: wrap;">
                        <button id="print-calendar-btn" class="glow-button">Print</button>
                        <button id="export-calendar-btn" class="glow-button">Export .txt</button>
                        <button id="clear-calendar-btn" class="glow-button" style="background-color: #FFAC0A;">Clear All Data</button>
                    </div>
                `,
                init: () => {
                    const calendarGrid = document.getElementById('calendar-grid-body');
                    const monthYearTitle = document.getElementById('month-year-title');
                    const STORAGE_KEY = 'toolboxhub_workout_calendar_data';
                    let currentDate = new Date();
                    let workoutsData = JSON.parse(localStorage.getItem(STORAGE_KEY)) || {};
                    const workoutTemplates = {
                        ppl: { 'Mon': 'Push Day', 'Tue': 'Pull Day', 'Wed': 'Rest', 'Thu': 'Leg Day', 'Fri': 'Push Day', 'Sat': 'Pull Day', 'Sun': 'Rest' },
                        'upper-lower': { 'Mon': 'Upper Body', 'Tue': 'Lower Body', 'Wed': 'Rest', 'Thu': 'Upper Body', 'Fri': 'Lower Body', 'Sat': 'Rest', 'Sun': 'Rest' },
                        'full-body': { 'Mon': 'Full Body Workout', 'Tue': 'Rest', 'Wed': 'Full Body Workout', 'Thu': 'Rest', 'Fri': 'Full Body Workout', 'Sat': 'Rest', 'Sun': 'Rest' }
                    };
                    const saveWorkouts = () => localStorage.setItem(STORAGE_KEY, JSON.stringify(workoutsData));
                    const renderCalendar = () => {
                        calendarGrid.innerHTML = '';
                        const year = currentDate.getFullYear();
                        const month = currentDate.getMonth();
                        monthYearTitle.textContent = `${currentDate.toLocaleString('default', { month: 'long' })} ${year}`;
                        const firstDayOfMonth = new Date(year, month, 1).getDay();
                        const daysInMonth = new Date(year, month + 1, 0).getDate();
                        const today = new Date();
                        today.setHours(0, 0, 0, 0);
                        for (let i = 0; i < firstDayOfMonth; i++) {
                            calendarGrid.innerHTML += `<div class="day-cell other-month"></div>`;
                        }
                        for (let day = 1; day <= daysInMonth; day++) {
                            const cellDate = new Date(year, month, day);
                            const dateString = cellDate.toISOString().split('T')[0];
                            const workout = workoutsData[dateString];
                            const cell = document.createElement('div');
                            cell.className = 'day-cell';
                            cell.dataset.date = dateString;
                            if (cellDate.getTime() === today.getTime()) cell.classList.add('today');
                            let workoutHtml = '';
                            if (workout) {
                                if (workout.completed) cell.classList.add('workout-completed');
                                workoutHtml = `<div class="workout-preview">${workout.title}</div>${workout.completed ? '<div class="workout-completed-badge">✔</div>' : ''}`;
                            }
                            cell.innerHTML = `<span class="day-number">${day}</span>${workoutHtml}`;
                            cell.addEventListener('click', () => {
                                 openModal('workout-form-editor');
                                 setTimeout(() => showWorkoutForm(dateString, workout), 0);
                            });
                            calendarGrid.appendChild(cell);
                        }
                    };
                    const showWorkoutForm = (dateString, workout) => {
                        const date = new Date(dateString + 'T00:00:00');
                        modalTitle.textContent = `Workout for ${date.toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}`;
                        document.getElementById('workout-title-input').value = workout?.title || '';
                        document.getElementById('workout-details-input').value = workout?.details || '';
                        document.getElementById('workout-completed-checkbox').checked = workout?.completed || false;
                        const saveBtn = document.getElementById('save-workout-btn');
                        const deleteBtnContainer = document.getElementById('delete-workout-btn-container');
                        const newSaveBtn = saveBtn.cloneNode(true);
                        saveBtn.parentNode.replaceChild(newSaveBtn, saveBtn);
                        newSaveBtn.addEventListener('click', () => {
                            const title = document.getElementById('workout-title-input').value.trim();
                            if (!title) { alert('Workout title cannot be empty.'); return; }
                            workoutsData[dateString] = {
                                title: title,
                                details: document.getElementById('workout-details-input').value,
                                completed: document.getElementById('workout-completed-checkbox').checked
                            };
                            saveWorkouts();
                            closeModal();
                        });
                        if (workout) {
                            deleteBtnContainer.innerHTML = `<button id="delete-workout-btn" class="glow-button" style="background-color: #581c1c;">Delete</button>`;
                            document.getElementById('delete-workout-btn').addEventListener('click', () => {
                                if (confirm('Are you sure you want to delete this workout?')) {
                                    delete workoutsData[dateString];
                                    saveWorkouts();
                                    closeModal();
                                }
                            });
                        } else {
                            deleteBtnContainer.innerHTML = '';
                        }
                    };
                    document.getElementById('prev-month-btn').addEventListener('click', () => { currentDate.setMonth(currentDate.getMonth() - 1); renderCalendar(); });
                    document.getElementById('next-month-btn').addEventListener('click', () => { currentDate.setMonth(currentDate.getMonth() + 1); renderCalendar(); });
                    document.getElementById('apply-template-btn').addEventListener('click', () => {
                        const templateKey = document.getElementById('template-select').value;
                        if (!templateKey || !confirm('This will replace all workouts for the current month. Are you sure?')) return;
                        const template = workoutTemplates[templateKey];
                        const year = currentDate.getFullYear();
                        const month = currentDate.getMonth();
                        for(let day = 1; day <= new Date(year, month + 1, 0).getDate(); day++) {
                            const date = new Date(year, month, day);
                            const dayName = date.toLocaleString('en-us', { weekday: 'short' });
                            const dateString = date.toISOString().split('T')[0];
                            const workoutTitle = template[dayName];
                            if (workoutTitle && workoutTitle !== 'Rest') {
                                workoutsData[dateString] = { title: workoutTitle, details: `${workoutTitle} from template`, completed: false };
                            } else {
                                delete workoutsData[dateString];
                            }
                        }
                        saveWorkouts();
                        renderCalendar();
                    });
                    document.getElementById('print-calendar-btn').addEventListener('click', () => window.print());
                    document.getElementById('export-calendar-btn').addEventListener('click', () => {
                        let exportText = "ToolBox Hub Workout Calendar Export\n\n";
                        Object.keys(workoutsData).sort().forEach(date => { const w = workoutsData[date]; exportText += `--- ${date} ---\nTitle: ${w.title}\nStatus: ${w.completed ? 'Completed' : 'Not Completed'}\nDetails:\n${w.details || 'N/A'}\n\n`; });
                        const blob = new Blob([exportText], {type: 'text/plain'});
                        const url = URL.createObjectURL(blob);
                        const a = document.createElement('a'); a.href = url; a.download = 'workout_calendar_export.txt'; a.click(); URL.revokeObjectURL(url);
                    });
                    document.getElementById('clear-calendar-btn').addEventListener('click', () => { if (confirm('DANGER! This will permanently delete all your workout data. Are you absolutely sure?')) { workoutsData = {}; saveWorkouts(); renderCalendar(); } });
                    toolImplementations['workout-form-editor'] = { title: "Edit Workout", getContent: () => `<div class="tool-container" id="workout-form"><div><label for="workout-title-input">Workout Title:</label><input type="text" id="workout-title-input"/></div><div><label for="workout-details-input">Exercises / Notes:</label><textarea id="workout-details-input" rows="6"></textarea></div><div style="display:flex; align-items: center; gap: 10px;"><input type="checkbox" id="workout-completed-checkbox" style="width: auto;"/><label for="workout-completed-checkbox" style="font-weight: normal;">Mark as Completed</label></div><div style="display: flex; justify-content: space-between; align-items: center; margin-top: 1rem;"><button id="save-workout-btn" class="glow-button cta-button">Save</button><div id="delete-workout-btn-container"></div></div></div>`, init: () => {} };
                    modal.addEventListener('modal:close', renderCalendar);
                    renderCalendar();
                }
            },
            'bmi-calculator': {
                title: 'BMI Calculator',
                icon: '⚖️',
                getContent: () => `
                    <div class="tool-container">
                        <div><label for="bmi-height">Height (cm):</label><input type="number" id="bmi-height" placeholder="e.g., 175"/></div>
                        <div><label for="bmi-weight">Weight (kg):</label><input type="number" id="bmi-weight" placeholder="e.g., 70"/></div>
                        <button id="bmi-calculate" class="glow-button">Calculate BMI</button><div id="tool-output"></div>
                    </div>`,
                init: () => {
                    document.getElementById('bmi-calculate').addEventListener('click', () => {
                        const height = parseFloat(document.getElementById('bmi-height').value), weight = parseFloat(document.getElementById('bmi-weight').value), output = document.getElementById('tool-output');
                        if (height > 0 && weight > 0) {
                            const bmi = (weight / ((height / 100) ** 2)).toFixed(2); let category = '';
                            if (bmi < 18.5) category = 'Underweight'; else if (bmi < 24.9) category = 'Normal weight'; else if (bmi < 29.9) category = 'Overweight'; else category = 'Obese';
                            output.innerHTML = `<p><strong>Your BMI is: ${bmi}</strong></p><p>This is considered: <strong>${category}</strong></p><div style="width:100%; background:var(--dark-bg); border-radius:5px; margin-top:10px; border:1px solid var(--border-color);"><div style="width:${Math.min(100, (bmi/40)*100)}%; background:var(--accent-color); height:20px; border-radius:5px;"></div></div>`;
                        } else { output.textContent = 'Please enter valid height and weight.'; }
                    });
                }
            },
            'bmr-calculator': {
                title: 'BMR &amp; Calorie Analyzer',
                icon: '🔥',
                getContent: () => `<div class="tool-container"><div><label for="bmr-age">Age:</label><input type="number" id="bmr-age" placeholder="e.g., 25"/></div><div><label>Gender:</label><select id="bmr-gender"><option value="male">Male</option><option value="female">Female</option></select></div><div><label for="bmr-height">Height (cm):</label><input type="number" id="bmr-height" placeholder="e.g., 175"/></div><div><label for="bmr-weight">Weight (kg):</label><input type="number" id="bmr-weight" placeholder="e.g., 70"/></div><div><label>Activity Level:</label><select id="bmr-activity"><option value="1.2">Sedentary</option><option value="1.375">Lightly active</option><option value="1.55">Moderately active</option><option value="1.725">Very active</option><option value="1.9">Extra active</option></select></div><button id="bmr-calculate" class="glow-button">Calculate</button><div id="tool-output"></div></div>`,
                init: () => {
                    document.getElementById('bmr-calculate').addEventListener('click', () => {
                           const age = parseFloat(document.getElementById('bmr-age').value), gender = document.getElementById('bmr-gender').value, height = parseFloat(document.getElementById('bmr-height').value), weight = parseFloat(document.getElementById('bmr-weight').value), activity = parseFloat(document.getElementById('bmr-activity').value), output = document.getElementById('tool-output');
                           if (age > 0 && height > 0 && weight > 0) {
                               let bmr = gender === 'male' ? 88.362 + (13.397 * weight) + (4.799 * height) - (5.677 * age) : 447.593 + (9.247 * weight) + (3.098 * height) - (4.330 * age);
                               const dailyCalories = bmr * activity;
                               output.innerHTML = `<p><strong>BMR:</strong> ${bmr.toFixed(0)} Cal/day</p><p><strong>Daily Needs:</strong> ${dailyCalories.toFixed(0)} Cal/day</p>`;
                           } else { output.textContent = 'Please fill in all fields with valid numbers.'; }
                    });
                }
            },
             'keto-calculator': {
                title: 'Keto Macro Calculator',
                icon: '🥑',
                getContent: () => `<div class="tool-container" id="keto-calculator-tool"></div>`,
                init: () => {
                     document.getElementById('keto-calculator-tool').innerHTML = `<div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.5rem;"><div><label for="keto-age">Age</label><input type="number" id="keto-age" placeholder="e.g., 30"/></div><div><label for="keto-gender">Gender</label><select id="keto-gender"><option value="male">Male</option><option value="female">Female</option></select></div><div><label for="keto-weight">Weight</label><div class="input-group-toggle" style="display: flex; align-items: center; gap: 10px;"><input type="number" id="keto-weight" placeholder="e.g., 70"/><div class="unit-toggle" id="keto-weight-toggle" style="background-color: var(--button-bg); border: 1px solid var(--border-color); border-radius: 6px; display: flex;"><button class="active" data-unit="kg">kg</button><button data-unit="lbs">lbs</button></div></div></div><div><label for="keto-height">Height</label><div class="input-group-toggle" style="display: flex; align-items: center; gap: 10px;"><input type="number" id="keto-height" placeholder="e.g., 175"/><div class="unit-toggle" id="keto-height-toggle" style="background-color: var(--button-bg); border: 1px solid var(--border-color); border-radius: 6px; display: flex;"><button class="active" data-unit="cm">cm</button><button data-unit="ft">ft/in</button></div><input type="number" id="keto-height-in" placeholder="in" style="display: none; width: 80px;"/></div></div><div><label for="keto-activity">Activity</label><select id="keto-activity"><option value="1.2">Sedentary</option><option value="1.375">Lightly Active</option><option value="1.55">Active</option><option value="1.725">Very Active</option></select></div><div><label for="keto-goal">Goal</label><select id="keto-goal"><option value="lose">Lose Weight (20% deficit)</option><option value="maintain">Maintain</option><option value="gain">Gain Muscle (15% surplus)</option></select></div></div><div id="keto-results-container" style="display: none; margin-top: 2rem; border-top: 2px solid var(--accent-color); padding-top: 2rem;"><div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.5rem; align-items: center;"><div id="keto-output-text"></div><div style="position: relative; min-height: 280px;"><canvas id="keto-pie-chart"></canvas></div></div><div style="display: flex; flex-wrap: wrap; gap: 10px; margin-top: 1.5rem; justify-content: center;"><button id="keto-share-btn" class="glow-button">Share</button><button id="keto-download-btn" class="glow-button">Download</button><button id="keto-reset-btn" class="glow-button">Reset</button></div></div>`;
                    const ageIn = document.getElementById('keto-age'), genderIn = document.getElementById('keto-gender'), weightIn = document.getElementById('keto-weight'), heightIn = document.getElementById('keto-height'), heightInIn = document.getElementById('keto-height-in'), activityIn = document.getElementById('keto-activity'), goalIn = document.getElementById('keto-goal'), weightToggle = document.getElementById('keto-weight-toggle'), heightToggle = document.getElementById('keto-height-toggle'), resultsContainer = document.getElementById('keto-results-container'), outputText = document.getElementById('keto-output-text'), shareBtn = document.getElementById('keto-share-btn'), downloadBtn = document.getElementById('keto-download-btn'), resetBtn = document.getElementById('keto-reset-btn');
                    const ctx = document.getElementById('keto-pie-chart').getContext('2d');
                    let ketoChart;
                    const STORAGE_KEY = 'toolboxhub-keto-calculator';
                    const allInputs = [ageIn, genderIn, weightIn, heightIn, heightInIn, activityIn, goalIn];
                    const calculateMacros = () => {
                        const age = parseInt(ageIn.value), gender = genderIn.value, activity = parseFloat(activityIn.value), goal = goalIn.value;
                        let weightKg = parseFloat(weightIn.value);
                        if (weightToggle.querySelector('[data-unit="lbs"]').classList.contains('active')) weightKg *= 0.453592;
                        let heightCm = parseFloat(heightIn.value);
                        if (heightToggle.querySelector('[data-unit="ft"]').classList.contains('active')) { const feet = parseFloat(heightIn.value) || 0; const inches = parseFloat(heightInIn.value) || 0; heightCm = (feet * 12 + inches) * 2.54; }
                        if (!age || !weightKg || !heightCm) { resultsContainer.style.display = 'none'; return; }
                        let bmr = gender === 'male' ? 10 * weightKg + 6.25 * heightCm - 5 * age + 5 : 10 * weightKg + 6.25 * heightCm - 5 * age - 161;
                        let tdee = bmr * activity;
                        if (goal === 'lose') tdee *= 0.8; if (goal === 'gain') tdee *= 1.15;
                        const proteinGrams = weightKg * 1.5, proteinCals = proteinGrams * 4, carbsGrams = 25, carbsCals = carbsGrams * 4;
                        const fatCals = tdee - proteinCals - carbsCals, fatGrams = fatCals / 9;
                        displayResults({ tdee, fatGrams, proteinGrams, carbsGrams }); saveInputs();
                    };
                    const displayResults = (results) => {
                        resultsContainer.style.display = 'block';
                        const { tdee, fatGrams, proteinGrams, carbsGrams } = results;
                        outputText.innerHTML = `<h3 style="color:var(--accent-color); font-size:1.5em; margin-bottom:1rem;">${Math.round(tdee)} kcal/day</h3><p style="font-size:1.2em; line-height:1.8;"><strong style="color: #54a0ff;">Fat:</strong> ${Math.round(fatGrams)}g<br/><strong style="color: #ff6b6b;">Protein:</strong> ${Math.round(proteinGrams)}g<br/><strong style="color: #feca57;">Carbs:</strong> ${Math.round(carbsGrams)}g</p>`;
                        const chartData = { labels: ['Fat', 'Protein', 'Carbs'], datasets: [{ data: [Math.round(fatGrams), Math.round(proteinGrams), Math.round(carbsGrams)], backgroundColor: ['#54a0ff', '#ff6b6b', '#feca57'], borderColor: 'var(--dark-bg)', borderWidth: 4 }] };
                        if (ketoChart) ketoChart.destroy();
                        ketoChart = new Chart(ctx, { type: 'pie', data: chartData, options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: true, position: 'top', labels: { color: 'var(--text-primary)' } }, tooltip: { callbacks: { label: (c) => `${c.label}: ${c.raw}g` } } } } });
                    };
                    const saveInputs = () => { const inputs = { age: ageIn.value, gender: genderIn.value, weight: weightIn.value, height: heightIn.value, heightIn: heightInIn.value, activity: activityIn.value, goal: goalIn.value, weightUnit: weightToggle.querySelector('.active').dataset.unit, heightUnit: heightToggle.querySelector('.active').dataset.unit }; localStorage.setItem(STORAGE_KEY, JSON.stringify(inputs)); };
                    const loadInputs = () => { const saved = JSON.parse(localStorage.getItem(STORAGE_KEY)); if (saved) { ageIn.value = saved.age; genderIn.value = saved.gender; weightIn.value = saved.weight; heightIn.value = saved.height; heightInIn.value = saved.heightIn; activityIn.value = saved.activity; goalIn.value = saved.goal; weightToggle.querySelectorAll('button').forEach(b => b.classList.toggle('active', b.dataset.unit === saved.weightUnit)); heightToggle.querySelectorAll('button').forEach(b => b.classList.toggle('active', b.dataset.unit === saved.heightUnit)); heightInIn.style.display = saved.heightUnit === 'ft' ? 'block' : 'none'; calculateMacros(); } };
                    allInputs.forEach(input => input.addEventListener('input', calculateMacros));
                    weightToggle.addEventListener('click', e => { if(e.target.tagName === 'BUTTON') { weightToggle.querySelector('.active').classList.remove('active'); e.target.classList.add('active'); calculateMacros(); } });
                    heightToggle.addEventListener('click', e => { if(e.target.tagName === 'BUTTON') { heightToggle.querySelector('.active').classList.remove('active'); e.target.classList.add('active'); heightInIn.style.display = e.target.dataset.unit === 'ft' ? 'block' : 'none'; calculateMacros(); } });
                    shareBtn.addEventListener('click', () => { navigator.clipboard.writeText(`My Keto Macro Plan:\n${outputText.innerText}\nGenerated by ToolBox Hub.`).then(() => { shareBtn.textContent = 'Copied!'; setTimeout(() => { shareBtn.textContent = 'Share'; }, 2000); }); });
                    downloadBtn.addEventListener('click', () => { const a = document.createElement('a'); a.href = ketoChart.toBase64Image(); a.download = 'keto-macro-chart.png'; a.click(); });
                    resetBtn.addEventListener('click', () => { allInputs.forEach(input => input.value = ''); resultsContainer.style.display = 'none'; if (ketoChart) ketoChart.destroy(); localStorage.removeItem(STORAGE_KEY); ageIn.focus(); });
                    loadInputs();
                }
            },
            'tdee-calculator': {
                title: 'TDEE Calculator',
                icon: '🍽️',
                getContent: () => `
                    <div class="tool-container">
                        <div><label for="tdee-age">Age:</label><input type="number" id="tdee-age" placeholder="e.g., 25"/></div>
                        <div><label>Gender:</label><select id="tdee-gender"><option value="male">Male</option><option value="female">Female</option></select></div>
                        <div><label for="tdee-height">Height (cm):</label><input type="number" id="tdee-height" placeholder="e.g., 175"/></div>
                        <div><label for="tdee-weight">Weight (kg):</label><input type="number" id="tdee-weight" placeholder="e.g., 70"/></div>
                        <div><label>Activity Level:</label><select id="tdee-activity">
                            <option value="1.2">Sedentary</option><option value="1.375">Lightly Active</option><option value="1.55">Moderately Active</option><option value="1.725">Very Active</option><option value="1.9">Extra Active</option>
                        </select></div>
                        <button id="tdee-calculate" class="glow-button">Calculate TDEE</button><div id="tool-output"></div>
                    </div>`,
                init: () => {
                    document.getElementById('tdee-calculate').addEventListener('click', () => {
                        const age = parseFloat(document.getElementById('tdee-age').value), gender = document.getElementById('tdee-gender').value, height = parseFloat(document.getElementById('tdee-height').value), weight = parseFloat(document.getElementById('tdee-weight').value), activity = parseFloat(document.getElementById('tdee-activity').value), output = document.getElementById('tool-output');
                        if (age > 0 && height > 0 && weight > 0) {
                            let bmr = (10 * weight) + (6.25 * height) - (5 * age) + (gender === 'male' ? 5 : -161);
                            const tdee = bmr * activity;
                            output.innerHTML = `<p style="border-bottom: 1px solid var(--border-color); padding-bottom: 10px; margin-bottom: 10px;"><strong>Maintenance Calories: ${tdee.toFixed(0)} kcal/day</strong><br/><small>This is your TDEE.</small></p><p><strong>For Weight Loss:</strong><br/>Mild (0.25 kg/wk): <strong>${(tdee - 250).toFixed(0)}</strong> kcal/day<br/>Standard (0.5 kg/wk): <strong>${(tdee - 500).toFixed(0)}</strong> kcal/day</p><p style="margin-top:10px;"><strong>For Weight Gain:</strong><br/>Mild (0.25 kg/wk): <strong>${(tdee + 250).toFixed(0)}</strong> kcal/day<br/>Standard (0.5 kg/wk): <strong>${(tdee + 500).toFixed(0)}</strong> kcal/day</p>`;
                        } else { output.textContent = 'Please fill in all fields with valid positive numbers.'; }
                    });
