            },
            'habit-tracker': {
                title: 'Daily Habit Tracker',
                icon: '✔️',
                getContent: () => `<div class="tool-container"><p>Track your daily habits. Your data is saved automatically in your browser.</p><div id="habits-list"></div><div style="display:flex; gap:10px; margin-top:1rem;"><input type="text" id="new-habit-input" placeholder="e.g., Drank 8 glasses of water"/><button id="add-habit-btn" class="glow-button">Add</button></div></div>`,
                init: () => {
                    const list = document.getElementById('habits-list'), input = document.getElementById('new-habit-input'), btn = document.getElementById('add-habit-btn'), key = 'toolboxhub-habits';
                    const load = () => JSON.parse(localStorage.getItem(key)) || {}; const save = data => localStorage.setItem(key, JSON.stringify(data));
                    const render = () => {
                        const today = new Date().toISOString().slice(0, 10); const allHabits = load(); const habits = allHabits[today] || []; list.innerHTML = habits.length ? '' : '<p>No habits tracked for today. Add one below!</p>';
                        habits.forEach((h, i) => { const el = document.createElement('div'); el.style.cssText = 'display:flex; align-items:center; justify-content:space-between; padding:10px; border-bottom:1px solid var(--border-color);'; el.innerHTML = `<span style="text-decoration:${h.done?'line-through':'none'}; cursor:pointer;" data-index="${i}">${h.text}</span><button data-index="${i}" style="background:red; color:white; border:none; border-radius:5px; padding:5px 10px; cursor:pointer;">X</button>`; list.appendChild(el); });
                    };
                    list.addEventListener('click', e => { const idx = e.target.dataset.index; if (idx === undefined) return; const today = new Date().toISOString().slice(0, 10); const allHabits = load(); if (e.target.tagName === 'SPAN') allHabits[today][idx].done = !allHabits[today][idx].done; if (e.target.tagName === 'BUTTON') allHabits[today].splice(idx, 1); save(allHabits); render(); });
                    btn.addEventListener('click', () => { const text = input.value.trim(); if (!text) return; const today = new Date().toISOString().slice(0, 10); const allHabits = load(); if (!allHabits[today]) allHabits[today] = []; allHabits[today].push({ text, done: false }); save(allHabits); input.value = ''; render(); });
                    render();
                }
            },
            'breathing-exercise': {
                title: 'Breathing Exercise Guide',
                icon: '🧘',
                getContent: () => `
                    <div class="tool-container" style="align-items: center;">
                        <div class="breathing-container" style="display: flex; flex-direction: column; align-items: center; justify-content: center; margin: 20px 0; min-height: 200px;">
                           <div id="modalBreathingCircle" style="width: 120px; height: 120px; background-color: var(--accent-color); border-radius: 50%; display: flex; align-items: center; justify-content: center; color: var(--dark-bg); font-weight: bold; font-size: 1.2em; transition: all 0.5s ease-in-out;"></div>
                           <p id="modalBreathingInstructions" style="margin-top: 15px; font-size: 1.1em; color: var(--text-primary); text-align: center;">Click 'Start' to begin.</p>
                        </div>
                        <div style="display:flex; gap: 10px;">
                           <button id="modalStartBreathingBtn" class="glow-button cta-button">Start</button>
                           <button id="modalToggleSoundBtn" class="glow-button">Toggle Sound</button>
                        </div>
                        <audio id="modalBackgroundMusic" loop=""><source src="https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3" type="audio/mpeg"></source></audio>
                    </div>`,
                init: () => {
                    const circle = document.getElementById('modalBreathingCircle');
                    const instructions = document.getElementById('modalBreathingInstructions');
                    const startBtn = document.getElementById('modalStartBreathingBtn');
                    const soundBtn = document.getElementById('modalToggleSoundBtn');
                    const music = document.getElementById('modalBackgroundMusic');
                    let isBreathing = false, bInterval;
                    const phases = [
                        { name: 'Inhale...', duration: 4000, scale: 1.5, shadow: '0 0 30px var(--secondary-glow)' }, 
                        { name: 'Hold', duration: 4000, scale: 1.5, shadow: '0 0 30px var(--secondary-glow)' }, 
                        { name: 'Exhale...', duration: 6000, scale: 1, shadow: '0 0 15px var(--primary-glow)' }
                    ];
                    let phaseIndex = 0;
                    const runPhase = () => {
                        const phase = phases[phaseIndex];
                        instructions.textContent = phase.name;
                        circle.style.transform = `scale(${phase.scale})`;
                        circle.style.boxShadow = phase.shadow;
                        phaseIndex = (phaseIndex + 1) % phases.length;
                        bInterval = setTimeout(runPhase, phase.duration);
                    };
                    const start = () => { if (isBreathing) return; isBreathing = true; startBtn.textContent = 'Stop'; phaseIndex = 0; runPhase(); music.play().catch(()=>{}); };
                    const stop = () => { if (!isBreathing) return; isBreathing = false; startBtn.textContent = 'Start'; clearTimeout(bInterval); instructions.textContent = "Click 'Start' to begin."; circle.style.transform = 'scale(1)'; circle.style.boxShadow = 'none'; music.pause(); music.currentTime = 0; };
                    startBtn.addEventListener('click', () => isBreathing ? stop() : start());
                    soundBtn.addEventListener('click', () => { music.muted = !music.muted; soundBtn.style.opacity = music.muted ? 0.6 : 1;});
                    modal.addEventListener('modal:close', stop, { once: true });
                }
            },
            'fitness-challenge-wheel': {
                title: 'Fitness Challenge Wheel',
                icon: '🎡',
                getContent: () => `<div class="tool-container" style="align-items:center;"><div class="challenge-wheel-container" style="display: flex; flex-direction: column; align-items: center; justify-content: center; margin: 20px 0;"><canvas id="challengeWheelCanvas" width="300" height="300"></canvas><div id="challengeResult" style="margin-top: 20px; font-size: 1.4em; font-weight: bold; color: var(--accent-color); text-align: center; min-height: 30px;">Spin the wheel!</div></div><button id="spinWheelBtn" class="glow-button">Spin Wheel</button><div id="confettiContainer" style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none; overflow: hidden;"></div></div>`,
                init: () => {
                    const canvas = document.getElementById('challengeWheelCanvas'), ctx = canvas.getContext('2d'), spinBtn = document.getElementById('spinWheelBtn'), resultDisplay = document.getElementById('challengeResult'), confettiContainer = document.getElementById('confettiContainer');
                    const challenges = ["10 Push-ups", "20 Squats", "1 Min Plank", "15 Lunges", "25 Crunches", "30 Jacks", "10 Burpees", "2 Min Wall Sit"]; const colors = ['#FF6347', '#FFD700', '#6A5ACD', '#3CB371', '#FF69B4', '#4682B4', '#DAA520', '#ADFF2F'];
                    let spinning = false, animationFrameId; const borderColor = getComputedStyle(document.body).getPropertyValue('--border-color').trim();
                    function drawWheel() { ctx.clearRect(0, 0, 300, 300); const centerX = 150, centerY = 150, radius = 145; const arcSize = 2 * Math.PI / challenges.length; for (let i = 0; i < challenges.length; i++) { const startAngle = i * arcSize, endAngle = (i + 1) * arcSize; ctx.beginPath(); ctx.arc(centerX, centerY, radius, startAngle, endAngle); ctx.lineTo(centerX, centerY); ctx.fillStyle = colors[i % colors.length]; ctx.fill(); ctx.strokeStyle = borderColor; ctx.lineWidth = 2; ctx.stroke(); ctx.save(); ctx.translate(centerX, centerY); ctx.rotate(startAngle + arcSize / 2); ctx.textAlign = 'right'; ctx.fillStyle = 'white'; ctx.font = 'bold 14px Arial'; ctx.fillText(challenges[i], radius * 0.9, 0); ctx.restore(); } ctx.beginPath(); ctx.fillStyle = 'white'; ctx.moveTo(295, 150); ctx.lineTo(275, 140); ctx.lineTo(275, 160); ctx.fill(); }
                    function spin() { if (spinning) return; spinning = true; spinBtn.disabled = true; resultDisplay.textContent = "Spinning..."; const targetAngle = (360 * 5) + (Math.random() * 360); const startTime = performance.now(), duration = 4000; function animate(time) { const elapsed = time - startTime; if (elapsed < duration) { const eased = 1 - Math.pow(1 - (elapsed / duration), 3); const rotation = eased * targetAngle; canvas.style.transform = `rotate(${rotation}deg)`; animationFrameId = requestAnimationFrame(animate); } else { spinning = false; spinBtn.disabled = false; const finalRotation = targetAngle % 360; canvas.style.transform = `rotate(${finalRotation}deg)`; const finalAngle = (360 - finalRotation + 360) % 360; const segmentAngle = 360 / challenges.length; const landedIndex = Math.floor(finalAngle / segmentAngle); resultDisplay.textContent = `Challenge: ${challenges[landedIndex]}`; /* Confetti */ for (let i = 0; i < 50; i++) { const c = document.createElement('div'); c.className = 'confetti'; c.style.cssText=`position:absolute; width:10px; height:10px; opacity:0; animation:confetti-fall 2s forwards ease-out; left:${Math.random()*100}%; top:${Math.random()*100}%; background-color:${colors[Math.floor(Math.random()*colors.length)]};--x:${(Math.random()-.5)*400}px;--y:${Math.random()*300+100}px;--rot:${Math.random()*720}deg;`; c.addEventListener('animationend', () => c.remove()); confettiContainer.appendChild(c); } } } animationFrameId = requestAnimationFrame(animate); }
                    drawWheel(); spinBtn.addEventListener('click', spin);
                    modal.addEventListener('modal:close', () => { if (animationFrameId) cancelAnimationFrame(animationFrameId); }, { once: true });
                }
            },
            'portion-visualizer': {
                title: 'Meal Portion Visualizer',
                icon: '✋',
                getContent: () => `<div class="tool-container"><p>Select your details to get a visual estimate of your meal portions. These are general guidelines.</p><div style="display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 1.5rem;"><div><label for="portion-gender">Gender:</label><select id="portion-gender"><option value="female">Female</option><option value="male">Male</option></select></div><div><label for="portion-age">Age Group:</label><select id="portion-age"><option value="adult">Adult (19-50)</option><option value="teen">Teen (14-18)</option><option value="child">Child (4-13)</option><option value="senior">Senior (50+)</option></select></div></div><div id="portion-output-area" style="display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 1rem; text-align: center;"><div class="portion-display-card" style="padding:1rem; border:1px solid var(--border-color); border-radius:8px;"><h4>Protein</h4><div id="protein-visual" style="font-size: 4rem; line-height: 1.2; color: #ff6b6b;"></div><p id="protein-text" style="font-weight: bold;"></p></div><div class="portion-display-card" style="padding:1rem; border:1px solid var(--border-color); border-radius:8px;"><h4>Vegetables</h4><div id="veg-visual" style="font-size: 4rem; line-height: 1.2; color: #2ecc71;"></div><p id="veg-text" style="font-weight: bold;"></p></div><div class="portion-display-card" style="padding:1rem; border:1px solid var(--border-color); border-radius:8px;"><h4>Carbs</h4><div id="carbs-visual" style="font-size: 4rem; line-height: 1.2; color: #feca57;"></div><p id="carbs-text" style="font-weight: bold;"></p></div><div class="portion-display-card" style="padding:1rem; border:1px solid var(--border-color); border-radius:8px;"><h4>Fats</h4><div id="fats-visual" style="font-size: 4rem; line-height: 1.2; color: #54a0ff;"></div><p id="fats-text" style="font-weight: bold;"></p></div></div><p style="margin-top: 1.5rem; font-size: 0.9em; color: var(--text-secondary);"><strong>Reference Key:</strong> ✋ Palm, ✊ Fist, 👍 Thumb. These are per-meal estimates.</p></div>`,
                init: () => {
                    const genderSelect = document.getElementById('portion-gender'), ageSelect = document.getElementById('portion-age'), proteinVisual = document.getElementById('protein-visual'), proteinText = document.getElementById('protein-text'), carbsVisual = document.getElementById('carbs-visual'), carbsText = document.getElementById('carbs-text'), fatsVisual = document.getElementById('fats-visual'), fatsText = document.getElementById('fats-text'), vegVisual = document.getElementById('veg-visual'), vegText = document.getElementById('veg-text');
                    function updatePortions() {
                        const gender = genderSelect.value, age = ageSelect.value; let p, c, f, v;
                        if (age === 'child') { p = { text: '1 Palm', visual: '✋' }; v = { text: '1 Fist', visual: '✊' }; c = { text: '1 Cupped Hand', visual: '✊' }; f = { text: '1 Thumb', visual: '👍' }; } 
                        else if (gender === 'male') { p = { text: '2 Palms', visual: '✋✋' }; v = { text: '2 Fists', visual: '✊✊' }; c = { text: '2 Cupped Hands', visual: '✊✊' }; f = { text: '2 Thumbs', visual: '👍👍' }; } 
                        else { p = { text: '1 Palm', visual: '✋' }; v = { text: '1 Fist', visual: '✊' }; c = { text: '1 Cupped Hand', visual: '✊' }; f = { text: '1 Thumb', visual: '👍' }; }
                        proteinVisual.textContent = p.visual; proteinText.textContent = p.text; carbsVisual.textContent = c.visual; carbsText.textContent = c.text; fatsVisual.textContent = f.visual; fatsText.textContent = f.text; vegVisual.textContent = v.visual; vegText.textContent = v.text;
                    }
                    genderSelect.addEventListener('change', updatePortions); ageSelect.addEventListener('change', updatePortions); updatePortions();
                }
            },
            'fitness-challenge-generator': {
                title: '30-Day Fitness Challenge',
                icon: '🏅',
                getContent: () => `<div class="tool-container" id="challenge-generator-tool"></div>`,
                init: () => {
                     document.getElementById('challenge-generator-tool').innerHTML = `<div id="challenge-setup" style="padding: 1rem; border: 1px solid var(--border-color); border-radius: 8px; margin-bottom: 1.5rem;"><div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1rem;"><div><label for="challenge-exercise">Select Exercise:</label><select id="challenge-exercise"><option value="Push-ups">Push-ups</option><option value="Squats">Squats</option><option value="Crunches">Crunches</option><option value="Plank" data-unit="seconds">Plank (seconds)</option></select></div><div><label for="challenge-type">Plan Type:</label><select id="challenge-type"><option value="goal">Goal-Based</option><option value="random">Progressive Random</option></select></div></div><div id="goal-inputs" style="margin-top: 1rem; display: grid; grid-template-columns: 1fr 1fr; gap: 1rem;"><div><label for="start-value">Starting Reps/Secs:</label><input type="number" id="start-value" value="10"/></div><div><label for="end-goal">30-Day Goal:</label><input type="number" id="end-goal" value="50"/></div></div><button id="generate-challenge-btn" class="glow-button" style="margin-top: 1.5rem; width: 100%;">Generate My Challenge</button></div><div id="challenge-display" style="display: none;"><div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 1rem;"><h3 id="challenge-title" style="margin: 0;"></h3><button id="reset-challenge-btn" class="glow-button" style="padding: 0.5rem 1rem;">Start New</button></div><div id="challenge-progress-container" style="background-color: var(--button-bg); border-radius: 5px; padding: 3px; margin-bottom: 1rem;"><div id="challenge-progress-bar" style="width: 0%; height: 25px; background-color: var(--accent-color); border-radius: 5px; text-align: center; line-height: 25px; color: var(--dark-bg); font-weight: bold; transition: width 0.5s ease;">0%</div></div><div id="challenge-plan-container" style="display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1rem; max-height: 40vh; overflow-y: auto; padding: 0.5rem;"></div><div id="celebration-gif-container" style="text-align: center; margin-top: 1.5rem; display: none;"><h3>Congratulations! Challenge Complete!</h3><img id="celebration-gif" src="" alt="Celebration!" style="max-width: 80%; border-radius: 8px; margin-top: 1rem;"/></div></div>`;
                    const setupDiv = document.getElementById('challenge-setup'), displayDiv = document.getElementById('challenge-display'), planContainer = document.getElementById('challenge-plan-container'), typeSelect = document.getElementById('challenge-type'), goalInputs = document.getElementById('goal-inputs'), generateBtn = document.getElementById('generate-challenge-btn'), resetBtn = document.getElementById('reset-challenge-btn'), progressBar = document.getElementById('challenge-progress-bar'), challengeTitle = document.getElementById('challenge-title'), celebrationContainer = document.getElementById('celebration-gif-container'), celebrationGif = document.getElementById('celebration-gif');
                    const STORAGE_KEY = 'toolboxhub-30day-challenge', celebrationGifs = ['https://media.giphy.com/media/artj92V8o75VPL7AeQ/giphy.gif', 'https://media.giphy.com/media/v1.Y2lkPTc5MGI3NjExNTF1MWo1aXhyM3A2d3FhOW94ajd0ajRrcjJ0OHQ0bmpxMmQ5MmU3OSZlcD12MV9pbnRlcm5hbF9naWZfYnlfaWQmY3Q9Zw/kyLYXonQYYfwYDIeZl/giphy.gif', 'https://media.giphy.com/media/3oz8xAFtqoOUUrsh7W/giphy.gif'];
                    let challengeData = {};
                    const updateUI = () => { const hasChallenge = challengeData && challengeData.plan; setupDiv.style.display = hasChallenge ? 'none' : 'block'; displayDiv.style.display = hasChallenge ? 'block' : 'none'; goalInputs.style.display = typeSelect.value === 'goal' ? 'grid' : 'none'; };
                    const saveChallenge = () => localStorage.setItem(STORAGE_KEY, JSON.stringify(challengeData));
                    const loadChallenge = () => { const saved = localStorage.getItem(STORAGE_KEY); if (saved) { challengeData = JSON.parse(saved); return true; } return false; };
                    const renderPlan = () => { if (!challengeData.plan) return; planContainer.innerHTML = ''; challengeTitle.textContent = `Your 30-Day ${challengeData.exercise} Challenge`; challengeData.plan.forEach(day => { const item = document.createElement('div'); item.className = `challenge-day-item ${day.completed ? 'completed' : ''}`; item.style.cssText=`background: ${day.completed ? '#274746' : 'var(--button-bg)'}; border: 1px solid var(--border-color); border-radius: 8px; padding: 1rem; display: flex; align-items: center; justify-content: space-between;`; const taskText = day.isRest ? 'Rest Day' : `${day.value} ${challengeData.unit}`; item.innerHTML = `<b>Day ${day.day}</b><label for="day-${day.day}" style="flex-grow:1; margin-left:1rem; cursor:pointer; text-decoration: ${day.completed ? 'line-through' : 'none'};">${taskText}</label><input type="checkbox" id="day-${day.day}" data-day="${day.day}" ${day.isRest ? 'disabled' : ''} ${day.completed ? 'checked' : ''} style="width:20px;height:20px;"/>`; planContainer.appendChild(item); }); };
                    const updateProgress = () => { const activeDays = challengeData.plan.filter(d => !d.isRest); const completedDays = activeDays.filter(d => d.completed); const progress = activeDays.length > 0 ? (completedDays.length / activeDays.length) * 100 : 0; progressBar.style.width = `${progress}%`; progressBar.textContent = `${Math.round(progress)}%`; if (progress >= 100) { celebrationGif.src = celebrationGifs[Math.floor(Math.random() * celebrationGifs.length)]; celebrationContainer.style.display = 'block'; } else { celebrationContainer.style.display = 'none'; } };
                    const handleGenerate = () => { const exerciseSelect = document.getElementById('challenge-exercise'); const exercise = exerciseSelect.value, unit = exerciseSelect.options[exerciseSelect.selectedIndex].dataset.unit || 'reps', type = typeSelect.value; const startVal = parseInt(document.getElementById('start-value').value) || 10, endGoal = parseInt(document.getElementById('end-goal').value) || 50; challengeData = { exercise, unit, plan: [] }; let dailyValues = []; if (type === 'goal') { const increment = (endGoal - startVal) / 24; for (let i = 0; i < 30; i++) { if ((i + 1) % 5 === 0) dailyValues.push({ isRest: true }); else { const val = Math.round(startVal + (dailyValues.filter(d => !d.isRest).length * increment)); dailyValues.push({ value: val, isRest: false }); } } } else { let currentVal = startVal; for (let i = 0; i < 30; i++) { if ((i + 1) % 5 === 0) dailyValues.push({ isRest: true }); else { currentVal += Math.floor(Math.random() * 3) + 1; dailyValues.push({ value: currentVal, isRest: false }); } } } challengeData.plan = dailyValues.map((d, i) => ({ ...d, day: i + 1, completed: false })); saveChallenge(); updateUI(); renderPlan(); updateProgress(); };
                    typeSelect.addEventListener('change', updateUI); generateBtn.addEventListener('click', handleGenerate); resetBtn.addEventListener('click', () => { challengeData = {}; localStorage.removeItem(STORAGE_KEY); updateUI(); celebrationContainer.style.display = 'none'; }); planContainer.addEventListener('change', e => { if (e.target.type === 'checkbox') { const dayNum = parseInt(e.target.dataset.day), dayData = challengeData.plan.find(d => d.day === dayNum); if (dayData) { dayData.completed = e.target.checked; e.target.closest('.challenge-day-item').style.background = dayData.completed ? '#274746' : 'var(--button-bg)'; e.target.previousElementSibling.style.textDecoration = dayData.completed ? 'line-through' : 'none'; saveChallenge(); updateProgress(); } } });
                    if (loadChallenge()) { renderPlan(); updateProgress(); } updateUI();
                }
            },
            'macro-planner': {
                title: 'Macro Nutrient Split Planner',
                icon: '🥗',
                getContent: () => `
                    <div class="tool-container">
                        <div><label for="macro-calories">Total Daily Calories:</label><input type="number" id="macro-calories" placeholder="e.g., 2000" value="2000"/></div>
                        <div style="margin-top: 1.5rem;"><label for="protein-slider">Protein: <span id="protein-percent-label">40</span>%</label><input type="range" id="protein-slider" min="0" max="100" value="40" style="width: 100%;"/></div>
                        <div><label for="carbs-slider">Carbohydrates: <span id="carbs-percent-label">40</span>%</label><input type="range" id="carbs-slider" min="0" max="100" value="40" style="width: 100%;"/></div>
                        <div style="margin-top: 1rem;"><p style="font-weight: bold; font-size: 1.1em;">Fat: <span id="fat-percent-label">20</span>% (auto-calculated)</p></div>
                        <div id="macro-output-area" style="display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 2rem; align-items: center; margin-top: 1.5rem; padding: 1rem; border: 1px solid var(--border-color); border-radius: 8px; background-color: var(--dark-bg);"><div id="macro-results-text" style="font-size: 1.2rem; line-height: 1.8;"></div><div style="position: relative; min-height: 250px;"><canvas id="macro-pie-chart"></canvas></div></div>
                         <button id="macro-download-btn" class="glow-button" style="margin-top: 1.5rem;">Download Chart</button>
                    </div>`,
                init: () => {
                    const caloriesInput = document.getElementById('macro-calories'), proteinSlider = document.getElementById('protein-slider'), carbsSlider = document.getElementById('carbs-slider'), proteinLabel = document.getElementById('protein-percent-label'), carbsLabel = document.getElementById('carbs-percent-label'), fatLabel = document.getElementById('fat-percent-label'), resultsText = document.getElementById('macro-results-text'), downloadBtn = document.getElementById('macro-download-btn'), ctx = document.getElementById('macro-pie-chart').getContext('2d');
                    let macroChart;
                    const calculateAndDisplay = () => {
                        const totalCalories = parseFloat(caloriesInput.value) || 0;
                        let proteinPercent = parseInt(proteinSlider.value), carbsPercent = parseInt(carbsSlider.value), fatPercent = 100 - proteinPercent - carbsPercent;
                        proteinLabel.textContent = proteinPercent; carbsLabel.textContent = carbsPercent; fatLabel.textContent = fatPercent < 0 ? 0 : fatPercent;
                        const proteinGrams = ((totalCalories * proteinPercent) / 100) / 4, carbsGrams = ((totalCalories * carbsPercent) / 100) / 4, fatGrams = ((totalCalories * (fatPercent < 0 ? 0 : fatPercent)) / 100) / 9;
                        resultsText.innerHTML = `<p style="color: #ff6b6b;"><strong>Protein:</strong> ${proteinGrams.toFixed(1)} g</p><p style="color: #feca57;"><strong>Carbs:</strong> ${carbsGrams.toFixed(1)} g</p><p style="color: #54a0ff;"><strong>Fat:</strong> ${fatGrams.toFixed(1)} g</p>`;
                        const chartData = { labels: ['Protein', 'Carbs', 'Fat'], datasets: [{ label: 'Macro Split %', data: [proteinPercent, carbsPercent, fatPercent < 0 ? 0 : fatPercent], backgroundColor: ['#ff6b6b', '#feca57', '#54a0ff'], borderColor: 'var(--card-bg)', borderWidth: 3 }] };
                        if (macroChart) { macroChart.data.datasets[0].data = chartData.datasets[0].data; macroChart.update(); } else { macroChart = new Chart(ctx, { type: 'pie', data: chartData, options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'top', labels: { color: 'var(--text-primary)' } }, tooltip: { callbacks: { label: (c) => `${c.label || ''}: ${c.parsed || 0}%` } } } } }); }
                    };
                    const handleSlider = (slider1, slider2) => () => { const v1 = parseInt(slider1.value), v2 = parseInt(slider2.value); if (v1 + v2 > 100) slider2.value = 100 - v1; calculateAndDisplay(); };
                    proteinSlider.addEventListener('input', handleSlider(proteinSlider, carbsSlider)); carbsSlider.addEventListener('input', handleSlider(carbsSlider, proteinSlider)); caloriesInput.addEventListener('input', calculateAndDisplay);
                    downloadBtn.addEventListener('click', () => { const link = document.createElement('a'); link.href = macroChart.toBase64Image(); link.download = `macro-split-${caloriesInput.value || 0}kcal.png`; link.click(); });
                    calculateAndDisplay();
                    modal.addEventListener('modal:close', () => { if (macroChart) { macroChart.destroy(); macroChart = null; } }, { once: true });
                }
            },
'sleep-tracker': {
    title: 'Sleep Quality Tracker',
    icon: '😴',
    getContent: () => `
        <div class="tool-container">
            <div>
                <label for="sleep-date">Date:</label>
                <input type="date" id="sleep-date"/>
            </div>
            <div style="margin-top:1rem;">
                <label for="sleep-hours">Hours Slept:</label>
                <input type="number" id="sleep-hours" placeholder="e.g. 7.5" step="0.1" min="0" max="24"/>
            </div>
            <button id="log-sleep-btn" class="glow-button" style="margin-top:1rem;">Log Sleep</button>

            <h3 style="margin-top:2rem;">📊 Sleep Log</h3>
            <table id="sleep-log-table" style="width:100%; border-collapse:collapse; margin-top:1rem;">
                <thead>
                    <tr>
                        <th style="padding:6px; border-bottom:1px solid var(--border-color);">Date</th>
                        <th style="padding:6px; border-bottom:1px solid var(--border-color);">Hours</th>
                        <th style="padding:6px; border-bottom:1px solid var(--border-color);">Quality</th>
                    </tr>
                </thead>
                <tbody></tbody>
            </table>

            <div id="sleep-insights" style="margin-top:1.5rem; font-weight:bold;"></div>

            <div style="margin-top:2rem; position:relative; min-height:250px;">
                <canvas id="sleep-chart"></canvas>
            </div>

            <button id="reset-sleep-btn" class="glow-button" style="margin-top:1.5rem; background:#e74c3c;">Reset Data</button>
        </div>
    `,
    init: () => {
        const dateInput = document.getElementById('sleep-date'),
              hoursInput = document.getElementById('sleep-hours'),
              logBtn = document.getElementById('log-sleep-btn'),
              resetBtn = document.getElementById('reset-sleep-btn'),
              tbody = document.querySelector('#sleep-log-table tbody'),
              insights = document.getElementById('sleep-insights'),
              ctx = document.getElementById('sleep-chart').getContext('2d');

        let sleepData = JSON.parse(localStorage.getItem('sleepData')) || [];
        let sleepChart;

        const getQuality = (h) => {
            if (h >= 7 && h <= 9) return "✅ Good";
            if (h >= 6 && h < 7) return "⚠️ Average";
            if (h > 9) return "🌙 Overslept";
            return "😴 Poor";
        };

        const renderTable = () => {
            tbody.innerHTML = "";
            sleepData.forEach(e => {
                tbody.innerHTML += `
                    <tr>
                        <td style="padding:6px; border-bottom:1px solid var(--border-color);">${e.date}</td>
                        <td style="padding:6px; border-bottom:1px solid var(--border-color);">${e.hours}</td>
                        <td style="padding:6px; border-bottom:1px solid var(--border-color);">${e.quality}</td>
                    </tr>`;
            });
        };

        const renderInsights = () => {
            if (!sleepData.length) {
                insights.textContent = "";
                return;
            }
            const avg = (sleepData.reduce((s, e) => s + e.hours, 0) / sleepData.length).toFixed(1);
            let advice = "";
            if (avg >= 7 && avg <= 9) advice = "✅ Great! Your sleep is healthy.";
            else if (avg < 6) advice = "⚠️ Not enough sleep. Try to rest more.";
            else if (avg > 9) advice = "🌙 You might be oversleeping.";
            else advice = "🙂 Could improve a bit.";

            insights.textContent = `Average Sleep: ${avg} hrs. ${advice}`;
        };

        const renderChart = () => {
            if (sleepChart) sleepChart.destroy();
            sleepChart = new Chart(ctx, {
                type: 'bar',
                data: {
                    labels: sleepData.map(e => e.date),
                    datasets: [{
                        label: 'Hours Slept',
                        data: sleepData.map(e => e.hours),
                        backgroundColor: '#54a0ff',
                        borderColor: '#2980b9',
                        borderWidth: 2
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                        y: { beginAtZero: true, max: 12, ticks: { color: 'var(--text-primary)' } },
                        x: { ticks: { color: 'var(--text-primary)' } }
                    },
                    plugins: {
                        legend: { labels: { color: 'var(--text-primary)' } }
                    }
                }
            });
        };

        const updateAll = () => {
            renderTable();
            renderInsights();
            renderChart();
            localStorage.setItem('sleepData', JSON.stringify(sleepData));
        };

        logBtn.addEventListener('click', () => {
            const d = dateInput.value, h = parseFloat(hoursInput.value);
            if (!d || isNaN(h)) { alert("Enter valid date and hours!"); return; }
            sleepData.push({ date: d, hours: h, quality: getQuality(h) });
            updateAll();
        });

        resetBtn.addEventListener('click', () => {
            if (confirm("Clear all sleep data?")) {
                sleepData = [];
                updateAll();
            }
        });

        updateAll();

        modal.addEventListener('modal:close', () => { if (sleepChart) { sleepChart.destroy(); sleepChart = null; } }, { once: true });
    }
},
     'stress-test': {
    title: 'Stress Level Test (Self-assessment)',
    icon: '🧠',
    getContent: () => `
        <div class="tool-container">
            <h3>🧠 Stress Level Questionnaire</h3>
            <p>Rate each statement from <strong>1 (Never)</strong> to <strong>5 (Always)</strong>.</p>

            <form id="stress-form" style="margin-top:1rem;">
                <div class="question">
                    <label>1. I feel overwhelmed by daily tasks.</label><br/>
                    <input type="number" min="1" max="5" required name="q1"/>
                </div>
                <div class="question">
                    <label>2. I often have trouble sleeping due to worries.</label><br/>
                    <input type="number" min="1" max="5" required name="q2"/>
                </div>
                <div class="question">
                    <label>3. I feel easily irritated or frustrated.</label><br/>
                    <input type="number" min="1" max="5" required name="q3"/>
                </div>
                <div class="question">
                    <label>4. I find it hard to relax and unwind.</label><br/>
                    <input type="number" min="1" max="5" required name="q4"/>
                </div>
                <div class="question">
                    <label>5. I experience frequent headaches or muscle tension.</label><br/>
                    <input type="number" min="1" max="5" required name="q5"/>
                </div>
                <button type="submit" class="glow-button" style="margin-top:1rem;">Calculate Stress Level</button>
            </form>

            <div id="stress-result" style="margin-top:2rem; font-weight:bold;"></div>

            <div style="margin-top:2rem; position:relative; min-height:250px;">
                <canvas id="stress-chart"></canvas>
            </div>
        </div>
    `,
    init: () => {
        const form = document.getElementById('stress-form');
        const resultBox = document.getElementById('stress-result');
        const ctx = document.getElementById('stress-chart').getContext('2d');
        let stressChart;

        form.addEventListener('submit', (e) => {
            e.preventDefault();

            const formData = new FormData(form);
            const scores = [...formData.values()].map(v => parseInt(v));
            const total = scores.reduce((a, b) => a + b, 0);
            const avg = (total / scores.length).toFixed(1);

            let level = "";
            let advice = "";
            if (avg <= 2) {
                level = "🟢 Low Stress";
                advice = "Keep up your healthy habits! Maintain balance.";
            } else if (avg > 2 && avg <= 3.5) {
                level = "🟡 Moderate Stress";
                advice = "Consider relaxation techniques like meditation, walks, or journaling.";
            } else {
                level = "🔴 High Stress";
                advice = "Important: Take breaks, talk to friends/family, or seek professional help if needed.";
            }

            resultBox.innerHTML = `Your Stress Score: <strong>${avg}/5</strong> <br/> Level: <strong>${level}</strong><br/>💡 ${advice}`;

            // Render Chart
            if (stressChart) stressChart.destroy();
            stressChart = new Chart(ctx, {
                type: 'radar',
                data: {
                    labels: [
                        "Overwhelm",
                        "Sleep Issues",
                        "Irritability",
                        "Relaxation Difficulty",
                        "Physical Symptoms"
                    ],
                    datasets: [{
                        label: 'Stress Profile',
                        data: scores,
                        backgroundColor: 'rgba(231, 76, 60, 0.3)',
                        borderColor: '#e74c3c',
                        borderWidth: 2,
                        pointBackgroundColor: '#e74c3c'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                        r: {
                            min: 0,
                            max: 5,
                            ticks: { stepSize: 1, color: 'var(--text-primary)' },
                            pointLabels: { color: 'var(--text-primary)' }
                        }
                    },
                    plugins: {
                        legend: { labels: { color: 'var(--text-primary)' } }
                    }
                }
            });
        });

        modal.addEventListener('modal:close', () => {
            if (stressChart) { stressChart.destroy(); stressChart = null; }
        }, { once: true });
    }
},


            'image-compressor': { title: 'Image Compressor', icon: '🖼️', getContent: () => `<div class="tool-container"><label for="compress-upload">Upload Image:</label><input type="file" id="compress-upload" accept="image/*"/><label for="compress-quality">Quality (<span id="quality-val">0.7</span>):</label><input type="range" id="compress-quality" min="0.1" max="1.0" step="0.05" value="0.7"/><div id="tool-output"></div><canvas id="compress-canvas" style="display:none;"></canvas></div>`, init: () => { const uploader = document.getElementById('compress-upload'), slider = document.getElementById('compress-quality'), output = document.getElementById('tool-output'), canvas = document.getElementById('compress-canvas'), ctx = canvas.getContext('2d'), val = document.getElementById('quality-val'); let file = null, img = new Image(); const compress = () => { if (!file) return; const quality = parseFloat(slider.value); val.textContent = quality.toFixed(2); canvas.width = img.width; canvas.height = img.height; ctx.drawImage(img, 0, 0); const url = canvas.toDataURL(file.type, quality); const originalSize = (file.size / 1024).toFixed(2); const newSize = (url.length * 0.75 / 1024).toFixed(2); output.innerHTML = `<p>Original Size: ${originalSize} KB</p><p>New Size: ~${newSize} KB</p><img src="${url}" style="max-width:100%; margin-top:10px; border:1px solid var(--border-color);"/><a href="${url}" download="compressed-${file.name}" class="glow-button" style="display:block; margin-top:10px; text-align:center;">Download Compressed Image</a>`; }; img.onload = compress; uploader.addEventListener('change', e => { file = e.target.files[0]; if (file) { const reader = new FileReader(); reader.onload = ev => { img.src = ev.target.result; }; reader.readAsDataURL(file); } }); slider.addEventListener('input', () => val.textContent = parseFloat(slider.value).toFixed(2)); slider.addEventListener('change', compress); }},
            'image-resizer': { title: 'Social Media Resizer', icon: '📏', getContent: () => `<div class="tool-container"><label for="resize-upload">1. Upload Image:</label><input type="file" id="resize-upload" accept="image/*"/><label for="resize-preset">2. Select a Preset:</label><select id="resize-preset"><option value="custom">Custom</option><option value="1080x1080">Instagram Post (1080x1080)</option><option value="1080x1350">Instagram Portrait (1080x1350)</option><option value="1200x628">Facebook Post (1200x628)</option><option value="1280x720">YouTube Thumbnail (1280x720)</option></select><div id="custom-dims" style="display:flex; gap:10px;"><input type="number" id="resize-width" placeholder="Width"/><input type="number" id="resize-height" placeholder="Height"/></div><button id="resize-btn" class="glow-button">Resize &amp; Download</button><div id="tool-output"></div><canvas id="resize-canvas" style="display:none;"></canvas></div>`, init: () => { const uploader = document.getElementById('resize-upload'), preset = document.getElementById('resize-preset'), custom = document.getElementById('custom-dims'), wIn = document.getElementById('resize-width'), hIn = document.getElementById('resize-height'), btn = document.getElementById('resize-btn'), canvas = document.getElementById('resize-canvas'), ctx = canvas.getContext('2d'), output = document.getElementById('tool-output'); let img = null; uploader.addEventListener('change', e => { if(e.target.files[0]) {const r = new FileReader(); r.onload = ev => { img = new Image(); img.src = ev.target.result; output.innerHTML=`<p style="color: var(--accent-color);">Image loaded. Ready to resize.</p>` }; r.readAsDataURL(e.target.files[0]);} }); preset.addEventListener('change', () => { custom.style.display = preset.value === 'custom' ? 'flex' : 'none'; if(preset.value !== 'custom') { const [w, h] = preset.value.split('x'); wIn.value = w; hIn.value = h; } }); btn.addEventListener('click', () => { if (!img) { output.innerHTML=`<p style="color:red;">Please upload an image first.</p>`; return; } const nW = parseInt(wIn.value), nH = parseInt(hIn.value); if (!nW || !nH) { output.innerHTML=`<p style="color:red;">Please set valid dimensions.</p>`; return; } canvas.width = nW; canvas.height = nH; const iRatio = img.width / img.height, cRatio = nW / nH; let sx, sy, sW, sH; if (iRatio > cRatio) { sH = img.height; sW = sH * cRatio; sx = (img.width - sW) / 2; sy = 0; } else { sW = img.width; sH = sW / cRatio; sy = (img.height - sH) / 2; sx = 0; } ctx.drawImage(img, sx, sy, sW, sH, 0, 0, nW, nH); const link = document.createElement('a'); link.href = canvas.toDataURL('image/png'); link.download = 'resized-image.png'; link.click(); output.innerHTML=`<p>Download should have started!</p>`; }); }},
            'meta-tag-generator': { title: 'Meta Tag Generator', icon: '📝', getContent: () => `<div class="tool-container"><div><label for="meta-title">Title (Max 60 chars):</label><input type="text" id="meta-title" placeholder="Your Page Title"/></div><div><label for="meta-desc">Description (Max 160 chars):</label><textarea id="meta-desc" rows="3" placeholder="A compelling description of your page."></textarea></div><div><label for="meta-keys">Keywords (Comma-separated):</label><input type="text" id="meta-keys" placeholder="keyword1, keyword2"/></div><div><label for="meta-author">Author:</label><input type="text" id="meta-author" placeholder="Your Name or Company"/></div><button id="meta-generate-btn" class="glow-button">Generate Tags</button><div id="tool-output-container" style="display:none; margin-top:1rem;"><label>Generated Meta Tags:</label><textarea id="tool-output" rows="8" readonly="" style="white-space:pre;"></textarea><button id="meta-copy-btn" class="glow-button" style="margin-top:0.5rem;">Copy to Clipboard</button></div></div>`, init: () => { const generateBtn = document.getElementById('meta-generate-btn'), copyBtn = document.getElementById('meta-copy-btn'), outputContainer = document.getElementById('tool-output-container'), outputEl = document.getElementById('tool-output'); generateBtn.addEventListener('click', () => { const title = document.getElementById('meta-title').value.trim(), desc = document.getElementById('meta-desc').value.trim(), keys = document.getElementById('meta-keys').value.trim(), author = document.getElementById('meta-author').value.trim(); let tags = `<title>${title}</title>\n<meta name="description" content="${desc}">\n`; if (keys) tags += `<meta name="keywords" content="${keys}">\n`; if (author) tags += `<meta name="author" content="${author}">\n`; tags += `<meta name="robots" content="index, follow">`; outputEl.value = tags; outputContainer.style.display = 'block'; }); copyBtn.addEventListener('click', () => { navigator.clipboard.writeText(outputEl.value).then(() => { copyBtn.textContent = 'Copied!'; setTimeout(() => { copyBtn.textContent = 'Copy to Clipboard'; }, 2000); }); }); }},
            'favicon-generator': { 
                title: 'Advanced Favicon Generator',
                icon: '✨', 
                getContent: () => `
                    <style>
                        .favicon-preview-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1.5rem; margin-top: 1rem; text-align: center; }
                        .preview-box { background-color: var(--dark-bg); padding: 1.5rem 1rem; border-radius: 8px; border: 1px solid var(--border-color); }
                        .preview-box h4 { margin-bottom: 1rem; color: var(--text-secondary); font-size: 0.9em; }
                        .browser-tab-preview { background: var(--button-bg); padding: 8px; border-radius: 6px; display: flex; align-items: center; }
                        #preview-browser-icon { width: 16px; height: 16px; margin-right: 8px; background-size: contain; image-rendering: pixelated; }
                        .ios-preview, .android-preview { display: flex; flex-direction: column; align-items: center; gap: 5px; }
                        #preview-apple-icon, #preview-android-icon { width: 60px; height: 60px; background-size: cover; border-radius: 12px; }
                    </style>
                    <div class="tool-container">
                        <label for="favicon-upload" class="glow-button">1. Upload Your Image (PNG, JPG)</label>
                        <input type="file" id="favicon-upload" accept="image/png, image/jpeg" style="display:none;"/>

                        <div class="favicon-preview-grid">
                            <div class="preview-box"><h4>Browser Tab</h4><div class="browser-tab-preview"><div id="preview-browser-icon"></div><span>Your Site Title</span></div></div>
                            <div class="preview-box"><h4>iOS Home Screen</h4><div class="ios-preview"><div id="preview-apple-icon"></div><span>Your App</span></div></div>
                            <div class="preview-box"><h4>Android Home Screen</h4><div class="android-preview"><div id="preview-android-icon"></div><span>Your App</span></div></div>
                        </div>

                        <button id="favicon-generate-btn" class="glow-button cta-button" disabled="" style="margin-top: 1.5rem;">2. Generate &amp; Download Package (.zip)</button>

                        <div id="tool-output" style="display:none; white-space: pre; background-color: var(--dark-bg); font-family: monospace;"></div>
                        <button id="favicon-copy-html-btn" class="glow-button" style="display:none; margin-top: 0.5rem;">Copy HTML to Clipboard</button>
                    </div>`, 
                init: () => {
                    const uploader = document.getElementById('favicon-upload');
                    const generateBtn = document.getElementById('favicon-generate-btn');
                    const outputEl = document.getElementById('tool-output');
                    const copyBtn = document.getElementById('favicon-copy-html-btn');
                    const browserPreview = document.getElementById('preview-browser-icon');
                    const applePreview = document.getElementById('preview-apple-icon');
                    const androidPreview = document.getElementById('preview-android-icon');

                    let sourceImage = null;

                    uploader.addEventListener('change', e => {
                        if (e.target.files && e.target.files[0]) {
                            const reader = new FileReader();
                            reader.onload = ev => {
                                sourceImage = new Image();
                                sourceImage.onload = () => {
                                    browserPreview.style.backgroundImage = `url(${ev.target.result})`;
                                    applePreview.style.backgroundImage = `url(${ev.target.result})`;
                                    androidPreview.style.backgroundImage = `url(${ev.target.result})`;
                                    generateBtn.disabled = false;
                                    outputEl.style.display = 'none';
                                    copyBtn.style.display = 'none';
                                };
                                sourceImage.src = ev.target.result;
                            };
                            reader.readAsDataURL(e.target.files[0]);
                        }
                    });

                    const resizeImage = (img, size) => {
                        return new Promise(resolve => {
                            const canvas = document.createElement('canvas');
                            canvas.width = size;
                            canvas.height = size;
                            const ctx = canvas.getContext('2d');
                            ctx.drawImage(img, 0, 0, size, size);
                            canvas.toBlob(blob => resolve(blob), 'image/png');
                        });
                    };

                    generateBtn.addEventListener('click', async () => {
                        if (!sourceImage) return;

                        generateBtn.disabled = true;
                        generateBtn.textContent = 'Generating...';

                        const zip = new JSZip();
                        const sizes = [
                            { name: 'favicon-16x16.png', size: 16 },
                            { name: 'favicon-32x32.png', size: 32 },
                            { name: 'apple-touch-icon.png', size: 180 },
                            { name: 'android-chrome-192x192.png', size: 192 },
                            { name: 'android-chrome-512x512.png', size: 512 }
                        ];

                        const resizePromises = sizes.map(item => resizeImage(sourceImage, item.size).then(blob => zip.file(item.name, blob)));

                        const manifest = {
                            name: "Your App Name",
                            short_name: "App",
                            icons: [
                                { src: "/android-chrome-192x192.png", sizes: "192x192", type: "image/png" },
                                { src: "/android-chrome-512x512.png", sizes: "512x512", type: "image/png" }
                            ],
                            theme_color: "#ffffff",
                            background_color: "#ffffff",
                            display: "standalone"
                        };
                        zip.file("site.webmanifest", JSON.stringify(manifest, null, 2));

                        // Generate a basic ICO file from the 32x32 png
                        const icoBlob = await resizeImage(sourceImage, 32);
                        zip.file('favicon.ico', icoBlob);

                        await Promise.all(resizePromises);

                        zip.generateAsync({ type: "blob" }).then(content => {
                            const link = document.createElement('a');
                            link.href = URL.createObjectURL(content);
                            link.download = "favicon_package.zip";
                            document.body.appendChild(link);
                            link.click();
                            document.body.removeChild(link);
                        });

                        const htmlCode = 
`<link rel="apple-touch-icon" sizes="180x180" href="/apple-touch-icon.png"/>
<link rel="icon" type="image/png" sizes="32x32" href="/favicon-32x32.png"/>
<link rel="icon" type="image/png" sizes="16x16" href="/favicon-16x16.png"/>
<link rel="manifest" href="/site.webmanifest"/>`;

                        outputEl.textContent = `3. Upload the contents of the ZIP to your website's root directory, then paste this code into the <head> of your HTML:\n\n${htmlCode}`;
                        outputEl.style.display = 'block';
                        copyBtn.style.display = 'block';

                        generateBtn.disabled = false;
                        generateBtn.textContent = 'Generate & Download Package (.zip)';
                    });

                    copyBtn.addEventListener('click', () => {
                        navigator.clipboard.writeText(outputEl.textContent.split('\n\n')[1]).then(() => {
                            copyBtn.textContent = 'Copied!';
                            setTimeout(() => copyBtn.textContent = 'Copy HTML to Clipboard', 2000);
                        });
                    });
                }
            },
            'image-to-base64': { title: 'Image to Base64', icon: '🔗', getContent: () => `<div class="tool-container"><label for="base64-upload" class="glow-button">Upload Image</label><input type="file" id="base64-upload" accept="image/*" style="display:none;"/><label style="margin-top:1rem;">Base64 String:</label><textarea id="base64-output" rows="8" placeholder="Base64 data will appear here..." readonly=""></textarea><button id="base64-copy-btn" class="glow-button" style="display:none; margin-top:0.5rem;">Copy String</button></div>`, init: () => { const uploader = document.getElementById('base64-upload'), outputEl = document.getElementById('base64-output'), copyBtn = document.getElementById('base64-copy-btn'); uploader.addEventListener('change', e => { if(e.target.files && e.target.files[0]){ const reader = new FileReader(); reader.onload = ev => { outputEl.value = ev.target.result; copyBtn.style.display = 'block'; }; reader.readAsDataURL(e.target.files[0]); } }); copyBtn.addEventListener('click', () => { navigator.clipboard.writeText(outputEl.value).then(() => { copyBtn.textContent = 'Copied!'; setTimeout(() => { copyBtn.textContent = 'Copy String'; }, 2000); }); }); }},
            'image-to-text': { title: 'Image to Text (OCR)', icon: '📄', getContent: () => `<div class="tool-container"><div><label for="ocr-image-upload" class="glow-button">1. Upload Image</label><input type="file" id="ocr-image-upload" accept="image/*" style="display:none"/></div><div><label for="ocr-language">2. Select Language:</label><select id="ocr-language"><option value="eng" selected="selected">English</option><option value="spa">Spanish</option><option value="fra">French</option><option value="deu">German</option><option value="chi_sim">Chinese</option><option value="jpn">Japanese</option></select></div><button id="ocr-extract-btn" class="glow-button cta-button" disabled="">3. Extract Text</button><div id="ocr-status" style="margin-top: 1rem; color: var(--text-secondary);">Status: Please upload an image.</div><div><label for="ocr-output">Extracted Text:</label><textarea id="ocr-output" rows="10" placeholder="Text will appear here..." readonly=""></textarea></div></div>`, init: () => { const uploadEl = document.getElementById('ocr-image-upload'), langEl = document.getElementById('ocr-language'), extractBtn = document.getElementById('ocr-extract-btn'), statusEl = document.getElementById('ocr-status'), outputEl = document.getElementById('ocr-output'); let uploadedFile = null; uploadEl.addEventListener('change', (e) => { if(e.target.files && e.target.files[0]){ uploadedFile = e.target.files[0]; statusEl.textContent = `Status: Ready to process "${uploadedFile.name}".`; statusEl.style.color = 'var(--accent-color)'; extractBtn.disabled = false; } }); extractBtn.addEventListener('click', () => { if (!uploadedFile) { return; } extractBtn.disabled = true; outputEl.value = ''; statusEl.style.color = 'var(--text-secondary)'; Tesseract.recognize(uploadedFile, langEl.value, { logger: m => { statusEl.textContent = `${m.status}... (${(m.progress * 100).toFixed(0)}%)`; }}) .then(({ data: { text } }) => { outputEl.value = text; statusEl.textContent = 'Extraction complete!'; statusEl.style.color = 'var(--accent-color)'; }) .catch(err => { console.error(err); statusEl.textContent = 'Error: Could not extract text.'; statusEl.style.color = 'red'; }) .finally(() => { extractBtn.disabled = false; }); }); }},
            'text-to-speech': { title: 'Text to Speech', icon: '🔊', getContent: () => `<div class="tool-container"><textarea id="tts-text" rows="8" placeholder="Type or paste text here..."></textarea><div style="display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-block: 1rem;"><div><label for="tts-voice">Voice (for preview):</label><select id="tts-voice" style="width: 100%;"></select></div><div><label for="tts-rate">Speed: <span id="tts-rate-label">1</span></label><input type="range" id="tts-rate" min="0.5" max="2" step="0.1" value="1"></div><div style="grid-column: 1 / -1;"><label for="tts-pitch">Pitch: <span id="tts-pitch-label">1</span></label><input type="range" id="tts-pitch" min="0" max="2" step="0.1" value="1"></div></div><div id="tts-status" style="color: var(--text-secondary); min-height: 1.2em;">Status: Ready.</div><div style="display: flex; flex-wrap: wrap; gap: 10px; margin-top: 1rem;"><button id="tts-speak" class="glow-button">Speak</button><button id="tts-pause-resume" class="glow-button">Pause</button><button id="tts-stop" class="glow-button">Stop</button><button id="tts-download" class="glow-button cta-button">Download MP3</button></div></div>`, init: () => { const synth = window.speechSynthesis, textEl = document.getElementById('tts-text'), voiceSel = document.getElementById('tts-voice'), rateEl = document.getElementById('tts-rate'), pitchEl = document.getElementById('tts-pitch'), rateLabel = document.getElementById('tts-rate-label'), pitchLabel = document.getElementById('tts-pitch-label'), speakBtn = document.getElementById('tts-speak'), pauseResumeBtn = document.getElementById('tts-pause-resume'), stopBtn = document.getElementById('tts-stop'), downloadBtn = document.getElementById('tts-download'), statusEl = document.getElementById('tts-status'); let voices = []; let utterance = new SpeechSynthesisUtterance(); const updateUI = (state) => { const hasText = textEl.value.trim().length > 0; speakBtn.disabled = !hasText || state === 'speaking'; downloadBtn.disabled = !hasText; if (state === 'speaking') { statusEl.textContent = 'Status: Speaking...'; pauseResumeBtn.disabled = false; stopBtn.disabled = false; pauseResumeBtn.textContent = 'Pause'; } else if (state === 'paused') { statusEl.textContent = 'Status: Paused.'; pauseResumeBtn.textContent = 'Resume'; } else { statusEl.textContent = 'Status: Ready.'; pauseResumeBtn.disabled = true; stopBtn.disabled = true; pauseResumeBtn.textContent = 'Pause'; }}; const loadVoices = () => { voices = synth.getVoices(); voiceSel.innerHTML = voices.map(v => `<option value="${v.name}">${v.name} (${v.lang})</option>`).join(''); voiceSel.value = (voices.find(v=>v.default) || voices[0])?.name; }; const speak = () => { if (synth.speaking) synth.cancel(); utterance.text = textEl.value; utterance.voice = voices.find(v => v.name === voiceSel.value); utterance.pitch = pitchEl.value; utterance.rate = rateEl.value; synth.speak(utterance); }; loadVoices(); if (synth.onvoiceschanged !== undefined) synth.onvoiceschanged = loadVoices; utterance.onstart = () => updateUI('speaking'); utterance.onpause = () => updateUI('paused'); utterance.onresume = () => updateUI('speaking'); utterance.onend = () => updateUI('idle'); textEl.addEventListener('input', () => { if(!synth.speaking && !synth.paused) updateUI('idle'); }); rateEl.addEventListener('input', () => rateLabel.textContent = rateEl.value); pitchEl.addEventListener('input', () => pitchLabel.textContent = pitchEl.value); speakBtn.addEventListener('click', speak); pauseResumeBtn.addEventListener('click', () => { synth.paused ? synth.resume() : synth.pause(); }); stopBtn.addEventListener('click', () => synth.cancel()); downloadBtn.addEventListener('click', () => { const text = textEl.value.trim(); if (!text) return; const lang = (voices.find(v => v.name === voiceSel.value) || {lang:'en-US'}).lang; const url = `https://translate.google.com/translate_tts?ie=UTF-8&q=${encodeURIComponent(text)}&tl=${lang}&client=tw-ob`; const a = document.createElement('a'); a.href = url; a.download = 'speech.mp3'; a.click(); }); modal.addEventListener('modal:close', () => synth.cancel(), { once: true }); updateUI('idle'); }},
          'audio-transcriber': {
    title: '🎙️ Audio to Text (Transcription Lite)',
    icon: '🎙️',
    getContent: () => `
        <div class="tool-container">
            <h3 style="margin-bottom:1rem;">Live Transcription</h3>
            <button id="start-rec" class="glow-button">🎤 Start Recording</button>
            <button id="stop-rec" class="glow-button" style="background:#e74c3c; margin-left:0.5rem;">⏹ Stop</button>

            <div id="transcript-box" style="margin-top:1rem; padding:1rem; min-height:150px; border:1px solid var(--border-color); border-radius:8px; background:var(--card-bg); overflow-y:auto;"></div>

            <div style="margin-top:1.5rem;">
                <button id="clear-transcript" class="glow-button" style="background:#f39c12;">🧹 Clear</button>
                <button id="download-txt" class="glow-button">⬇️ Export .txt</button>
            </div>
        </div>
    `,
    init: () => {
        const startBtn = document.getElementById('start-rec');
        const stopBtn = document.getElementById('stop-rec');
        const clearBtn = document.getElementById('clear-transcript');
        const downloadBtn = document.getElementById('download-txt');
        const transcriptBox = document.getElementById('transcript-box');

        let recognition;
        let finalTranscript = "";

        if ('webkitSpeechRecognition' in window) {
            recognition = new webkitSpeechRecognition();
            recognition.continuous = true;
            recognition.interimResults = true;
            recognition.lang = "en-US";

            recognition.onresult = (event) => {
                let interim = "";
                for (let i = event.resultIndex; i < event.results.length; ++i) {
                    if (event.results[i].isFinal) {
                        finalTranscript += event.results[i][0].transcript + " ";
                    } else {
                        interim += event.results[i][0].transcript;
                    }
                }
                transcriptBox.innerHTML = `<p>${finalTranscript}</p><i style="opacity:0.6;">${interim}</i>`;
                transcriptBox.scrollTop = transcriptBox.scrollHeight;
            };
        } else {
            transcriptBox.innerHTML = "<p style='color:#e74c3c;'>⚠️ Speech recognition not supported in this browser.</p>";
        }

        startBtn.addEventListener('click', () => {
            if (recognition) recognition.start();
        });

        stopBtn.addEventListener('click', () => {
            if (recognition) recognition.stop();
        });

        clearBtn.addEventListener('click', () => {
            finalTranscript = "";
            transcriptBox.innerHTML = "";
        });

        downloadBtn.addEventListener('click', () => {
            const blob = new Blob([finalTranscript], { type: "text/plain" });
            const link = document.createElement("a");
            link.href = URL.createObjectURL(blob);
            link.download = "transcript.txt";
            link.click();
        });

        // Clean up when modal closes
        modal.addEventListener('modal:close', () => {
            if (recognition) recognition.stop();
            finalTranscript = "";
            transcriptBox.innerHTML = "";
        }, { once: true });
    }
},

            'video-converter': { title: 'Video Player', icon: '🎬', getContent: () => `<div class="tool-container"><label for="video-upload" class="glow-button">Upload a video to play</label><input type="file" id="video-upload" accept="video/*" style="display:none;"><video id="video-player" controls style="width:100%; margin-top:1rem; border-radius:5px; display:none;"></video><div id="tool-output">Note: This is a player. True browser-based conversion is highly experimental and depends on file size and format.</div></div>`, init: () => { const uploader = document.getElementById('video-upload'), player = document.getElementById('video-player'); uploader.addEventListener('change', e => { const file = e.target.files[0]; if (file) { const url = URL.createObjectURL(file); player.src = url; player.style.display = 'block'; } }); }},
            'qr-generator': { title: 'QR Code Generator', icon: '📱', getContent: () => `<div class="tool-container"><label for="qr-text">Text or URL to encode:</label><input type="text" id="qr-text" placeholder="https://example.com"><div id="tool-output" style="text-align:center; padding:20px; min-height: 250px;"><p>Your QR Code will appear here.</p></div></div>`, init: () => { const input = document.getElementById('qr-text'), output = document.getElementById('tool-output'); const generate = () => { const text = input.value.trim(); if (text) { const url = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(text)}`; output.innerHTML = `<img src="${url}" alt="Generated QR Code" style="border:5px solid white; border-radius: 8px;"><br><a href="${url}" download="qrcode.png" class="glow-button" style="display:inline-block; margin-top:15px;">Download PNG</a>`; } else { output.innerHTML = '<p>Your QR Code will appear here.</p>'; } }; input.addEventListener('input', generate); }},
            'age-calculator': { title: 'Age Calculator', icon: '🎂', getContent: () => `<div class="tool-container"><label for="birthdate">Enter your Date of Birth:</label><input type="date" id="birthdate"><button id="age-calculate-btn" class="glow-button">Calculate Age</button><div id="tool-output"></div></div>`, init: () => { document.getElementById('age-calculate-btn').addEventListener('click', () => { const bday = document.getElementById('birthdate').value, output = document.getElementById('tool-output'); if (!bday) { output.textContent = 'Please select your date of birth.'; return; } const birthDate = new Date(bday), today = new Date(); let years = today.getFullYear() - birthDate.getFullYear(), months = today.getMonth() - birthDate.getMonth(), days = today.getDate() - birthDate.getDate(); if (days < 0) { months--; days += new Date(today.getFullYear(), today.getMonth(), 0).getDate(); } if (months < 0) { years--; months += 12; } output.innerHTML = `You are <strong>${years}</strong> years, <strong>${months}</strong> months, and <strong>${days}</strong> days old.`; }); }},
            'emi-calculator': { 
                title: 'Advanced EMI Calculator', 
                icon: '🏦', 
                getContent: () => `
                    <div class="tool-container">
                        <div>
                            <label for="emi-loan-type">Loan Type:</label>
                            <select id="emi-loan-type">
                                <option value="personal">Personal Loan</option>
                                <option value="home">Home Loan</option>
                                <option value="car">Car Loan</option>
                            </select>
                        </div>
                        <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1rem;">
                            <div><label for="emi-principal">Total Loan Amount:</label><input type="number" id="emi-principal" placeholder="e.g., 500000"></div>
                            <div><label for="emi-rate">Annual Interest Rate (%):</label><input type="number" id="emi-rate" placeholder="e.g., 10.5"></div>
                            <div><label for="emi-tenure">Loan Tenure (Years):</label><input type="number" id="emi-tenure" placeholder="e.g., 5"></div>
                            <div id="emi-down-payment-container" style="display:none;">
                                <label for="emi-down-payment">Down Payment:</label>
                                <input type="number" id="emi-down-payment" placeholder="e.g., 100000">
                            </div>
                        </div>
                        <button id="emi-calculate-btn" class="glow-button cta-button" style="margin-top:1rem;">Calculate EMI</button>
                        <div id="tool-output" style="margin-top:1.5rem; border: none; padding: 0;"></div>
                        <canvas id="emi-chart" style="margin-top: 1.5rem; max-height: 250px; display: none;"></canvas>
                    </div>
                `, 
                init: () => { 
                    const loanTypeSelect = document.getElementById('emi-loan-type');
                    const principalInput = document.getElementById('emi-principal');
                    const rateInput = document.getElementById('emi-rate');
                    const tenureInput = document.getElementById('emi-tenure');
                    const downPaymentContainer = document.getElementById('emi-down-payment-container');
                    const downPaymentInput = document.getElementById('emi-down-payment');
                    const calculateBtn = document.getElementById('emi-calculate-btn');
                    const outputDiv = document.getElementById('tool-output');
                    const chartCanvas = document.getElementById('emi-chart');
                    const ctx = chartCanvas.getContext('2d');
                    let emiChart = null;

                    const updateLoanTypeUI = () => {
                        const loanType = loanTypeSelect.value;
                        if (loanType === 'home' || loanType === 'car') {
                            downPaymentContainer.style.display = 'block';
                        } else {
                            downPaymentContainer.style.display = 'none';
                            downPaymentInput.value = '';
                        }
                        calculateEMI();
                    };

                    const calculateEMI = () => {
                        const totalAmount = parseFloat(principalInput.value) || 0;
                        const downPayment = parseFloat(downPaymentInput.value) || 0;
                        const annualRate = parseFloat(rateInput.value) || 0;
                        const tenureYears = parseFloat(tenureInput.value) || 0;

                        if (emiChart) {
                           emiChart.destroy();
                           emiChart = null;
                        }
                        chartCanvas.style.display = 'none';
                        outputDiv.innerHTML = '';

                        if (totalAmount <= 0 || annualRate <= 0 || tenureYears <= 0) {
                            return;
                        }

                        const P = totalAmount - downPayment;
                        if (P <= 0) {
                            outputDiv.innerHTML = '<p style="color:red; text-align:center;">Loan amount must be greater than down payment.</p>';
                            return;
                        }

                        const R = (annualRate / 12) / 100;
                        const N = tenureYears * 12;

                        const emi = (P * R * Math.pow(1 + R, N)) / (Math.pow(1 + R, N) - 1);
                        const totalPayment = emi * N;
                        const totalInterest = totalPayment - P;

                        if (!isFinite(emi)) return;

                        outputDiv.innerHTML = `
                            <div style="text-align:center;">
                                 <div style="font-size: 1.2rem; color: var(--text-secondary);">Monthly EMI</div>
                                 <div style="font-size: 3rem; font-weight: 700; color: var(--accent-color); margin-block: 0.5rem;">${emi.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</div>
                            </div>
                             <div style="margin-top: 1.5rem; display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; text-align: center;">
                                <div style="background: var(--button-bg); padding: 1rem; border-radius: 8px;">
                                    <div style="font-size: 1rem; color: var(--text-secondary);">Principal Amount</div>
                                    <div style="font-size: 1.5rem; font-weight: 600;">${P.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</div>
                                </div>
                                 <div style="background: var(--button-bg); padding: 1rem; border-radius: 8px;">
                                    <div style="font-size: 1rem; color: var(--text-secondary);">Total Interest</div>
                                    <div style="font-size: 1.5rem; font-weight: 600;">${totalInterest.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</div>
                                </div>
                            </div>
                             <p style="text-align:center; margin-top:1rem; color: var(--text-secondary);"><strong>Total Payment:</strong> ${totalPayment.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</p>
                        `;

                        chartCanvas.style.display = 'block';

                        emiChart = new Chart(ctx, {
                            type: 'pie',
                            data: {
                                labels: ['Principal Loan Amount', 'Total Interest Paid'],
                                datasets: [{ data: [P, totalInterest], backgroundColor: ['var(--accent-color)', '#30363d'], borderColor: 'var(--card-bg)', borderWidth: 4 }]
                            },
                            options: {
                                responsive: true,
                                plugins: {
                                    legend: { position: 'bottom', labels: { color: 'var(--text-primary)' } },
                                    tooltip: { callbacks: { label: (c) => `${c.label}: ${c.parsed.toLocaleString()}` } }
                                }
                            }
                        });
                    };

                    calculateBtn.addEventListener('click', calculateEMI);
                    loanTypeSelect.addEventListener('change', updateLoanTypeUI);
                    [principalInput, rateInput, tenureInput, downPaymentInput].forEach(el => el.addEventListener('input', calculateEMI));

                    modal.addEventListener('modal:close', () => { if (emiChart) emiChart.destroy(); }, { once: true });
                    updateLoanTypeUI();
                } 
            },
            'sip-calculator': { title: 'SIP Calculator', icon: '📈', getContent: () => `<div class="tool-container"><div><label for="sip-amount">Monthly Investment:</label><input type="number" id="sip-amount" placeholder="e.g., 5000"></div><div><label for="sip-rate">Expected Annual Return (%):</label><input type="number" id="sip-rate" placeholder="e.g., 12"></div><div><label for="sip-time">Period (Years):</label><input type="number" id="sip-time" placeholder="e.g., 10"></div><button id="sip-calculate-btn" class="glow-button">Calculate Returns</button><div id="tool-output"></div></div>`, init: () => { document.getElementById('sip-calculate-btn').addEventListener('click', () => { const P = parseFloat(document.getElementById('sip-amount').value), annualRate = parseFloat(document.getElementById('sip-rate').value), T = parseFloat(document.getElementById('sip-time').value), output = document.getElementById('tool-output'); if (P > 0 && annualRate > 0 && T > 0) { const i = (annualRate / 100) / 12, n = T * 12; const M = P * ((Math.pow(1 + i, n) - 1) / i) * (1 + i); const invested = P * n, gained = M - invested; output.innerHTML = `<p><strong>Invested Amount:</strong> ${invested.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</p><p><strong>Est. Returns:</strong> ${gained.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</p><p><strong>Total Value:</strong> ${M.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</p>`; } else { output.textContent = 'Please enter valid numbers.'; } }); }},
            'compound-interest-calculator': {
                title: 'Compound Interest Calculator',
                icon: '💹',
                getContent: () => `
                    <div class="tool-container">
                        <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.5rem;">
                            <div><label for="ci-principal">Initial Principal ($)</label><input type="number" id="ci-principal" value="1000"></div>
                            <div><label for="ci-contribution">Monthly Contribution ($)</label><input type="number" id="ci-contribution" value="100"></div>
                            <div><label for="ci-rate">Annual Interest Rate (%)</label><input type="number" id="ci-rate" value="7"></div>
                            <div><label for="ci-years">Years to Grow</label><input type="number" id="ci-years" value="10"></div>
                            <div style="grid-column: 1 / -1;"><label for="ci-compound">Compounding Frequency</label><select id="ci-compound">
                                <option value="1">Annually</option>
                                <option value="2">Semi-Annually</option>
                                <option value="4">Quarterly</option>
                                <option value="12" selected>Monthly</option>
                                <option value="365">Daily</option>
                            </select></div>
                        </div>
                        <button id="ci-calculate-btn" class="glow-button cta-button">Calculate</button>
                        <div id="tool-output"></div>
                        <canvas id="ci-chart" style="margin-top: 1.5rem;"></canvas>
                    </div>
                `,
                init: () => {
                    const principalInput = document.getElementById('ci-principal');
                    const contributionInput = document.getElementById('ci-contribution');
                    const rateInput = document.getElementById('ci-rate');
                    const yearsInput = document.getElementById('ci-years');
                    const compoundSelect = document.getElementById('ci-compound');
                    const calculateBtn = document.getElementById('ci-calculate-btn');
                    const outputDiv = document.getElementById('tool-output');
                    const ctx = document.getElementById('ci-chart').getContext('2d');
                    let chartInstance = null;

                    const calculateAndDisplay = () => {
                        const P = parseFloat(principalInput.value) || 0;
                        const PMT = parseFloat(contributionInput.value) || 0;
                        const annualRate = parseFloat(rateInput.value) || 0;
                        const t = parseInt(yearsInput.value) || 0;
                        const n = parseInt(compoundSelect.value) || 12;

                        const r = annualRate / 100;

                        let futureValue = P;
                        let totalContributions = P;

                        for (let i = 0; i < t * n; i++) {
                            futureValue *= (1 + r / n);
                            futureValue += PMT;
                            totalContributions += PMT;
                        }

                        if (PMT > 0) { // Future value of a series formula for contribution part
                             futureValue = P * Math.pow(1 + r / n, n * t) + PMT * ((Math.pow(1 + r / n, n * t) - 1) / (r / n));
                        } else { // Standard compound interest for principal only
                            futureValue = P * Math.pow(1 + r/n, n*t);
                        }

                        totalContributions = P + (PMT * n * t);
                        const totalInterest = futureValue - totalContributions;

                        outputDiv.innerHTML = `
                            <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 1rem; text-align: center; margin-top: 1rem; padding-top: 1rem; border-top: 1px solid var(--border-color);">
                                <div>
                                    <div style="font-size: 0.9em; color: var(--text-secondary);">Future Value</div>
                                    <div style="font-size: 1.8em; font-weight: 700; color: var(--accent-color);">$${futureValue.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</div>
                                </div>
                                <div>
                                    <div style="font-size: 0.9em; color: var(--text-secondary);">Total Contributions</div>
                                    <div style="font-size: 1.5em; font-weight: 600;">$${totalContributions.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</div>
                                </div>
                                <div>
                                    <div style="font-size: 0.9em; color: var(--text-secondary);">Total Interest</div>
                                    <div style="font-size: 1.5em; font-weight: 600;">$${totalInterest.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}</div>
                                </div>
                            </div>
                        `;

                        if (chartInstance) { chartInstance.destroy(); }

                        // Recalculate for chart (simpler yearly calc)
                        let chartLabels = ['Start'];
                        let chartPrincipalData = [P];
                        let chartContributionsData = [0];
                        let chartInterestData = [0];
                        let currentBalance = P;

                        for(let i=1; i <= t; i++) {
                            chartLabels.push(`Year ${i}`);
                            let balanceBeforeContributions = currentBalance;
                            currentBalance = balanceBeforeContributions * Math.pow(1 + r / n, n) + PMT * ((Math.pow(1 + r / n, n) - 1) / (r/n));

                            chartPrincipalData.push(P);
                            chartContributionsData.push(PMT * n * i);
                            chartInterestData.push(currentBalance - P - (PMT * n * i));
                        }


                        chartInstance = new Chart(ctx, {
                            type: 'bar',
                            data: {
                                labels: chartLabels,
                                datasets: [{
                                    label: 'Principal',
                                    data: chartPrincipalData,
                                    backgroundColor: '#8b949e',
                                }, {
                                    label: 'Contributions',
                                    data: chartContributionsData,
                                    backgroundColor: '#30363d',
                                },{
                                    label: 'Interest',
                                    data: chartInterestData,
                                    backgroundColor: 'var(--accent-color)',
                                }]
                            },
                            options: {
                                responsive: true,
                                scales: {
                                    x: { stacked: true, ticks: { color: 'var(--text-secondary)' }, grid: { color: 'var(--border-color)' } },
                                    y: { stacked: true, ticks: { color: 'var(--text-secondary)', callback: function(value) { return '$' + value.toLocaleString(); }}, grid: { color: 'var(--border-color)' } }
                                },
                                plugins: {
                                    legend: { labels: { color: 'var(--text-primary)' } },
                                    tooltip: { callbacks: { label: function(context) { let label = context.dataset.label || ''; if (label) { label += ': '; } label += '$' + context.parsed.y.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2}); return label; } } }
                                }
                            }
                        });
                    };
                    [principalInput, contributionInput, rateInput, yearsInput, compoundSelect].forEach(el => el.addEventListener('input', calculateAndDisplay));
                    calculateBtn.addEventListener('click', calculateAndDisplay);
                    calculateAndDisplay();
                    modal.addEventListener('modal:close', () => { if (chartInstance) { chartInstance.destroy(); chartInstance = null; } }, { once: true });
                }
            },

             'invoice-generator': {
  title: 'Invoice Generator — India (Advanced)',
  icon: '🧾',
  getContent: () => `
    <div class="tool-container" style="max-width:1000px;">
      <style>
        .inv-row { display:flex; gap:12px; align-items:center; margin-bottom:8px; }
        .inv-row > * { flex:1; }
        .inv-items table { width:100%; border-collapse:collapse; margin-top:8px; }
        .inv-items th, .inv-items td { padding:8px; border:1px solid var(--border-color); text-align:left; }
        .small { font-size:0.9rem; color:var(--muted); }
        .right { text-align:right; }
      </style>

      <div style="display:flex; gap:1rem;">
        <div style="flex:1;">
          <h3>Seller / Your Details</h3>
          <input placeholder="Business name" id="inv-seller-name" class="full" />
          <input placeholder="Address" id="inv-seller-address" />
          <div class="inv-row">
            <input placeholder="State (e.g. West Bengal)" id="inv-seller-state" />
            <input placeholder="GSTIN (optional)" id="inv-seller-gstin" />
          </div>
        </div>

        <div style="flex:1;">
          <h3>Buyer / Customer Details</h3>
          <input placeholder="Customer name" id="inv-buyer-name" />
          <input placeholder="Customer address" id="inv-buyer-address" />
          <div class="inv-row">
            <input placeholder="State" id="inv-buyer-state" />
            <input placeholder="GSTIN (if applicable)" id="inv-buyer-gstin" />
          </div>
        </div>
      </div>

      <div style="margin-top:12px;" class="inv-row">
        <div style="flex:1">
          <label>Invoice No</label>
          <input id="inv-number" />
        </div>
        <div style="flex:1">
          <label>Invoice Date</label>
          <input type="date" id="inv-date" />
        </div>
        <div style="flex:1">
          <label>Place of Supply (State)</label>
          <input id="inv-place" />
        </div>
      </div>

      <h3 style="margin-top:16px;">Items</h3>
      <div class="inv-items">
        <table id="items-table">
          <thead>
            <tr>
              <th style="width:28%;">Description</th>
              <th style="width:10%;">HSN / SAC</th>
              <th style="width:10%;">Qty</th>
              <th style="width:12%;">Rate (₹)</th>
              <th style="width:12%;">Discount (₹)</th>
              <th style="width:10%;">Tax %</th>
              <th style="width:12%;">Amount (₹)</th>
              <th style="width:6%;">✖</th>
            </tr>
          </thead>
          <tbody></tbody>
        </table>

        <button id="add-item-btn" class="glow-button" style="margin-top:8px;">+ Add Item</button>
      </div>

      <div style="margin-top:14px; display:flex; gap:12px; align-items:flex-end;">
        <div style="flex:1">
          <label>Invoice Notes / Terms</label>
          <textarea id="inv-notes" rows="3" style="width:100%;"></textarea>
        </div>
        <div style="width:340px; border:1px solid var(--border-color); padding:10px; border-radius:8px;">
          <div class="inv-row"><label>Sub Total</label><div id="calc-sub" class="right">₹0.00</div></div>
          <div class="inv-row"><label>Total Discount</label><div id="calc-discount" class="right">₹0.00</div></div>
          <div class="inv-row"><label>Taxable Value</label><div id="calc-taxable" class="right">₹0.00</div></div>

          <div id="tax-breakup" style="margin-top:8px;"></div>

          <div class="inv-row" style="font-weight:bold; margin-top:6px;">
            <label>Grand Total</label><div id="calc-grand" class="right">₹0.00</div>
          </div>

          <div class="inv-row small" style="margin-top:6px;">
            <div>
              <label>Round Off</label>
              <input type="checkbox" id="inv-round" />
            </div>
            <div style="text-align:right;">
              <label>Shipping (₹)</label>
              <input id="inv-shipping" type="number" min="0" value="0" style="width:100px;"/>
            </div>
          </div>
        </div>
      </div>

      <div style="margin-top:12px; display:flex; gap:8px;">
        <button id="save-inv-btn" class="glow-button">Save Invoice</button>
        <button id="print-inv-btn" class="glow-button">Print / Save as PDF</button>
        <button id="export-json-btn" class="glow-button">Export JSON</button>
        <button id="export-csv-btn" class="glow-button">Export CSV</button>
        <select id="load-inv-select" style="margin-left:auto;"></select>
        <button id="delete-saved-btn" style="background:#e74c3c;" class="glow-button">Delete Saved</button>
      </div>

      <div id="invoice-preview" style="display:none; margin-top:12px;"></div>
    </div>
  `,
  init: () => {
    // Helpers & state
    const $ = (id) => document.getElementById(id);
    const tbody = document.querySelector('#items-table tbody');
    const addItemBtn = $('add-item-btn');
    const invDate = $('inv-date'), invNumber = $('inv-number'), invPlace = $('inv-place');
    const sellerName = $('inv-seller-name'), sellerAddr = $('inv-seller-address'), sellerState = $('inv-seller-state'), sellerGstin = $('inv-seller-gstin');
    const buyerName = $('inv-buyer-name'), buyerAddr = $('inv-buyer-address'), buyerState = $('inv-buyer-state'), buyerGstin = $('inv-buyer-gstin');
    const notes = $('inv-notes'), shippingInput = $('inv-shipping'), roundChk = $('inv-round');
    const calcSub = $('calc-sub'), calcDiscount = $('calc-discount'), calcTaxable = $('calc-taxable'), calcGrand = $('calc-grand'), taxBreakup = $('tax-breakup');
    const saveBtn = $('save-inv-btn'), printBtn = $('print-inv-btn'), exportJson = $('export-json-btn'), exportCsv = $('export-csv-btn');
    const loadSelect = $('load-inv-select'), deleteSaved = $('delete-saved-btn'), previewDiv = $('invoice-preview');

    let items = JSON.parse(localStorage.getItem('invoice_items')) || [];
    let savedInvoices = JSON.parse(localStorage.getItem('saved_invoices')) || {};

    // Initialize invoice date & number
    const todayISO = new Date().toISOString().slice(0,10);
    if (!invDate.value) invDate.value = todayISO;
    if (!invNumber.value) invNumber.value = genInvoiceNo();

    function genInvoiceNo() {
      const d = new Date();
      const y = d.getFullYear().toString().slice(-2);
      const m = String(d.getMonth()+1).padStart(2,'0');
      const counter = parseInt(localStorage.getItem('inv_counter_' + y + m) || '0') + 1;
      localStorage.setItem('inv_counter_' + y + m, counter);
      return `INV-${y}${m}-${String(counter).padStart(4,'0')}`;
    }

    // Item row factory
    function addItemRow(data = {}) {
      const id = 'row_' + Date.now() + Math.random().toString(36).slice(2,7);
      const tr = document.createElement('tr');
      tr.dataset.id = id;
      tr.innerHTML = `
        <td><input class="item-desc" value="${data.desc || ''}" placeholder="Description"/></td>
        <td><input class="item-hsn" value="${data.hsn || ''}" placeholder="HSN/SAC"/></td>
        <td><input type="number" min="0" step="1" class="item-qty" value="${data.qty ?? 1}"/></td>
        <td><input type="number" min="0" step="0.01" class="item-rate" value="${data.rate ?? 0}"/></td>
        <td><input type="number" min="0" step="0.01" class="item-discount" value="${data.discount ?? 0}"/></td>
        <td><input type="number" min="0" step="0.01" class="item-tax" value="${data.tax ?? 0}"/></td>
        <td class="right item-amount">₹0.00</td>
        <td class="right"><button class="remove-item" title="Remove">✖</button></td>
      `;
      tbody.appendChild(tr);

      // attach events
      ['item-qty','item-rate','item-discount','item-tax','item-desc','item-hsn'].forEach(cls => {
        tr.querySelector('.' + cls).addEventListener('input', renderAll);
      });
      tr.querySelector('.remove-item').addEventListener('click', () => { tr.remove(); renderAll(); });

      renderAll();
    }

    addItemBtn.addEventListener('click', () => addItemRow());

    // Load saved items (if any)
    if (!items.length) {
      // seed one blank row
      addItemRow();
    } else {
      items.forEach(it => addItemRow(it));
    }

    // Calculation logic
    function parseNumber(v) { const n = parseFloat(v); return isNaN(n) ? 0 : n; }

    function renderAll() {
      const rows = Array.from(tbody.querySelectorAll('tr'));
      let subTotal = 0, totalDiscount = 0;
      const taxMap = {}; // taxPercent -> taxable & taxAmount

      rows.forEach(r => {
        const qty = parseNumber(r.querySelector('.item-qty').value);
        const rate = parseNumber(r.querySelector('.item-rate').value);
        const discount = parseNumber(r.querySelector('.item-discount').value);
        const taxPerc = parseNumber(r.querySelector('.item-tax').value);

        const lineGross = +(qty * rate);
        const lineDiscount = Math.min(discount, lineGross);
        const taxable = +(lineGross - lineDiscount);
        const taxAmount = +(taxable * taxPerc / 100);

        subTotal += lineGross;
        totalDiscount += lineDiscount;

        // accumulate tax map
        if (!taxMap[taxPerc]) taxMap[taxPerc] = { taxable: 0, tax: 0 };
        taxMap[taxPerc].taxable += taxable;
        taxMap[taxPerc].tax += taxAmount;

        r.querySelector('.item-amount').textContent = `₹${(taxable + taxAmount).toFixed(2)}`;
      });

      const shipping = parseNumber(shippingInput.value);
      const taxableValue = subTotal - totalDiscount;
      // choose IGST vs CGST+SGST depending on states
      const sellerSt = (sellerState.value || '').trim().toLowerCase();
      const buyerSt = (buyerState.value || '').trim().toLowerCase();
      const intraState = sellerSt && buyerSt && (sellerSt === buyerSt);

      // build tax breakup UI
      taxBreakup.innerHTML = '';
      let totalTax = 0;
      Object.keys(taxMap).sort((a,b)=>parseFloat(a)-parseFloat(b)).forEach(k => {
        const pct = parseFloat(k);
        const t = taxMap[k];
        totalTax += t.tax;
        if (intraState) {
          // split equally into CGST & SGST
          const half = t.tax / 2;
          taxBreakup.innerHTML += `<div class="inv-row small"><div>Tax @ ${pct}% on ₹${t.taxable.toFixed(2)}</div><div class="right">CGST ₹${half.toFixed(2)} | SGST ₹${half.toFixed(2)}</div></div>`;
        } else {
          taxBreakup.innerHTML += `<div class="inv-row small"><div>Tax @ ${pct}% on ₹${t.taxable.toFixed(2)}</div><div class="right">IGST ₹${t.tax.toFixed(2)}</div></div>`;
        }
      });

      let grand = taxableValue + totalTax + shipping;
      if (roundChk.checked) {
        const rounded = Math.round(grand);
        grand = rounded; // simple round-off to nearest rupee
      }

      calcSub.textContent = `₹${subTotal.toFixed(2)}`;
      calcDiscount.textContent = `₹${totalDiscount.toFixed(2)}`;
      calcTaxable.textContent = `₹${taxableValue.toFixed(2)}`;
      calcGrand.textContent = `₹${grand.toFixed(2)}`;
    }

    // Save / Load logic
    function refreshSavedList() {
      loadSelect.innerHTML = '<option value="">-- Load saved invoice --</option>';
      Object.keys(savedInvoices).forEach(k => {
        const opt = document.createElement('option');
        opt.value = k;
        opt.textContent = `${k} — ${savedInvoices[k].date} — ${savedInvoices[k].buyerName || '-'}`;
        loadSelect.appendChild(opt);
      });
    }
    refreshSavedList();

    saveBtn.addEventListener('click', () => {
      const inv = collectInvoiceData();
      const id = inv.number;
      savedInvoices[id] = inv;
      localStorage.setItem('saved_invoices', JSON.stringify(savedInvoices));
      alert('Invoice saved locally: ' + id);
      refreshSavedList();
    });

    loadSelect.addEventListener('change', () => {
      const id = loadSelect.value;
      if (!id) return;
      if (!savedInvoices[id]) { alert('Saved invoice not found.'); return; }
      populateInvoice(savedInvoices[id]);
    });

    deleteSaved.addEventListener('click', () => {
      const id = loadSelect.value;
      if (!id) { alert('Choose a saved invoice to delete'); return; }
      if (confirm('Delete ' + id + ' ?')) {
        delete savedInvoices[id];
        localStorage.setItem('saved_invoices', JSON.stringify(savedInvoices));
        refreshSavedList();
        alert('Deleted');
      }
    });

    function collectInvoiceData() {
      const rows = Array.from(tbody.querySelectorAll('tr'));
      const items = rows.map(r => ({
        desc: r.querySelector('.item-desc').value,
        hsn: r.querySelector('.item-hsn').value,
        qty: parseNumber(r.querySelector('.item-qty').value),
        rate: parseNumber(r.querySelector('.item-rate').value),
        discount: parseNumber(r.querySelector('.item-discount').value),
        tax: parseNumber(r.querySelector('.item-tax').value),
      }));
      const inv = {
        number: invNumber.value || genInvoiceNo(),
        date: invDate.value,
        place: invPlace.value,
        seller: { name: sellerName.value, address: sellerAddr.value, state: sellerState.value, gstin: sellerGstin.value },
        buyer: { name: buyerName.value, address: buyerAddr.value, state: buyerState.value, gstin: buyerGstin.value },
        items,
        notes: notes.value,
        shipping: parseNumber(shippingInput.value),
        roundOff: roundChk.checked,
        savedAt: new Date().toISOString(),
        buyerName: buyerName.value
      };
      return inv;
    }

    function populateInvoice(inv) {
      invNumber.value = inv.number; invDate.value = inv.date; invPlace.value = inv.place || '';
      sellerName.value = inv.seller.name || ''; sellerAddr.value = inv.seller.address || ''; sellerState.value = inv.seller.state || ''; sellerGstin.value = inv.seller.gstin || '';
      buyerName.value = inv.buyer.name || ''; buyerAddr.value = inv.buyer.address || ''; buyerState.value = inv.buyer.state || ''; buyerGstin.value = inv.buyer.gstin || '';
      notes.value = inv.notes || ''; shippingInput.value = inv.shipping || 0; roundChk.checked = !!inv.roundOff;

      // clear rows
      tbody.innerHTML = '';
      inv.items.forEach(it => addItemRow(it));
      renderAll();
    }

    // Export JSON / CSV
    exportJson.addEventListener('click', () => {
      const inv = collectInvoiceData();
      const blob = new Blob([JSON.stringify(inv, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a'); a.href = url; a.download = `${inv.number}.json`; a.click();
      URL.revokeObjectURL(url);
    });

    exportCsv.addEventListener('click', () => {
      const inv = collectInvoiceData();
      let csv = `Invoice No,${inv.number}\nDate,${inv.date}\n\nDescription,HSN/SAC,Qty,Rate,Discount,Tax%,LineTotal\n`;
      inv.items.forEach(it => {
        const lineGross = it.qty * it.rate;
        const taxable = Math.max(0, lineGross - it.discount);
        const tax = taxable * it.tax / 100;
        const lineTotal = taxable + tax;
        csv += `"${it.desc}","${it.hsn}",${it.qty},${it.rate},${it.discount},${it.tax},${lineTotal.toFixed(2)}\n`;
      });
      const blob = new Blob([csv], { type: 'text/csv' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a'); a.href = url; a.download = `${inv.number}.csv`; a.click();
      URL.revokeObjectURL(url);
    });

    // Print / printable view
    printBtn.addEventListener('click', () => {
      const inv = collectInvoiceData();
      const legal = buildPrintableHTML(inv);
      const w = window.open('', '_blank', 'width=900,height=700');
      w.document.write(legal);
      w.document.close();
      // small delay to ensure resources loaded
      setTimeout(() => w.print(), 500);
    });

    function money(n) { return `₹${parseNumber(n).toFixed(2)}`; }

    function buildPrintableHTML(inv) {
      // calculate to show tax breakup properly
      // create a simple calculation engine (similar to renderAll)
      let subTotal = 0, totalDiscount = 0;
      const taxMap = {};
      inv.items.forEach(it => {
        const lineGross = it.qty * it.rate;
        const lineDiscount = Math.min(it.discount, lineGross);
        const taxable = lineGross - lineDiscount;
        const taxAmount = taxable * it.tax / 100;
        subTotal += lineGross; totalDiscount += lineDiscount;
        if (!taxMap[it.tax]) taxMap[it.tax] = { taxable:0, tax:0 };
        taxMap[it.tax].taxable += taxable; taxMap[it.tax].tax += taxAmount;
      });
      const taxableValue = subTotal - totalDiscount;
      let totalTax = 0; Object.values(taxMap).forEach(v => totalTax += v.tax);
      let grand = taxableValue + totalTax + (inv.shipping || 0);
      if (inv.roundOff) grand = Math.round(grand);

      const seller = inv.seller, buyer = inv.buyer;
      const intra = (seller.state||'').trim().toLowerCase() === (buyer.state||'').trim().toLowerCase();

      // build item rows
      const rowsHtml = inv.items.map(it => {
        const lineGross = it.qty * it.rate;
        const taxable = Math.max(0, lineGross - it.discount);
        const taxAmt = taxable * it.tax / 100;
        return `<tr>
          <td style="padding:6px;border:1px solid #ddd;">${escapeHtml(it.desc)}</td>
          <td style="padding:6px;border:1px solid #ddd;">${escapeHtml(it.hsn)}</td>
          <td style="padding:6px;border:1px solid #ddd; text-align:right;">${it.qty}</td>
          <td style="padding:6px;border:1px solid #ddd; text-align:right;">${it.rate.toFixed(2)}</td>
          <td style="padding:6px;border:1px solid #ddd; text-align:right;">${it.discount.toFixed(2)}</td>
          <td style="padding:6px;border:1px solid #ddd; text-align:right;">${it.tax}%</td>
          <td style="padding:6px;border:1px solid #ddd; text-align:right;">${(taxable + taxAmt).toFixed(2)}</td>
        </tr>`; }).join('');

      let taxHtml = '';
      Object.keys(taxMap).forEach(k => {
        const t = taxMap[k];
        if (intra) {
          const half = t.tax / 2;
          taxHtml += `<div style="display:flex; justify-content:space-between;"><div>Tax ${k}% on ${t.taxable.toFixed(2)}</div><div>CGST ${half.toFixed(2)} | SGST ${half.toFixed(2)}</div></div>`;
        } else {
          taxHtml += `<div style="display:flex; justify-content:space-between;"><div>Tax ${k}% on ${t.taxable.toFixed(2)}</div><div>IGST ${t.tax.toFixed(2)}</div></div>`;
        }
      });

      return `
        <html><head><title>${escapeHtml(inv.number)}</title>
        <style>
          body { font-family: Arial, sans-serif; color:#222; margin:20px; }
          .header { display:flex; justify-content:space-between; align-items:flex-start; }
          .box { border:1px solid #ddd; padding:12px; border-radius:6px; }
          table { width:100%; border-collapse:collapse; margin-top:8px; }
        </style>
        </head><body>
          <div class="header">
            <div>
              <h2>${escapeHtml(seller.name || '')}</h2>
              <div>${escapeHtml(seller.address || '')}</div>
              <div>State: ${escapeHtml(seller.state||'')} | GSTIN: ${escapeHtml(seller.gstin||'')}</div>
            </div>
            <div style="text-align:right;">
              <h3>Tax Invoice</h3>
              <div>Invoice No: <strong>${escapeHtml(inv.number)}</strong></div>
              <div>Date: ${escapeHtml(inv.date)}</div>
              <div>Place of Supply: ${escapeHtml(inv.place||'')}</div>
            </div>
          </div>

          <div style="margin-top:12px; display:flex; gap:12px;">
            <div class="box" style="flex:1;">
              <strong>Bill To:</strong><br/>
              ${escapeHtml(buyer.name||'')}<br/>
              ${escapeHtml(buyer.address||'')}<br/>
              State: ${escapeHtml(buyer.state||'')} | GSTIN: ${escapeHtml(buyer.gstin||'')}
            </div>
            <div class="box" style="width:320px;">
              <strong>Summary</strong>
              <div>Sub Total: ${subTotal.toFixed(2)}</div>
              <div>Total Discount: ${totalDiscount.toFixed(2)}</div>
              <div>Taxable: ${taxableValue.toFixed(2)}</div>
              ${taxHtml}
              <div style="font-weight:bold; margin-top:6px;">Grand Total: ${grand.toFixed(2)}</div>
            </div>
          </div>

          <table>
            <thead>
              <tr>
                <th style="padding:6px;border:1px solid #ddd;">Description</th>
                <th style="padding:6px;border:1px solid #ddd;">HSN/SAC</th>
                <th style="padding:6px;border:1px solid #ddd; text-align:right;">Qty</th>
                <th style="padding:6px;border:1px solid #ddd; text-align:right;">Rate</th>
                <th style="padding:6px;border:1px solid #ddd; text-align:right;">Disc</th>
                <th style="padding:6px;border:1px solid #ddd; text-align:right;">Tax%</th>
                <th style="padding:6px;border:1px solid #ddd; text-align:right;">Line Total</th>
              </tr>
            </thead>
            <tbody>${rowsHtml}</tbody>
          </table>

          <div style="margin-top:12px;">
            <strong>Notes / Terms:</strong>
            <div>${escapeHtml(inv.notes || '')}</div>
          </div>

          <div style="margin-top:24px; display:flex; gap:24px;">
            <div style="flex:1;">
              <div>Prepared By: ____________________</div>
            </div>
            <div style="width:320px; text-align:right;">
              <div>For ${escapeHtml(seller.name || '')}</div>
              <div style="margin-top:48px;">Authorised Signatory</div>
            </div>
          </div>

        </body></html>
      `;
    }

    // utility
    function escapeHtml(s) {
      if (!s) return '';
      return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    }

    // initial render
    renderAll();

    // clean up on modal close if modal exists in host
    if (typeof modal !== 'undefined') {
      modal.addEventListener('modal:close', () => {
        // nothing heavy to clean up
      }, { once: true });
    }
  }
},


            'unit-converter': { title: 'Unit Converter', icon: '🔄', getContent: () => `<div class="tool-container"><label for="unit-type">Category:</label><select id="unit-type"><option value="length">Length</option><option value="weight">Weight</option><option value="temp">Temperature</option></select><div style="display:flex; align-items:center; gap:10px;"><input type="number" id="unit-input" value="1"><select id="unit-from"></select><span>=</span><input type="text" id="unit-output" readonly><select id="unit-to"></select></div></div>`, init: () => { const typeSel = document.getElementById('unit-type'), fromSel = document.getElementById('unit-from'), toSel = document.getElementById('unit-to'), input = document.getElementById('unit-input'), output = document.getElementById('unit-output'); const units = { length: {'Meters': 1, 'Kilometers': 1000, 'Miles': 1609.34, 'Feet': 0.3048}, weight: {'Grams': 1, 'Kilograms': 1000, 'Pounds': 453.592, 'Ounces': 28.3495}, temp: {'Celsius': 'c', 'Fahrenheit': 'f', 'Kelvin': 'k'} }; const populate = () => { const type = typeSel.value, opts = Object.keys(units[type]); fromSel.innerHTML = toSel.innerHTML = opts.map(o => `<option value="${units[type][o]}">${o}</option>`).join(''); toSel.selectedIndex = 1; }; const convert = () => { const type = typeSel.value, from = fromSel.value, to = toSel.value, val = parseFloat(input.value); if (isNaN(val)) { output.value = ''; return; } if (type === 'temp') { let tempC; if (from === 'c') tempC = val; if (from === 'f') tempC = (val - 32) * 5 / 9; if (from === 'k') tempC = val - 273.15; let res; if (to === 'c') res = tempC; if (to === 'f') res = (tempC * 9 / 5) + 32; if (to === 'k') res = tempC + 273.15; output.value = res.toFixed(2); } else { output.value = (val * from / to).toFixed(4); } }; [typeSel, fromSel, toSel, input].forEach(el => el.addEventListener(el.id === 'unit-input' ? 'input' : 'change', convert)); typeSel.addEventListener('change', populate); populate(); convert(); }},


            'snake-game': { title: 'Classic Snake Game', icon: '🐍', getContent: () => `<div class="tool-container" style="align-items:center;"><p>Use <strong>Arrow Keys</strong> or <strong>Swipe</strong> on the canvas to move.</p><canvas id="snake-canvas" width="400" height="400" style="background-color: var(--dark-bg);"></canvas><div id="snake-score" style="font-size:1.2rem; margin-top:10px;">Score: 0</div><button id="snake-restart-btn" class="glow-button" style="margin-top: 15px; display: none;">Restart Game</button></div>`, init: () => { const canvas = document.getElementById('snake-canvas'), ctx = canvas.getContext('2d'), scoreEl = document.getElementById('snake-score'), restartBtn = document.getElementById('snake-restart-btn'); const gridSize = 20; let snake, food, direction, score, gameOver, gameLoopTimeout, touchStartX, touchStartY; const gameLoop = () => { if (gameOver) { ctx.fillStyle = 'white'; ctx.font = '40px Arial'; ctx.textAlign = 'center'; ctx.fillText('Game Over!', canvas.width / 2, canvas.height / 2 - 20); ctx.font = '20px Arial'; ctx.fillText(`Final Score: ${score}`, canvas.width / 2, canvas.height / 2 + 20); restartBtn.style.display = 'block'; return; } let head = { x: snake[0].x, y: snake[0].y }; if (direction === 'right') head.x++; else if (direction === 'left') head.x--; else if (direction === 'up') head.y--; else if (direction === 'down') head.y++; const hitWall = head.x < 0 || head.x >= canvas.width / gridSize || head.y < 0 || head.y >= canvas.height / gridSize; const hitSelf = snake.some(p => p.x === head.x && p.y === head.y); if (hitWall || hitSelf) gameOver = true; snake.unshift(head); if (head.x === food.x && head.y === food.y) { score++; scoreEl.textContent = `Score: ${score}`; placeFood(); } else { snake.pop(); } ctx.fillStyle = getComputedStyle(canvas).backgroundColor; ctx.fillRect(0, 0, canvas.width, canvas.height); ctx.fillStyle = 'var(--accent-color)'; snake.forEach(p => ctx.fillRect(p.x * gridSize, p.y * gridSize, gridSize - 2, gridSize - 2)); ctx.fillStyle = '#e74c3c'; ctx.fillRect(food.x * gridSize, food.y * gridSize, gridSize - 2, gridSize - 2); gameLoopTimeout = setTimeout(gameLoop, 150); }; const placeFood = () => { let newFoodX, newFoodY, collision; do { newFoodX = Math.floor(Math.random() * (canvas.width / gridSize)); newFoodY = Math.floor(Math.random() * (canvas.height / gridSize)); collision = snake.some(s => s.x === newFoodX && s.y === newFoodY); } while (collision); food = { x: newFoodX, y: newFoodY }; }; const keyHandler = e => { if (gameOver) return; if (e.key === 'ArrowUp' && direction !== 'down') direction = 'up'; else if (e.key === 'ArrowDown' && direction !== 'up') direction = 'down'; else if (e.key === 'ArrowLeft' && direction !== 'right') direction = 'left'; else if (e.key === 'ArrowRight' && direction !== 'left') direction = 'right'; }; const touchStartHandler = e => { e.preventDefault(); touchStartX = e.touches[0].clientX; touchStartY = e.touches[0].clientY; }; const touchEndHandler = e => { if (gameOver) return; const touchEndX = e.changedTouches[0].clientX, touchEndY = e.changedTouches[0].clientY; const dx = touchEndX - touchStartX, dy = touchEndY - touchStartY; if (Math.abs(dx) > Math.abs(dy)) { if (dx > 0 && direction !== 'left') direction = 'right'; else if (dx < 0 && direction !== 'right') direction = 'left'; } else { if (dy > 0 && direction !== 'up') direction = 'down'; else if (dy < 0 && direction !== 'down') direction = 'up'; } }; const startGame = () => { snake = [{ x: 10, y: 10 }]; direction = 'right'; score = 0; gameOver = false; scoreEl.textContent = 'Score: 0'; restartBtn.style.display = 'none'; placeFood(); if (gameLoopTimeout) clearTimeout(gameLoopTimeout); gameLoop(); }; document.addEventListener('keydown', keyHandler); canvas.addEventListener('touchstart', touchStartHandler); canvas.addEventListener('touchend', touchEndHandler); restartBtn.addEventListener('click', startGame); modal.addEventListener('modal:close', () => { clearTimeout(gameLoopTimeout); document.removeEventListener('keydown', keyHandler); canvas.removeEventListener('touchstart', touchStartHandler); canvas.removeEventListener('touchend', touchEndHandler); }, { once: true }); startGame(); }},
            'tic-tac-toe': { title: 'Tic-Tac-Toe', icon: '🎲', getContent: () => `<div class="tool-container" style="align-items:center;"><h3 id="ttt-status">Player X's turn</h3><div id="ttt-board" style="display:grid; grid-template-columns: repeat(3, 100px); grid-template-rows: repeat(3, 100px); gap: 5px;">${Array(9).fill('').map((_, i) => `<div class="ttt-cell" data-index="${i}" style="width:100px; height:100px; background:var(--button-bg); display:flex; align-items:center; justify-content:center; font-size:3rem; cursor:pointer; border: 1px solid var(--border-color); border-radius: 8px;"></div>`).join('')}</div><button id="ttt-restart" class="glow-button" style="margin-top:1rem;">Restart Game</button></div>`, init: () => { const status = document.getElementById('ttt-status'), restartBtn = document.getElementById('ttt-restart'), cells = document.querySelectorAll('.ttt-cell'); let current, gameState, active; const wins = [[0, 1, 2], [3, 4, 5], [6, 7, 8], [0, 3, 6], [1, 4, 7], [2, 5, 8], [0, 4, 8], [2, 4, 6]]; const start = () => { current = 'X'; gameState = Array(9).fill(""); active = true; status.innerHTML = `Player ${current}'s turn`; cells.forEach(c => { c.innerHTML = ""; c.style.color = 'var(--text-primary)'; }); }; const checkWin = () => { let roundWon = wins.some(w => gameState[w[0]] && gameState[w[0]] === gameState[w[1]] && gameState[w[1]] === gameState[w[2]]); if (roundWon) { status.innerHTML = `Player ${current} has won!`; active = false; return; } if (!gameState.includes("")) { status.innerHTML = `Game ended in a draw!`; active = false; return; } current = current === "X" ? "O" : "X"; status.innerHTML = `Player ${current}'s turn`; }; const clickCell = e => { const cell = e.target, idx = parseInt(cell.dataset.index); if (gameState[idx] !== "" || !active) return; gameState[idx] = current; cell.innerHTML = current; cell.style.color = current === 'X' ? 'var(--accent-color)' : '#ff6b6b'; checkWin(); }; cells.forEach(c => c.addEventListener('click', clickCell)); restartBtn.addEventListener('click', start); start(); }},
        'todo-list': {
    title: 'To-Do List & Task Prioritizer',
    icon: '✅',
    getContent: () => `
        <div class="tool-container">
            <!-- New Task Form -->
            <form id="task-form" class="flex flex-col sm:flex-row items-center gap-3">
                <input type="text" id="task-text" placeholder="Add a new task..." required 
                    class="flex-1 w-full px-3 py-2 rounded-lg border bg-transparent">
                <select id="task-priority" class="px-3 py-2 rounded-lg border bg-transparent">
                    <option value="low">Low Priority</option>
                    <option value="medium">Medium Priority</option>
                    <option value="high">High Priority</option>
                </select>
                <input type="date" id="task-date" 
                    class="px-3 py-2 rounded-lg border bg-transparent">
                <button type="submit" class="glow-button">Add Task</button>
            </form>

            <!-- Task Controls -->
            <div class="flex flex-col sm:flex-row items-center justify-between mt-4 gap-3">
                <input type="text" id="task-search" placeholder="Search tasks..."
                    class="flex-1 px-3 py-2 rounded-lg border bg-transparent">
                <div class="flex gap-3 w-full sm:w-auto">
                    <select id="filter-priority" class="px-3 py-2 rounded-lg border bg-transparent">
                        <option value="all">All Priorities</option>
                        <option value="high">High</option>
                        <option value="medium">Medium</option>
                        <option value="low">Low</option>
                    </select>
                    <select id="sort-by" class="px-3 py-2 rounded-lg border bg-transparent">
                        <option value="default">Sort by Default</option>
                        <option value="due-date">Due Date</option>
                        <option value="priority">Priority</option>
                    </select>
                </div>
            </div>

            <!-- Task List Grid -->
            <ul id="task-list" 
                class="mt-6 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4"></ul>
        </div>
    `,   <!-- ✅ COMMA added here -->

    init: () => {
        const taskForm = document.getElementById('task-form');
        const taskList = document.getElementById('task-list');
        const taskText = document.getElementById('task-text');
        const taskPriority = document.getElementById('task-priority');
        const taskDate = document.getElementById('task-date');
        const taskSearch = document.getElementById('task-search');
        const filterPriority = document.getElementById('filter-priority');
        const sortSelect = document.getElementById('sort-by');

        let tasks = [];

        // Save & load
        const saveTasks = () => localStorage.setItem('tasks', JSON.stringify(tasks));
        const loadTasks = () => {
            const stored = localStorage.getItem('tasks');
            if (stored) {
                tasks = JSON.parse(stored);
            }
            renderTasks();
        };

        // Render tasks
        const renderTasks = () => {
            const searchTerm = taskSearch.value.toLowerCase();
            const currentFilter = filterPriority.value;
            const currentSort = sortSelect.value;

            let filteredTasks = tasks.filter(task => {
                const matchesSearch = task.text.toLowerCase().includes(searchTerm);
                const matchesFilter = currentFilter === 'all' || task.priority === currentFilter;
                return matchesSearch && matchesFilter;
            });

            if (currentSort === 'due-date') {
                filteredTasks.sort((a, b) => {
                    const dateA = a.dueDate ? new Date(a.dueDate) : new Date('9999-12-31');
                    const dateB = b.dueDate ? new Date(b.dueDate) : new Date('9999-12-31');
                    return dateA - dateB;
                });
            } else if (currentSort === 'priority') {
                const order = { high: 3, medium: 2, low: 1 };
                filteredTasks.sort((a, b) => order[b.priority] - order[a.priority]);
            }

            taskList.innerHTML = '';

            if (!filteredTasks.length) {
                taskList.innerHTML = `<li class="col-span-full text-center text-gray-500 italic">No tasks found.</li>`;
                return;
            }

            filteredTasks.forEach(task => {
                const li = document.createElement('li');
                li.className = `tool-card flex flex-col justify-between p-4 border rounded-lg ${task.completed ? 'opacity-50' : ''}`;
                li.dataset.id = task.id;

                const colors = { high: '#f87171', medium: '#facc15', low: '#4ade80' };

                li.innerHTML = `
                    <div class="flex items-center space-x-3 mb-3">
                        <input type="checkbox" ${task.completed ? 'checked' : ''} class="cursor-pointer">
                        <span class="text-base font-medium ${task.completed ? 'line-through opacity-70' : ''}">
                            ${task.text}
                        </span>
                    </div>
                    <div class="flex flex-wrap items-center gap-3 text-sm opacity-80">
                        <span style="color:${colors[task.priority]}">●</span>
                        <span class="capitalize">${task.priority}</span>
                        <span>Due: ${task.dueDate || 'N/A'}</span>
                        <button class="edit-btn glow-button px-2 py-1">Edit</button>
                        <button class="delete-btn glow-button px-2 py-1">X</button>
                    </div>
                `;

                // Events
                li.querySelector('input[type="checkbox"]').addEventListener('change', () => {
                    task.completed = !task.completed;
                    saveTasks();
                    renderTasks();
                });

                li.querySelector('.delete-btn').addEventListener('click', () => {
                    tasks = tasks.filter(t => t.id !== task.id);
                    saveTasks();
                    renderTasks();
                });

                li.querySelector('.edit-btn').addEventListener('click', () => {
                    const newText = prompt("Edit the task:", task.text);
                    if (newText && newText.trim() !== "") {
                        task.text = newText.trim();
                        saveTasks();
                        renderTasks();
                    }
                });

                taskList.appendChild(li);
            });
        };

        // Add task
        taskForm.addEventListener('submit', (e) => {
            e.preventDefault();
            const text = taskText.value.trim();
            if (!text) return;

            const newTask = {
                id: Date.now(),
                text,
                priority: taskPriority.value,
                dueDate: taskDate.value,
                completed: false
            };

            tasks.push(newTask);

            // Reset form
            taskForm.reset();

            saveTasks();
            renderTasks();
        });

        // Listeners
        taskSearch.addEventListener('input', renderTasks);
        filterPriority.addEventListener('change', renderTasks);
        sortSelect.addEventListener('change', renderTasks);

        loadTasks();
    }
},

         'pomodoro-timer': {
    title: 'Pomodoro Timer ⏲️ – Focus Tool with Breaks',
    icon: '⏲️',
    getContent: () => `
        <div class="tool-container">
            <h3>🎯 Stay Focused with Pomodoro</h3>
            <div style="margin-top:1rem; display:flex; flex-direction:column; align-items:center; gap:1rem;">
                <div id="pomodoro-display" 
                    style="font-size:3rem; font-weight:bold; padding:1rem; border:2px solid var(--border-color); border-radius:12px; width:200px; text-align:center;">
                    25:00
                </div>
                <div style="display:flex; gap:0.5rem; flex-wrap:wrap; justify-content:center;">
                    <button id="start-pomo" class="glow-button">▶️ Start</button>
                    <button id="pause-pomo" class="glow-button">⏸️ Pause</button>
                    <button id="reset-pomo" class="glow-button">🔄 Reset</button>
                </div>
            </div>

            <div style="margin-top:1.5rem; display:flex; flex-wrap:wrap; gap:1rem; justify-content:center;">
                <label>Work (min): <input type="number" id="pomo-work" value="25" min="1" max="120" style="width:60px;"/></label>
                <label>Break (min): <input type="number" id="pomo-break" value="5" min="1" max="60" style="width:60px;"/></label>
                <label>Long Break (min): <input type="number" id="pomo-long" value="15" min="1" max="60" style="width:60px;"/></label>
                <label>Sessions per Cycle: <input type="number" id="pomo-cycle" value="4" min="1" max="10" style="width:60px;"/></label>
            </div>

            <h3 style="margin-top:2rem;">📊 Session Log</h3>
            <ul id="pomo-log" style="margin-top:1rem; max-height:150px; overflow-y:auto; padding-left:1rem; list-style:disc;"></ul>

            <div style="margin-top:2rem; position:relative; min-height:250px;">
                <canvas id="pomo-chart"></canvas>
            </div>

            <button id="clear-pomo-log" class="glow-button" style="margin-top:1.5rem; background:#e74c3c;">Clear Log</button>
        </div>
    `,
    init: () => {
        const display = document.getElementById('pomodoro-display'),
              startBtn = document.getElementById('start-pomo'),
              pauseBtn = document.getElementById('pause-pomo'),
              resetBtn = document.getElementById('reset-pomo'),
              logList = document.getElementById('pomo-log'),
              clearLogBtn = document.getElementById('clear-pomo-log'),
              workInput = document.getElementById('pomo-work'),
              breakInput = document.getElementById('pomo-break'),
              longInput = document.getElementById('pomo-long'),
              cycleInput = document.getElementById('pomo-cycle'),
              ctx = document.getElementById('pomo-chart').getContext('2d');

        let pomoData = JSON.parse(localStorage.getItem('pomoData')) || [];
        let pomoChart;

        let isRunning = false, isWork = true, sessionCount = 0, timer, timeLeft;

        const updateDisplay = () => {
            const min = Math.floor(timeLeft / 60).toString().padStart(2,'0');
            const sec = (timeLeft % 60).toString().padStart(2,'0');
            display.textContent = `${min}:${sec}`;
        };

        const logSession = (type, duration) => {
            const entry = { type, duration, date: new Date().toLocaleString() };
            pomoData.push(entry);
            renderLog();
            renderChart();
            localStorage.setItem('pomoData', JSON.stringify(pomoData));
        };

        const renderLog = () => {
            logList.innerHTML = "";
            pomoData.slice().reverse().forEach(e => {
                const li = document.createElement('li');
                li.textContent = `${e.type} – ${e.duration}min (${e.date})`;
                logList.appendChild(li);
            });
        };

        const renderChart = () => {
            if (pomoChart) pomoChart.destroy();
            const workSessions = pomoData.filter(e => e.type === "Work").length;
            const breakSessions = pomoData.filter(e => e.type.includes("Break")).length;

            pomoChart = new Chart(ctx, {
                type: 'doughnut',
                data: {
                    labels: ["Work Sessions", "Breaks"],
                    datasets: [{
                        data: [workSessions, breakSessions],
                        backgroundColor: ["#2ecc71", "#3498db"],
                        borderWidth: 2
                    }]
                },
                options: {
                    responsive: true,
                    plugins: { legend: { labels: { color: 'var(--text-primary)' } } }
                }
            });
        };

        const startTimer = () => {
            if (isRunning) return;
            isRunning = true;
            timer = setInterval(() => {
                timeLeft--;
                updateDisplay();
                if (timeLeft <= 0) {
                    clearInterval(timer);
                    isRunning = false;
                    if (isWork) {
                        sessionCount++;
                        logSession("Work", parseInt(workInput.value));
                        if (sessionCount % parseInt(cycleInput.value) === 0) {
                            timeLeft = parseInt(longInput.value) * 60;
                            isWork = false;
                            alert("🎉 Long Break Time!");
                        } else {
                            timeLeft = parseInt(breakInput.value) * 60;
                            isWork = false;
                            alert("☕ Short Break Time!");
                        }
                    } else {
                        logSession("Break", isWork ? parseInt(breakInput.value) : parseInt(longInput.value));
                        timeLeft = parseInt(workInput.value) * 60;
                        isWork = true;
                        alert("💪 Back to Work!");
                    }
                    updateDisplay();
                }
            }, 1000);
        };

        const pauseTimer = () => { clearInterval(timer); isRunning = false; };
        const resetTimer = () => { clearInterval(timer); isRunning = false; isWork = true; sessionCount = 0; timeLeft = parseInt(workInput.value) * 60; updateDisplay(); };

        startBtn.addEventListener('click', startTimer);
        pauseBtn.addEventListener('click', pauseTimer);
        resetBtn.addEventListener('click', resetTimer);

        clearLogBtn.addEventListener('click', () => {
            if (confirm("Clear all Pomodoro logs?")) {
                pomoData = [];
                renderLog();
                renderChart();
                localStorage.setItem('pomoData', JSON.stringify(pomoData));
            }
        });

        // Init
        timeLeft = parseInt(workInput.value) * 60;
        updateDisplay();
        renderLog();
        renderChart();

        modal.addEventListener('modal:close', () => { if (pomoChart) pomoChart.destroy(); }, { once: true });
    }
},

  'motivation-quote': {
    title: 'Daily Motivation Quote Generator',
    icon: '🌟',
    getContent: () => `
        <div class="tool-container" style="max-width:600px; margin:auto;">
            <div style="text-align:center; margin-bottom:1rem;">
                <h2>🌟 Daily Inspiration</h2>
                <p id="quote-text" style="font-size:1.2rem; margin-top:1rem; font-style:italic;">
                    Click below to get your daily motivation!
                </p>
                <p id="quote-author" style="margin-top:0.5rem; font-weight:bold;"></p>
            </div>

            <div style="display:flex; gap:0.5rem; flex-wrap:wrap; justify-content:center; margin-top:1rem;">
                <button id="new-quote-btn" class="glow-button">✨ New Quote</button>
                <button id="save-quote-btn" class="glow-button" style="background:#27ae60;">❤️ Save</button>
                <button id="share-quote-btn" class="glow-button" style="background:#f39c12;">📤 Share</button>
            </div>

            <h3 style="margin-top:2rem;">📖 Saved Quotes</h3>
            <ul id="saved-quotes" style="margin-top:1rem; padding-left:1rem; list-style:disc; word-break:break-word;"></ul>

            <h3 style="margin-top:2rem;">📊 Motivation Tracker</h3>
            <div style="position:relative; min-height:250px;">
                <canvas id="motivation-chart"></canvas>
            </div>

            <button id="reset-quotes-btn" class="glow-button" style="margin-top:1.5rem; background:#e74c3c;">Reset Saved Quotes</button>
        </div>
    `,
    init: () => {
       const quotes = [
    { text: "Believe you can and you're halfway there.", author: "Theodore Roosevelt" },
    { text: "Don’t watch the clock; do what it does. Keep going.", author: "Sam Levenson" },
    { text: "Dream big and dare to fail.", author: "Norman Vaughan" },
    { text: "It always seems impossible until it's done.", author: "Nelson Mandela" },
    { text: "Act as if what you do makes a difference. It does.", author: "William James" },
    { text: "Success is not in what you have, but who you are.", author: "Bo Bennett" },
    { text: "Hardships often prepare ordinary people for an extraordinary destiny.", author: "C.S. Lewis" },

    // ✅ Added 7 latest Indian motivational quotes
    { text: "Excellence is a continuous process and not an accident.", author: "Dr. A.P.J. Abdul Kalam" },
    { text: "Be the change that you wish to see in the world.", author: "Mahatma Gandhi" },
    { text: "Take risks in your life. If you win, you can lead. If you lose, you can guide.", author: "Swami Vivekananda" },
    { text: "If you want to shine like a sun, first burn like a sun.", author: "Dr. A.P.J. Abdul Kalam" },
    { text: "Courage is not the absence of fear — it’s inspiring others to move beyond it.", author: "Narendra Modi" },
    { text: "Opportunities don’t happen. You create them.", author: "Dhirubhai Ambani" },
    { text: "An idea can only become reality once it is broken down into organized, actionable elements.", author: "Azim Premji" }
];


        const quoteText = document.getElementById('quote-text');
        const quoteAuthor = document.getElementById('quote-author');
        const newBtn = document.getElementById('new-quote-btn');
        const saveBtn = document.getElementById('save-quote-btn');
        const shareBtn = document.getElementById('share-quote-btn');
        const savedList = document.getElementById('saved-quotes');
        const resetBtn = document.getElementById('reset-quotes-btn');
        const ctx = document.getElementById('motivation-chart').getContext('2d');

        let savedQuotes = JSON.parse(localStorage.getItem('savedQuotes')) || [];
        let quoteCount = JSON.parse(localStorage.getItem('quoteCount')) || {};
        let currentQuote = null;
        let chart;

        // Render random quote
        const renderQuote = () => {
            const q = quotes[Math.floor(Math.random() * quotes.length)];
            currentQuote = q;
            quoteText.textContent = `"${q.text}"`;
            quoteAuthor.textContent = `– ${q.author}`;
        };

        // Render saved quotes list
        const renderSaved = () => {
            savedList.innerHTML = "";
            savedQuotes.forEach(q => {
                const li = document.createElement("li");
                li.textContent = `"${q.text}" – ${q.author}`;
                savedList.appendChild(li);
            });
        };

        // Render chart
        const renderChart = () => {
            if (chart) chart.destroy();
            chart = new Chart(ctx, {
                type: 'line',
                data: {
                    labels: Object.keys(quoteCount),
                    datasets: [{
                        label: 'Quotes Viewed',
                        data: Object.values(quoteCount),
                        fill: true,
                        backgroundColor: 'rgba(52, 152, 219, 0.3)',
                        borderColor: '#2980b9',
                        tension: 0.3
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: { legend: { labels: { color: 'var(--text-primary)' } } },
                    scales: {
                        x: { ticks: { color: 'var(--text-primary)' } },
                        y: { beginAtZero: true, ticks: { color: 'var(--text-primary)' } }
                    }
                }
            });
        };

        // ✅ Event bindings (only once, no stacking)
        newBtn.onclick = () => {
            renderQuote();
            const today = new Date().toLocaleDateString();
            quoteCount[today] = (quoteCount[today] || 0) + 1;
            localStorage.setItem('quoteCount', JSON.stringify(quoteCount));
            renderChart();
        };

        saveBtn.onclick = () => {
            if (!currentQuote) return alert("Generate a quote first!");
            savedQuotes.push(currentQuote);
            localStorage.setItem('savedQuotes', JSON.stringify(savedQuotes));
            renderSaved();
        };

        shareBtn.onclick = () => {
            if (!currentQuote) return alert("Generate a quote first!");
            const shareText = `"${currentQuote.text}" – ${currentQuote.author}`;

            // ✅ Mobile Web Share API
            if (navigator.share) {
                navigator.share({
                    title: "Daily Motivation",
                    text: shareText,
                    url: window.location.href
                }).catch(() => {});
            } else {
                // ✅ Fallback
                const twitterUrl = `https://twitter.com/intent/tweet?text=${encodeURIComponent(shareText)}`;
                const whatsappUrl = `https://wa.me/?text=${encodeURIComponent(shareText)}`;
                const choice = confirm("Click OK to share on Twitter, Cancel for WhatsApp.");
                window.open(choice ? twitterUrl : whatsappUrl, "_blank");
            }
        };

        resetBtn.onclick = () => {
            if (confirm("Clear all saved quotes?")) {
                savedQuotes = [];
                localStorage.setItem('savedQuotes', JSON.stringify(savedQuotes));
                renderSaved();
            }
        };

        // Initial load
        renderSaved();
        renderChart();

        // Cleanup when modal closes
        modal.addEventListener('modal:close', () => {
            if (chart) { chart.destroy(); chart = null; }
        }, { once: true });
    }
},


            'quiz-converter': { title: 'Flashcard to Quiz Converter', icon: '🧠', getContent: () => `<div class="tool-container"><label for="flashcard-data">Paste your Anki/Quizlet data here (Tab or custom separated):</label><textarea id="flashcard-data" rows="8" placeholder="Term1\tDefinition1\nTerm2\tDefinition2..."></textarea><div style="display:flex; gap:1rem; align-items:center;"><label for="delimiter-select">Delimiter:</label><select id="delimiter-select"><option value="tab">Tab</option><option value="comma">Comma (,)</option><option value="pipe">Pipe (|)</option><option value="custom">Custom</option></select><input type="text" id="custom-delimiter" placeholder="Custom" style="display:none; width: 80px;"></div><button id="generate-quiz-btn" class="glow-button">Generate Quiz</button><div id="quiz-container" style="display: none; margin-top: 1.5rem;"></div><div id="tool-output"></div></div>`, init: () => { const dataInput = document.getElementById('flashcard-data'), generateBtn = document.getElementById('generate-quiz-btn'), quizContainer = document.getElementById('quiz-container'), output = document.getElementById('tool-output'), delimiterSelect = document.getElementById('delimiter-select'), customDelimiterInput = document.getElementById('custom-delimiter'); delimiterSelect.addEventListener('change', () => { customDelimiterInput.style.display = delimiterSelect.value === 'custom' ? 'inline-block' : 'none'; }); const shuffleArray = (array) => { for (let i = array.length - 1; i > 0; i--) { const j = Math.floor(Math.random() * (i + 1)); [array[i], array[j]] = [array[j], array[i]]; } return array; }; generateBtn.addEventListener('click', () => { let delimiter = {'tab':'\t', 'comma':',', 'pipe':'|'}[delimiterSelect.value] || customDelimiterInput.value; const lines = dataInput.value.trim().split('\n'); const flashcards = lines.map(line => { const parts = line.split(delimiter); return parts.length >= 2 ? { term: parts[0].trim(), definition: parts[1].trim() } : null; }).filter(card => card && card.term && card.definition); if (flashcards.length < 4) { output.textContent = 'Error: Please provide at least 4 valid flashcards.'; quizContainer.style.display = 'none'; return; } quizContainer.innerHTML = ''; output.textContent = ''; shuffleArray([...flashcards]).forEach((card, index) => { let options = [card.definition]; let otherDefs = flashcards.filter(c => c.definition !== card.definition).map(c => c.definition); shuffleArray(otherDefs); options.push(...otherDefs.slice(0, 3)); const questionDiv = document.createElement('div'); questionDiv.className = 'quiz-question'; questionDiv.style.cssText = `margin-bottom: 1.5rem; padding: 1.5rem; border: 1px solid var(--border-color); border-radius: 8px; background-color: var(--dark-bg);`; questionDiv.innerHTML = `<p style="font-weight: bold; color: var(--heading-color); margin-bottom: 1rem;">Question ${index + 1}: ${card.term}</p><div class="quiz-options">${shuffleArray(options).map(option => `<label class="option" style="display: block; margin-bottom: 0.5rem;"><input type="radio" name="question${index}" value="${option}"> ${option}</label>`).join('')}</div><div class="quiz-feedback" style="margin-top: 1rem; padding: 0.8rem; border-radius: 5px; font-weight: bold;"></div>`; quizContainer.appendChild(questionDiv); }); quizContainer.style.display = 'block'; quizContainer.addEventListener('change', e => { if (e.target.type === 'radio') { const qDiv = e.target.closest('.quiz-question'), feedbackDiv = qDiv.querySelector('.quiz-feedback'); const correctDef = flashcards.find(c => c.term === qDiv.querySelector('p').textContent.split(': ')[1]).definition; if (e.target.value === correctDef) { feedbackDiv.className = 'quiz-feedback feedback-correct'; feedbackDiv.textContent = 'Correct!'; feedbackDiv.style.cssText=`background-color:rgba(46,204,113,0.2); border-left:5px solid #2ecc71; color:#2ecc71;`; } else { feedbackDiv.className = 'quiz-feedback feedback-incorrect'; feedbackDiv.textContent = `Incorrect. Correct answer: ${correctDef}`; feedbackDiv.style.cssText=`background-color:rgba(231,76,60,0.2); border-left:5px solid #e74c3c; color:#e74c3c;`; } qDiv.querySelectorAll('input[type="radio"]').forEach(radio => radio.disabled = true); }}); }); }} 
        };
        // Populate the new tool slider on page load
        populateToolSlider();

        showPage('page-home');
    });
</script>



