<style>
  /* Hide Standard Theme Sidebars and Headers for this page */
  .sidebar-container, .bg-photo-overlay, .bg-photo-container { display: none !important; }
  .blog-posts { width: 100% !important; max-width: 100% !important; padding: 0 !important; }
  .post-body { padding: 0 !important; width: 100% !important; }
  .centered-top-container { max-width: 100% !important; }

  /* Fix Container Width */
  .page-body { max-width: 1200px; margin: 0 auto; padding: 20px; }

  /* Hide Comments */
  #comments, .comments-area { display: none !important; }

  /* Tool Specific CSS */
  :root {
      --accent-color: #22d3ee;
      --dark-bg: #0d1117;
      --card-bg: #161b22;
      --text-primary: #c9d1d9;
      --button-bg: #21262d;
      --border-color: #30363d;
  }

  /* Ensure grids display correctly */
  .tools-grid { 
      display: grid; 
      grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); 
      gap: 1.5rem; 
      margin-top: 2rem;
  }

  .tool-card {
      background-color: var(--card-bg);
      border: 1px solid var(--border-color);
      border-radius: 12px;
      padding: 2rem;
      text-align: center;
      color: var(--text-primary);
      transition: transform 0.3s ease;
  }

  .tool-card:hover { transform: translateY(-5px); border-color: var(--accent-color); }
  .tool-card h3 { color: #fff; margin-bottom: 10px; font-size: 1.2rem; }

  .glow-button {
      background-color: var(--button-bg);
      color: var(--text-primary);
      border: 1px solid var(--border-color);
      padding: 0.8rem 1.8rem;
      border-radius: 8px;
      cursor: pointer;
      font-weight: 600;
      margin-top: 10px;
      display: inline-block;
      text-decoration: none;
  }
  .glow-button:hover { background-color: #30363d; color: #fff; border-color: var(--accent-color); }

  /* Modals */
  .modal { display: none; position: fixed; z-index: 9999; left: 0; top: 0; width: 100%; height: 100%; overflow: auto; background-color: rgba(0,0,0,0.8); backdrop-filter: blur(5px); }
  .modal-content { background-color: var(--card-bg); margin: 5% auto; padding: 25px; border: 1px solid var(--accent-color); width: 90%; max-width: 800px; border-radius: 12px; color: var(--text-primary); position: relative; }
  .close-button { position: absolute; top: 10px; right: 20px; font-size: 30px; cursor: pointer; color: #fff; }
  .tool-container input, .tool-container select, .tool-container textarea { width: 100%; padding: 10px; margin: 5px 0; background: #0d1117; border: 1px solid #30363d; color: white; border-radius: 5px; }
</style>

