        <div class="tool-card"><h3>📊 Body Fat Calculator</h3><p>Estimate body fat percentage.</p><button class="glow-button" data-tool="body-fat-calculator">Launch Tool</button></div>
        <div class="tool-card"><h3>🔄 Plateau Tracker</h3><p>Track stalled progress.</p><button class="glow-button" data-tool="plateau-tracker">Launch Tool</button></div>
        <div class="tool-card"><h3>🗓️ Workout Calendar</h3><p>Editable fitness planner.</p><button class="glow-button" data-tool="workout-calendar">Launch Tool</button></div>
        <div class="tool-card"><h3>BMI Calculator</h3><p>Check your Body Mass Index.</p><button class="glow-button" data-tool="bmi-calculator">Launch Tool</button></div>
        <div class="tool-card"><h3>🔥 TDEE Calculator</h3><p>Total Daily Energy Expenditure.</p><button class="glow-button" data-tool="tdee-calculator">Launch Tool</button></div>
        <div class="tool-card"><h3>🥑 Keto Calculator</h3><p>Calculate Keto Macros.</p><button class="glow-button" data-tool="keto-calculator">Launch Tool</button></div>
    </div>

    <!-- Category: Finance -->
    <h3 style="color: var(--accent-color); border-bottom: 1px solid #30363d; padding-bottom: 10px; margin-top: 30px;">Financial Tools</h3>
    <div class="tools-grid">
        <div class="tool-card"><h3>🧾 GST Calculator</h3><p>Inclusive/Exclusive GST.</p><button class="glow-button" data-tool="advanced-gst-calculator">Launch Tool</button></div>
        <div class="tool-card"><h3>💸 Currency Converter</h3><p>Real-time exchange rates.</p><button class="glow-button" data-tool="currency-converter">Launch Tool</button></div>
        <div class="tool-card"><h3>🏦 EMI Calculator</h3><p>Loan EMI planner.</p><button class="glow-button" data-tool="emi-calculator">Launch Tool</button></div>
        <div class="tool-card"><h3>📈 SIP Calculator</h3><p>Investment returns.</p><button class="glow-button" data-tool="sip-calculator">Launch Tool</button></div>
    </div>

    <!-- Category: Productivity -->
    <h3 style="color: var(--accent-color); border-bottom: 1px solid #30363d; padding-bottom: 10px; margin-top: 30px;">Productivity</h3>
    <div class="tools-grid">
        <div class="tool-card"><h3>✅ To-Do List</h3><p>Prioritize your tasks.</p><button class="glow-button" data-tool="todo-list">Launch Tool</button></div>
        <div class="tool-card"><h3>⏲️ Pomodoro Timer</h3><p>Focus timer with breaks.</p><button class="glow-button" data-tool="pomodoro-timer">Launch Tool</button></div>
        <div class="tool-card"><h3>🔑 Keyword Density</h3><p>SEO Text Analyzer.</p><button class="glow-button" data-tool="keyword-density-checker">Launch Tool</button></div>
        <div class="tool-card"><h3>🖼️ Image Compressor</h3><p>Reduce image size.</p><button class="glow-button" data-tool="image-compressor">Launch Tool</button></div>
    </div>

</div>

<!-- 3. MODAL CONTAINER -->
<div class="modal" id="toolModal">
    <div class="modal-content">
        <span class="close-button">&times;</span>
        <h2 id="modal-title" style="color:white;">Tool Title</h2>
        <div id="modal-body"></div>
    </div>
</div>

<!-- 4. EXTERNAL SCRIPTS -->
<script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
<script src="https://cdn.jsdelivr.net/npm/tesseract.js@2/dist/tesseract.min.js"></script>
<script src="https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js"></script>

<!-- 5. TOOL LOGIC (Javascript) -->
<script>
    document.addEventListener('DOMContentLoaded', () => {

        // --- MODAL LOGIC ---
        const modal = document.getElementById('toolModal');
        const modalTitle = document.getElementById('modal-title');
        const modalBody = document.getElementById('modal-body');
        const closeBtn = document.querySelector('.close-button');

        // Function to open tool
        window.openTool = function(toolId) {
            if(toolImplementations[toolId]) {
                modalTitle.innerText = toolImplementations[toolId].title;
                modalBody.innerHTML = toolImplementations[toolId].getContent();
                modal.style.display = 'flex';
                if(toolImplementations[toolId].init) {
                    try { toolImplementations[toolId].init(); } 
                    catch(e) { console.error("Tool Error:", e); }
                }
            } else {
                alert("Tool not found: " + toolId);
            }
        };

        // Click listeners for buttons
        document.querySelectorAll('button[data-tool]').forEach(btn => {
            btn.addEventListener('click', function() {
                openTool(this.getAttribute('data-tool'));
            });
        });

        // Close logic
        closeBtn.onclick = () => { modal.style.display = "none"; modal.dispatchEvent(new CustomEvent('modal:close')); };
        window.onclick = (e) => { if (e.target == modal) { modal.style.display = "none"; modal.dispatchEvent(new CustomEvent('modal:close')); } };

        // --- SEARCH LOGIC ---
        const searchBar = document.getElementById('tool-search-bar');
        if(searchBar) {
            searchBar.addEventListener('keyup', (e) => {
                const term = e.target.value.toLowerCase();
                document.querySelectorAll('.tool-card').forEach(card => {
                    const txt = card.innerText.toLowerCase();
                    card.style.display = txt.includes(term) ? 'block' : 'none';
                });
            });
        }

        // --- TOOL IMPLEMENTATIONS OBJECT ---
        // (This contains the logic for your calculators)
        const toolImplementations = {
            'body-fat-calculator': {
                title: 'Body Fat Calculator',
                getContent: () => `
                    <div class="tool-container">
                        <label>Gender: <select id="bf-gender"><option value="male">Male</option><option value="female">Female</option></select></label>
                        <label>Height (cm): <input type="number" id="bf-height" placeholder="175"></label>
                        <label>Weight (kg): <input type="number" id="bf-weight" placeholder="70"></label>
                        <label>Neck (cm): <input type="number" id="bf-neck" placeholder="38"></label>
                        <label>Waist (cm): <input type="number" id="bf-waist" placeholder="85"></label>
                        <div id="hip-div" style="display:none;"><label>Hip (cm): <input type="number" id="bf-hip" placeholder="95"></label></div>
                        <button class="glow-button" id="calc-bf">Calculate</button>
                        <div id="bf-result" style="margin-top:15px; font-size:1.2rem; color:var(--accent-color);"></div>
                    </div>`,
                init: () => {
                    document.getElementById('bf-gender').addEventListener('change', function() {
                        document.getElementById('hip-div').style.display = this.value === 'female' ? 'block' : 'none';
                    });
                    document.getElementById('calc-bf').onclick = () => {
                        // Simple Logic Placeholder
                        const wa = parseFloat(document.getElementById('bf-waist').value);
                        const ne = parseFloat(document.getElementById('bf-neck').value);
                        const he = parseFloat(document.getElementById('bf-height').value);
                        if(wa && ne && he) {
                            // Simplified US Navy Formula
                            let res = 495 / (1.0324 - 0.19077 * Math.log10(wa - ne) + 0.15456 * Math.log10(he)) - 450;
                            document.getElementById('bf-result').innerText = "Est. Body Fat: " + res.toFixed(1) + "%";
                        } else {
                            document.getElementById('bf-result').innerText = "Please fill all fields";
                        }
                    }
                }
            },
            'bmi-calculator': {
                title: 'BMI Calculator',
                getContent: () => `
                    <div class="tool-container">
                        <label>Height (cm): <input type="number" id="bmi-height"></label>
                        <label>Weight (kg): <input type="number" id="bmi-weight"></label>
                        <button class="glow-button" id="calc-bmi">Calculate</button>
                        <div id="bmi-result" style="margin-top:15px; font-weight:bold;"></div>
                    </div>`,
                init: () => {
                    document.getElementById('calc-bmi').onclick = () => {
                        const h = document.getElementById('bmi-height').value / 100;
                        const w = document.getElementById('bmi-weight').value;
                        if(h && w) {
                            const bmi = (w / (h*h)).toFixed(2);
                            document.getElementById('bmi-result').innerText = `Your BMI: ${bmi}`;
                        }
                    }
                }
            },
            'todo-list': {
                title: 'To-Do List',
                getContent: () => `<input type="text" id="todo-input" placeholder="New Task..."><button class="glow-button" id="add-todo">Add Task</button><ul id="todo-ul" style="list-style:none; padding:0; margin-top:15px;"></ul>`,
                init: () => {
                    document.getElementById('add-todo').onclick = () => {
                        const val = document.getElementById('todo-input').value;
                        if(val) {
                            const li = document.createElement('li');
                            li.innerHTML = `<div style="background:#21262d; padding:10px; margin-bottom:5px; border-radius:5px; border:1px solid #30363d;">${val} <span style="float:right; cursor:pointer; color:red;" onclick="this.parentElement.remove()">✖</span></div>`;
                            document.getElementById('todo-ul').appendChild(li);
                            document.getElementById('todo-input').value = "";
                        }
                    }
                }
            },
            'pomodoro-timer': {
                title: 'Pomodoro Timer',
                getContent: () => `<div style="text-align:center;"><div style="font-size:4rem; font-weight:bold; margin:20px 0;" id="pomo-timer">25:00</div><button class="glow-button" id="start-pomo">Start Focus</button></div>`,
                init: () => {
                    let time = 25 * 60;
                    let interval;
                    document.getElementById('start-pomo').onclick = function() {
                        if(interval) clearInterval(interval);
                        this.innerText = "Running...";
                        interval = setInterval(() => {
                            if(time > 0) {
                                time--;
                                let m = Math.floor(time / 60);
                                let s = time % 60;
                                document.getElementById('pomo-timer').innerText = `${m}:${s < 10 ? '0'+s : s}`;
                            } else {
                                clearInterval(interval);
                                alert("Time's up!");
                            }
                        }, 1000);
                    }
                }
            },
            'currency-converter': {
                title: 'Currency Converter',
                getContent: () => `<div class="tool-container"><label>Amount (USD): <input type="number" id="curr-amount" value="1"></label><button class="glow-button" id="convert-curr">Convert to INR</button><div id="curr-result" style="margin-top:15px;"></div></div>`,
                init: () => {
                    document.getElementById('convert-curr').onclick = async () => {
                        const amt = document.getElementById('curr-amount').value;
                        document.getElementById('curr-result').innerText = "Fetching rate...";
                        try {
                            const res = await fetch('https://open.er-api.com/v6/latest/USD');
                            const data = await res.json();
                            const rate = data.rates.INR;
                            document.getElementById('curr-result').innerText = `₹ ${(amt * rate).toFixed(2)}`;
                        } catch(e) {
                            document.getElementById('curr-result').innerText = "Error fetching rates.";
                        }
                    }
                }
            },
            'advanced-gst-calculator': {
                title: 'GST Calculator',
                getContent: () => `
                    <div class="tool-container">
                        <label>Amount: <input type="number" id="gst-amount"></label>
                        <label>GST Rate (%): <select id="gst-rate"><option value="5">5%</option><option value="12">12%</option><option value="18">18%</option><option value="28">28%</option></select></label>
                        <button class="glow-button" id="calc-gst">Calculate</button>
                        <div id="gst-result" style="margin-top:10px;"></div>
                    </div>`,
                init: () => {
                    document.getElementById('calc-gst').onclick = () => {
                        const amt = parseFloat(document.getElementById('gst-amount').value);
                        const rate = parseFloat(document.getElementById('gst-rate').value);
                        const tax = (amt * rate) / 100;
                        const total = amt + tax;
                        document.getElementById('gst-result').innerHTML = `Tax: ${tax.toFixed(2)} <br> Total: ${total.toFixed(2)}`;
                    }
                }
            },
            // ... You can add your other tools (SIP, EMI, etc) back here using the same format ...
        };

        // Load URL Hash if present (e.g. #bmi-calculator)
        const hash = window.location.hash.substring(1);
        if(hash && toolImplementations[hash]) {
            openTool(hash);
        }
    });
</script>

