    Daily Priority Matrix Tool
    <content '><!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Daily Priority Matrix</title>

    <!-- Tailwind CSS for styling -->
    <script src="https://cdn.tailwindcss.com"></script>

    <!-- Google Fonts: Inter -->
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">

    <style>
        /* Custom styles for a smooth experience */
        body {
            font-family: 'Inter', sans-serif;
        }

        /* Style for the task items */
        .task {
            touch-action: none; /* Recommended for drag and drop on touch devices */
            cursor: grab;
            transition: background-color 0.2s ease-in-out, box-shadow 0.2s ease-in-out;
        }

        .task:active {
            cursor: grabbing;
        }

        /* Class for the element being dragged */
        .dragging {
            opacity: 0.5;
            box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.2), 0 4px 6px -2px rgba(0, 0, 0, 0.1);
        }

        /* Visual feedback when dragging over a quadrant */
        .drag-over {
            transform: scale(1.02);
            box-shadow: 0 0 20px rgba(0,0,0,0.1);
        }

        /* Quadrant transition for the drag-over effect */
        .quadrant {
            transition: transform 0.2s ease-out, box-shadow 0.2s ease-out;
        }
    </style>
</head>
<body class="bg-slate-50 text-slate-800">

    <div class="container mx-auto p-4 md:p-8 max-w-7xl">

        <!-- Header -->
        <header class="text-center mb-8">
            <h1 class="text-4xl md:text-5xl font-bold text-slate-700">Daily Priority Matrix</h1>
            <p class="text-slate-500 mt-2">Organize your tasks using the Eisenhower Matrix.</p>
        </header>

        <!-- Task Adder Form -->
        <div class="bg-white p-6 rounded-2xl shadow-sm mb-8">
            <h2 class="text-xl font-bold mb-4">Add a New Task</h2>
            <form id="add-task-form" class="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                <div class="md:col-span-2">
                    <label for="task-title" class="block text-sm font-medium text-slate-600">Task Title</label>
                    <input type="text" id="task-title" placeholder="e.g., Finish project proposal" class="mt-1 block w-full px-3 py-2 bg-white border border-slate-300 rounded-md text-sm shadow-sm placeholder-slate-400 focus:outline-none focus:border-sky-500 focus:ring-1 focus:ring-sky-500" required>
                </div>
                <div>
                     <label for="task-quadrant" class="block text-sm font-medium text-slate-600">Quadrant</label>
                    <select id="task-quadrant" class="mt-1 block w-full px-3 py-2 bg-white border border-slate-300 rounded-md text-sm shadow-sm focus:outline-none focus:border-sky-500 focus:ring-1 focus:ring-sky-500">
                        <option value="q1">Urgent & Important</option>
                        <option value="q2">Not Urgent & Important</option>
                        <option value="q3">Urgent & Not Important</option>
                        <option value="q4">Not Urgent & Not Important</option>
                    </select>
                </div>
                <button type="submit" class="w-full bg-sky-500 hover:bg-sky-600 text-white font-bold py-2 px-4 rounded-md transition-colors">Add Task</button>
            </form>
        </div>

        <!-- Priority Matrix Grid -->
        <main id="matrix-grid" class="grid grid-cols-1 md:grid-cols-2 gap-6">
            <!-- Quadrant 1: Urgent & Important -->
            <div id="q1" class="quadrant bg-red-100 p-5 rounded-2xl">
                <h3 class="font-bold text-lg text-red-800">Urgent & Important</h3>
                <p class="text-sm text-red-600 mb-4">(Do First)</p>
                <div class="task-list min-h-[150px] space-y-3"></div>
            </div>

            <!-- Quadrant 2: Not Urgent & Important -->
            <div id="q2" class="quadrant bg-blue-100 p-5 rounded-2xl">
                <h3 class="font-bold text-lg text-blue-800">Not Urgent & Important</h3>
                <p class="text-sm text-blue-600 mb-4">(Schedule)</p>
                <div class="task-list min-h-[150px] space-y-3"></div>
            </div>

            <!-- Quadrant 3: Urgent & Not Important -->
            <div id="q3" class="quadrant bg-amber-100 p-5 rounded-2xl">
                <h3 class="font-bold text-lg text-amber-800">Urgent & Not Important</h3>
                <p class="text-sm text-amber-600 mb-4">(Delegate)</p>
                <div class="task-list min-h-[150px] space-y-3"></div>
            </div>

            <!-- Quadrant 4: Not Urgent & Not Important -->
            <div id="q4" class="quadrant bg-slate-200 p-5 rounded-2xl">
                <h3 class="font-bold text-lg text-slate-800">Not Urgent & Not Important</h3>
                <p class="text-sm text-slate-600 mb-4">(Delete)</p>
                <div class="task-list min-h-[150px] space-y-3"></div>
            </div>
        </main>

        <!-- Article Section -->
        <article class="mt-12 bg-white p-8 rounded-2xl shadow-sm">
            <h2 class="text-2xl font-bold text-slate-700">Mastering Your Productivity with the Eisenhower Matrix</h2>
            <h3 class="text-lg text-slate-500 mt-1 mb-4">A simple method for prioritizing tasks and eliminating time-wasters.</h3>
            <div class="prose max-w-none text-slate-600">
                <p>The Eisenhower Matrix is a powerful time-management framework that helps you distinguish between urgent and important tasks. By categorizing your to-do list into four distinct quadrants, you can make smarter decisions about what to focus on first, what to schedule for later, what to delegate, and what to eliminate entirely. This approach, famously used by Dwight D. Eisenhower, shifts your focus from being merely "busy" to being truly effective.</p>
                <p>The goal is to spend most of your time on tasks that are important but not necessarily urgent. These are the activities that contribute to long-term goals, personal growth, and strategic planning. The matrix forces you to confront tasks that feel urgent but don't contribute to your objectives (delegate them) and to identify activities that are neither urgent nor important (delete them). By consistently applying this logic, you can reduce stress, avoid burnout, and ensure that your daily efforts are aligned with what truly matters most to you. This tool is designed to make that process visual, interactive, and seamless.</p>
            </div>
        </article>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', () => {
            const form = document.getElementById('add-task-form');
            const quadrants = document.querySelectorAll('.quadrant');

            // State management
            let tasks = [];

            // --- DATA PERSISTENCE ---
            function saveTasks() {
                localStorage.setItem('priorityMatrixTasks', JSON.stringify(tasks));
            }

            function loadTasks() {
                const storedTasks = localStorage.getItem('priorityMatrixTasks');
                tasks = storedTasks ? JSON.parse(storedTasks) : [];
            }

            // --- TASK RENDERING ---
            function createTaskElement(task) {
                const taskEl = document.createElement('div');
                taskEl.classList.add('task', 'bg-white', 'p-3', 'rounded-lg', 'shadow-sm', 'flex', 'justify-between', 'items-center');
                taskEl.setAttribute('draggable', 'true');
                taskEl.dataset.id = task.id;

                const taskTitle = document.createElement('span');
                taskTitle.textContent = task.title;
                taskTitle.classList.add('flex-grow', 'mr-2');

                const deleteBtn = document.createElement('button');
                deleteBtn.innerHTML = '&times;';
                deleteBtn.classList.add('text-slate-400', 'hover:text-red-500', 'font-bold', 'text-xl', 'w-6', 'h-6', 'flex', 'items-center', 'justify-center', 'rounded-full');
                deleteBtn.ariaLabel = 'Delete task';

                // Event listener for deleting a task
                deleteBtn.addEventListener('click', () => {
                    deleteTask(task.id);
                });

                taskEl.appendChild(taskTitle);
                taskEl.appendChild(deleteBtn);

                // Add dragstart listener to the task element
                taskEl.addEventListener('dragstart', handleDragStart);

                return taskEl;
            }

            function renderAllTasks() {
                // Clear all existing tasks from the DOM
                document.querySelectorAll('.task-list').forEach(list => list.innerHTML = '');

                // Render each task into its correct quadrant
                tasks.forEach(task => {
                    const taskEl = createTaskElement(task);
                    const quadrant = document.getElementById(task.quadrant);
                    if (quadrant) {
                        quadrant.querySelector('.task-list').appendChild(taskEl);
                    }
                });
            }


            // --- TASK MANIPULATION ---
            function addTask(e) {
                e.preventDefault();
                const titleInput = document.getElementById('task-title');
                const quadrantSelect = document.getElementById('task-quadrant');

                const title = titleInput.value.trim();
                const quadrant = quadrantSelect.value;

                if (title) {
                    const newTask = {
                        id: `task-${Date.now()}`,
                        title: title,
                        quadrant: quadrant,
                    };
                    tasks.push(newTask);
                    saveTasks();
                    renderAllTasks();
                    titleInput.value = ''; // Reset form
                    titleInput.focus();
                }
            }

            function deleteTask(taskId) {
                tasks = tasks.filter(task => task.id !== taskId);
                saveTasks();
                renderAllTasks();
            }

            function updateTaskQuadrant(taskId, newQuadrantId) {
                const task = tasks.find(t => t.id === taskId);
                if (task) {
                    task.quadrant = newQuadrantId;
                    saveTasks();
                    renderAllTasks();
                }
            }

            // --- DRAG AND DROP HANDLERS ---
            function handleDragStart(e) {
                e.dataTransfer.setData('text/plain', e.target.dataset.id);
                setTimeout(() => {
                    e.target.classList.add('dragging');
                }, 0);
            }

            function handleDragOver(e) {
                e.preventDefault(); // Necessary to allow dropping
                const quadrant = e.currentTarget;
                quadrant.classList.add('drag-over');
            }

            function handleDragLeave(e) {
                 e.currentTarget.classList.remove('drag-over');
            }

            function handleDrop(e) {
                e.preventDefault();
                e.currentTarget.classList.remove('drag-over');

                const taskId = e.dataTransfer.getData('text/plain');
                const newQuadrantId = e.currentTarget.id;

                const draggedEl = document.querySelector('.dragging');
                if(draggedEl) {
                    draggedEl.classList.remove('dragging');
                }

                updateTaskQuadrant(taskId, newQuadrantId);
            }


            // --- INITIALIZATION ---
            function initialize() {
                // Load tasks from local storage
                loadTasks();

                // Render tasks to the DOM
                renderAllTasks();

                // Add form submit listener
                form.addEventListener('submit', addTask);

                // Add drag and drop listeners to all quadrants
                quadrants.forEach(q => {
                    q.addEventListener('dragover', handleDragOver);
                    q.addEventListener('dragleave', handleDragLeave);
                    q.addEventListener('drop', handleDrop);
                });
            }

            initialize();
        });
    </script>

</body>
</html>

